export enum ThemeColor {
  RED = 'red',
  BLUE = 'blue',
  PURPLE = 'purple'
}

export interface NewsOverlayState {
  headline: string;
  subheadline: string;
  theme: ThemeColor;
  overlayImage: string | null;
}

export interface NewsItem extends NewsOverlayState {
  id: string;
  // Media
  videoUrl: string | null;
  videoFile: File | null;
  // Result
  generatedVideoUrl: string | null;
}

export interface GlobalState {
  audioUrl: string | null;
  audioFile: File | null;
  isProcessing: boolean;
  processingItemId: string | null;
  progress: string;
}

export interface ScrapedArticle {
  id: string;
  url: string;
  title: string;
  firstParagraph: string;
  imageUrl: string;
}

import React, { useState } from 'react';
import { ArrowLeft, Search, Download, Trash2, ExternalLink, FileSpreadsheet, Plus } from 'lucide-react';
import { ScrapedArticle } from '../types';
import * as XLSX from 'xlsx';

interface ScraperProps {
  onBack: () => void;
}

const Scraper: React.FC<ScraperProps> = ({ onBack }) => {
  const [urlInput, setUrlInput] = useState('');
  const [articles, setArticles] = useState<ScrapedArticle[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleScrape = async () => {
    if (!urlInput.trim()) return;

    setIsLoading(true);
    setError(null);

    try {
      // Use AllOrigins as a CORS proxy
      const proxyUrl = `https://api.allorigins.win/get?url=${encodeURIComponent(urlInput)}`;
      const response = await fetch(proxyUrl);
      const data = await response.json();

      if (!response.ok) throw new Error('Network response was not ok');

      const htmlContent = data.contents;
      const parser = new DOMParser();
      const doc = parser.parseFromString(htmlContent, 'text/html');

      // Extraction Logic
      // 1. Title
      const ogTitle = doc.querySelector('meta[property="og:title"]')?.getAttribute('content');
      const h1 = doc.querySelector('h1')?.innerText;
      const title = ogTitle || h1 || doc.title || 'No Title Found';

      // 2. First Paragraph
      const ogDesc = doc.querySelector('meta[property="og:description"]')?.getAttribute('content');
      // Find the first p tag that has significant text length (avoiding nav/menu links)
      let firstP = '';
      const paragraphs = doc.querySelectorAll('p');
      for (const p of paragraphs) {
        if (p.innerText.length > 50) {
            firstP = p.innerText;
            break;
        }
      }
      const description = firstP || ogDesc || 'No description found';

      // 3. Image
      const ogImage = doc.querySelector('meta[property="og:image"]')?.getAttribute('content');
      let imgUrl = ogImage || '';
      if (!imgUrl) {
          // Fallback to finding the largest image
          const imgs = doc.querySelectorAll('img');
          if (imgs.length > 0) imgUrl = imgs[0].src;
      }

      const newArticle: ScrapedArticle = {
        id: Date.now().toString(),
        url: urlInput,
        title: title.trim(),
        firstParagraph: description.trim(),
        imageUrl: imgUrl
      };

      setArticles(prev => [newArticle, ...prev]);
      setUrlInput('');

    } catch (err) {
      setError('Failed to fetch URL. Ensure the site allows access.');
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleExportExcel = () => {
    if (articles.length === 0) return;

    // Prepare data for sheet
    const data = articles.map(item => ({
        "Title": item.title,
        "First Paragraph": item.firstParagraph,
        "Image URL": item.imageUrl,
        "Source URL": item.url
    }));

    const ws = XLSX.utils.json_to_sheet(data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Scraped Data");

    XLSX.writeFile(wb, `scraped_articles_${Date.now()}.xlsx`);
  };

  const removeArticle = (id: string) => {
    setArticles(prev => prev.filter(a => a.id !== id));
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 flex flex-col">

      {/* Header */}
      <div className="bg-slate-900 border-b border-slate-800 p-4 sticky top-0 z-20 flex items-center justify-between">
        <div className="flex items-center gap-4">
            <button onClick={onBack} className="p-2 hover:bg-slate-800 rounded-full transition-colors text-slate-400 hover:text-white">
                <ArrowLeft className="w-5 h-5" />
            </button>
            <h1 className="text-xl font-bold bg-gradient-to-r from-green-400 to-emerald-500 bg-clip-text text-transparent flex items-center gap-2">
                <FileSpreadsheet className="w-6 h-6 text-green-500" />
                Article Scraper
            </h1>
        </div>

        {articles.length > 0 && (
            <button 
                onClick={handleExportExcel}
                className="bg-green-600 hover:bg-green-500 text-white px-4 py-2 rounded-lg font-semibold flex items-center gap-2 text-sm transition-all shadow-lg shadow-green-900/20"
            >
                <Download className="w-4 h-4" />
                Export Excel ({articles.length})
            </button>
        )}
      </div>

      <div className="flex-1 max-w-5xl w-full mx-auto p-6">

        {/* Input Area */}
        <div className="bg-slate-900 rounded-2xl p-6 border border-slate-800 shadow-xl mb-8">
            <label className="block text-sm font-medium text-slate-400 mb-2">Article URL</label>
            <div className="flex gap-3">
                <input 
                    type="url" 
                    value={urlInput}
                    onChange={(e) => setUrlInput(e.target.value)}
                    placeholder="https://example.com/news/article-1"
                    className="flex-1 bg-slate-950 border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-green-500 outline-none placeholder:text-slate-600"
                    onKeyDown={(e) => e.key === 'Enter' && handleScrape()}
                />
                <button 
                    onClick={handleScrape}
                    disabled={isLoading || !urlInput}
                    className="bg-slate-800 hover:bg-slate-700 disabled:opacity-50 text-white px-6 py-3 rounded-xl font-medium transition-all flex items-center gap-2 border border-slate-700"
                >
                    {isLoading ? <span className="animate-spin">⌛</span> : <Plus className="w-5 h-5" />}
                    Add to List
                </button>
            </div>
            {error && <p className="text-red-400 text-sm mt-3 flex items-center gap-1">⚠️ {error}</p>}
        </div>

        {/* Results List */}
        <div className="space-y-4">
            <h2 className="text-lg font-semibold text-slate-300 flex items-center gap-2">
                Scraped Items 
                <span className="bg-slate-800 text-slate-400 text-xs px-2 py-1 rounded-full">{articles.length}</span>
            </h2>

            {articles.length === 0 ? (
                <div className="text-center py-20 text-slate-600 border-2 border-dashed border-slate-800 rounded-2xl">
                    <Search className="w-12 h-12 mx-auto mb-4 opacity-50" />
                    <p>No articles scraped yet.</p>
                    <p className="text-sm">Enter a URL above to extract data.</p>
                </div>
            ) : (
                <div className="grid grid-cols-1 gap-4">
                    {articles.map((item) => (
                        <div key={item.id} className="bg-slate-900/50 border border-slate-800 rounded-xl p-4 flex gap-4 group hover:border-slate-700 transition-colors">
                            {/* Image Thumbnail */}
                            <div className="w-24 h-24 flex-shrink-0 bg-black rounded-lg overflow-hidden border border-slate-800">
                                {item.imageUrl ? (
                                    <img src={item.imageUrl} alt="" className="w-full h-full object-cover" onError={(e) => (e.currentTarget.style.display='none')}/>
                                ) : (
                                    <div className="w-full h-full flex items-center justify-center text-slate-700 text-xs">No Img</div>
                                )}
                            </div>

                            {/* Content */}
                            <div className="flex-1 min-w-0">
                                <h3 className="font-bold text-white text-lg leading-tight mb-2 line-clamp-2">{item.title}</h3>
                                <p className="text-slate-400 text-sm line-clamp-2 mb-3">{item.firstParagraph}</p>
                                <a href={item.url} target="_blank" rel="noopener noreferrer" className="text-xs text-blue-400 hover:underline flex items-center gap-1">
                                    <ExternalLink className="w-3 h-3" /> View Source
                                </a>
                            </div>

                            {/* Actions */}
                            <button 
                                onClick={() => removeArticle(item.id)}
                                className="self-start p-2 text-slate-500 hover:text-red-400 hover:bg-red-500/10 rounded-lg transition-colors"
                                title="Remove"
                            >
                                <Trash2 className="w-5 h-5" />
                            </button>
                        </div>
                    ))}
                </div>
            )}
        </div>
      </div>
    </div>
  );
};

export default Scraper;

import React, { useState } from 'react';
import Controls from './Controls';
import PreviewArea from './PreviewArea';
import { NewsItem, GlobalState, ThemeColor } from '../types';
import { exportCompositedVideo } from '../services/gemini';
import { ArrowLeft } from 'lucide-react';

interface VideoEditorProps {
    onBack: () => void;
}

const VideoEditor: React.FC<VideoEditorProps> = ({ onBack }) => {
  // Initialize with single default item
  const [items, setItems] = useState<NewsItem[]>([{
    id: '1',
    headline: 'NEWS UPDATE',
    subheadline: 'Upload your video to begin',
    theme: ThemeColor.RED,
    overlayImage: null,
    videoUrl: null,
    videoFile: null,
    generatedVideoUrl: null
  }]);

  const [activeItemId, setActiveItemId] = useState<string>('1');

  // Global state for audio (background music) and processing status
  const [globalState, setGlobalState] = useState<GlobalState>({
    audioUrl: null,
    audioFile: null,
    isProcessing: false,
    processingItemId: null,
    progress: ''
  });

  const activeItem = items.find(i => i.id === activeItemId) || items[0];

  const handleUpdateItem = (id: string, updates: Partial<NewsItem>) => {
    // If we are editing content (updates doesn't have generatedVideoUrl), clear the stale result
    const isSystemUpdate = 'generatedVideoUrl' in updates;

    setItems(prevItems => prevItems.map(item => {
        if (item.id !== id) return item;
        return {
            ...item,
            ...updates,
            // Reset generated result if user edits content
            generatedVideoUrl: isSystemUpdate ? updates.generatedVideoUrl! : null
        };
    }));
  };

  const handleAddItem = () => {
      const newItem: NewsItem = {
          id: Date.now().toString(),
          headline: 'NEW CLIP',
          subheadline: '',
          theme: ThemeColor.RED,
          overlayImage: null,
          videoUrl: null,
          videoFile: null,
          generatedVideoUrl: null
      };
      setItems(prev => [...prev, newItem]);
      setActiveItemId(newItem.id);
  };

  const handleRemoveItem = (id: string) => {
      if (items.length <= 1) return; // Prevent removing last item

      const newItems = items.filter(i => i.id !== id);
      setItems(newItems);

      if (activeItemId === id) {
          setActiveItemId(newItems[0].id);
      }
  };

  // Helper to trigger file download
  const triggerDownload = (url: string, headline: string) => {
    const a = document.createElement('a');
    a.href = url;
    a.download = `veo-news-${headline.replace(/\s+/g, '-').toLowerCase()}-${Date.now()}.webm`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
  };

  const handleProcessAll = async () => {
    // Filter items that have videos
    const validItems = items.filter(item => item.videoUrl);

    if (validItems.length === 0) {
      alert("Please upload videos for your clips to export.");
      return;
    }

    setGlobalState(prev => ({ ...prev, isProcessing: true }));

    for (let i = 0; i < validItems.length; i++) {
        const item = validItems[i];
        setGlobalState(prev => ({ 
            ...prev, 
            processingItemId: item.id,
            progress: `Processing clip ${i + 1} of ${validItems.length}...` 
        }));

        try {
            // Generate
            const downloadUrl = await exportCompositedVideo(
                item, 
                globalState.audioUrl,
                (msg) => setGlobalState(prev => ({ ...prev, progress: `Clip ${i + 1}/${validItems.length}: ${msg}` }))
            );

            // Update state with result
            handleUpdateItem(item.id, { generatedVideoUrl: downloadUrl });

            // Auto download
            triggerDownload(downloadUrl, item.headline);

        } catch (err: any) {
            console.error(err);
        }
    }

    setGlobalState(prev => ({ ...prev, isProcessing: false, processingItemId: null, progress: '' }));
  };

  const handleDownload = (item: NewsItem) => {
    if (!item.generatedVideoUrl) return;
    triggerDownload(item.generatedVideoUrl, item.headline);
  };

  return (
    <div className="flex flex-col lg:flex-row h-screen w-full overflow-hidden bg-slate-950 text-white relative">

      {/* Back Button Overlay for Mobile/Tablet or just convenient access */}
      <div className="absolute top-4 right-4 z-50 lg:hidden">
         <button onClick={onBack} className="bg-slate-800 p-2 rounded-full text-slate-300">
             <ArrowLeft />
         </button>
      </div>

      {/* Sidebar Controls */}
      <div className="relative z-20 flex-shrink-0">
          {/* Inject Back Button into Controls wrapper effectively by passing it down or wrapping Controls. 
              For simplicity, we modify Controls to accept onBack, OR render a back button above it. 
              Let's update Controls.tsx to accept an optional back action or just render it here.
              We'll render a small back bar above Controls for now or modify Controls.tsx.
              Actually, passing it to Controls is cleaner.
          */}
          <Controls 
            items={items}
            activeItemId={activeItemId}
            onSelect={setActiveItemId}
            onAdd={handleAddItem}
            onRemove={handleRemoveItem}
            onUpdate={handleUpdateItem}
            globalState={globalState}
            setGlobalState={setGlobalState}
            onGenerateAll={handleProcessAll}
            onDownload={handleDownload}
            onBack={onBack}
          />
      </div>

      {/* Main Preview */}
      <PreviewArea 
        activeItem={activeItem}
        globalState={globalState}
      />
    </div>
  );
};

export default VideoEditor;

import React, { useRef, useState } from 'react';
import { NewsItem, GlobalState, ThemeColor } from '../types';
import { Video, Type, Palette, Upload, Image as ImageIcon, Download, Loader2, Music, Link as LinkIcon, CheckCircle, Play, Plus, Trash2, Layers, ArrowLeft } from 'lucide-react';

interface ControlsProps {
  items: NewsItem[];
  activeItemId: string;
  onSelect: (id: string) => void;
  onAdd: () => void;
  onRemove: (id: string) => void;
  onUpdate: (id: string, updates: Partial<NewsItem>) => void;

  globalState: GlobalState;
  setGlobalState: React.Dispatch<React.SetStateAction<GlobalState>>;
  onGenerateAll: () => void;
  onDownload: (item: NewsItem) => void;
  onBack?: () => void;
}

const Controls: React.FC<ControlsProps> = ({
  items,
  activeItemId,
  onSelect,
  onAdd,
  onRemove,
  onUpdate,
  globalState,
  setGlobalState,
  onGenerateAll,
  onDownload,
  onBack
}) => {
  const videoInputRef = useRef<HTMLInputElement>(null);
  const imageInputRef = useRef<HTMLInputElement>(null);
  const audioInputRef = useRef<HTMLInputElement>(null);

  const activeItem = items.find(i => i.id === activeItemId) || items[0];

  const handleVideoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const url = URL.createObjectURL(file);
      onUpdate(activeItemId, { videoFile: file, videoUrl: url });
    }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const url = URL.createObjectURL(file);
      onUpdate(activeItemId, { overlayImage: url });
    }
  };

  const handleAudioUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const url = URL.createObjectURL(file);
      setGlobalState(prev => ({ ...prev, audioFile: file, audioUrl: url }));
    }
  };

  return (
    <div className="w-full lg:w-96 bg-slate-800 flex flex-col h-auto lg:h-full border-r border-slate-700 shadow-xl z-20">

      {/* Header */}
      <div className="p-6 pb-4 border-b border-slate-700 flex items-center gap-3">
        {onBack && (
            <button onClick={onBack} className="p-2 -ml-2 hover:bg-slate-700 rounded-full text-slate-400 hover:text-white transition-colors">
                <ArrowLeft className="w-5 h-5" />
            </button>
        )}
        <div>
            <h1 className="text-2xl font-bold bg-gradient-to-r from-blue-400 to-purple-400 bg-clip-text text-transparent mb-1">
            Irwan Kurnia
            </h1>
            <p className="text-slate-400 text-xs">Video Editor</p>
        </div>
      </div>

      {/* Story Board / Playlist */}
      <div className="px-6 py-4 border-b border-slate-700 bg-slate-900/30">
          <div className="flex items-center justify-between mb-3">
              <div className="flex items-center gap-2 text-slate-300 font-semibold text-sm">
                  <Layers className="w-4 h-4" />
                  <h2>Story Board</h2>
              </div>
              <button 
                  onClick={onAdd}
                  className="p-1.5 bg-blue-600 hover:bg-blue-500 rounded text-white transition-colors"
                  title="Add New Clip"
              >
                  <Plus className="w-4 h-4" />
              </button>
          </div>

          <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-thin scrollbar-thumb-slate-700 scrollbar-track-transparent">
              {items.map((item, index) => (
                  <div 
                      key={item.id}
                      onClick={() => onSelect(item.id)}
                      className={`
                          flex-shrink-0 w-20 h-24 rounded-lg border-2 cursor-pointer relative group overflow-hidden transition-all
                          ${item.id === activeItemId ? 'border-blue-500 ring-2 ring-blue-500/20' : 'border-slate-700 hover:border-slate-500'}
                          ${item.generatedVideoUrl ? 'shadow-[0_0_10px_rgba(34,197,94,0.3)]' : ''}
                      `}
                  >
                      {item.videoUrl ? (
                          <video src={item.videoUrl} className="w-full h-full object-cover opacity-60" />
                      ) : (
                          <div className="w-full h-full bg-slate-800 flex items-center justify-center">
                              <span className="text-slate-600 font-bold text-lg">{index + 1}</span>
                          </div>
                      )}

                      {/* Status Indicator */}
                      <div className="absolute bottom-0 left-0 right-0 h-1 bg-slate-700">
                          {item.generatedVideoUrl && <div className="h-full bg-green-500 w-full"></div>}
                          {globalState.processingItemId === item.id && <div className="h-full bg-blue-500 w-full animate-pulse"></div>}
                      </div>

                      {/* Remove Button (Hover) */}
                      {items.length > 1 && (
                          <button 
                              onClick={(e) => { e.stopPropagation(); onRemove(item.id); }}
                              className="absolute top-1 right-1 p-1 bg-red-500/80 hover:bg-red-600 text-white rounded opacity-0 group-hover:opacity-100 transition-opacity"
                          >
                              <Trash2 className="w-3 h-3" />
                          </button>
                      )}
                  </div>
              ))}
          </div>
      </div>

      {/* Scrollable Controls Area */}
      <div className="flex-1 overflow-y-auto p-6 space-y-8">

        {/* Media Section */}
        <div className="space-y-4">
            <div className="flex items-center gap-2 text-blue-300 font-semibold border-b border-slate-700 pb-2">
            <Video className="w-5 h-5" />
            <h2>Clip Media</h2>
            </div>

            {/* Video Upload */}
            <div className="space-y-2">
            <label className="text-xs font-medium text-slate-400 uppercase tracking-wider block">Background Video (9:16)</label>
            <input 
                type="file" 
                accept="video/*" 
                ref={videoInputRef}
                onChange={handleVideoUpload}
                className="hidden" 
            />
            <button
                onClick={() => {
                    if(videoInputRef.current) videoInputRef.current.value = '';
                    videoInputRef.current?.click();
                }}
                className="w-full py-3 px-4 rounded-lg border border-slate-600 bg-slate-900/50 hover:bg-slate-700 text-slate-300 flex items-center justify-center gap-2 transition-all text-sm group"
            >
                <Upload className="w-4 h-4 group-hover:scale-110 transition-transform" />
                {activeItem.videoFile ? 'Replace Video' : 'Upload Video File'}
            </button>
            {activeItem.videoFile && (
                <p className="text-xs text-green-400 truncate text-center">
                ✓ {activeItem.videoFile.name}
                </p>
            )}
            </div>

            {/* Image Upload */}
            <div className="space-y-2">
            <label className="text-xs font-medium text-slate-400 uppercase tracking-wider block">News Image / Graphic</label>
            <input 
                type="file" 
                accept="image/*" 
                ref={imageInputRef}
                onChange={handleImageUpload}
                className="hidden" 
            />
            <button
                onClick={() => {
                    if(imageInputRef.current) imageInputRef.current.value = '';
                    imageInputRef.current?.click();
                }}
                className="w-full py-3 px-4 rounded-lg border border-slate-600 bg-slate-900/50 hover:bg-slate-700 text-slate-300 flex items-center justify-center gap-2 transition-all text-sm group"
            >
                <ImageIcon className="w-4 h-4 group-hover:scale-110 transition-transform" />
                {activeItem.overlayImage && activeItem.overlayImage.startsWith('blob:') ? 'Change Image File' : 'Upload Image File'}
            </button>

            <div className="relative">
                <div className="absolute inset-y-0 left-0 flex items-center pl-3 pointer-events-none text-slate-500">
                    <LinkIcon className="w-3.5 h-3.5" />
                </div>
                <input 
                    type="text" 
                    placeholder="Or paste image URL..."
                    className="w-full bg-slate-900 border border-slate-700 rounded-lg py-2 pl-9 pr-3 text-xs text-white focus:ring-1 focus:ring-blue-500 outline-none placeholder:text-slate-600"
                    value={activeItem.overlayImage?.startsWith('blob:') ? '' : activeItem.overlayImage || ''}
                    onChange={(e) => onUpdate(activeItemId, { overlayImage: e.target.value })}
                />
            </div>

            {activeItem.overlayImage && (
                <button 
                    onClick={() => onUpdate(activeItemId, { overlayImage: null })}
                    className="text-xs text-red-400 hover:text-red-300 w-full text-center block mt-1"
                >
                    Remove Image
                </button>
            )}
            </div>
        </div>

        {/* Global Audio Section */}
        <div className="space-y-4">
             <div className="flex items-center gap-2 text-slate-300 font-semibold border-b border-slate-700 pb-2">
                 <Music className="w-5 h-5" />
                 <h2>Background Music (Global)</h2>
             </div>
             <div className="space-y-2">
                <input 
                    type="file" 
                    accept="audio/*" 
                    ref={audioInputRef}
                    onChange={handleAudioUpload}
                    className="hidden" 
                />
                <button
                    onClick={() => audioInputRef.current?.click()}
                    className="w-full py-2 px-4 rounded-lg border border-slate-600 bg-slate-900/30 hover:bg-slate-700 text-slate-400 flex items-center justify-center gap-2 transition-all text-xs"
                >
                    <Music className="w-3 h-3" />
                    {globalState.audioFile ? 'Change Music' : 'Upload Music'}
                </button>
                {globalState.audioFile && (
                    <div className="flex justify-between items-center text-xs px-2">
                        <span className="text-green-400 truncate max-w-[150px]">{globalState.audioFile.name}</span>
                        <button 
                            onClick={() => setGlobalState(prev => ({...prev, audioFile: null, audioUrl: null}))}
                            className="text-red-400 hover:text-red-300"
                        >
                            Clear
                        </button>
                    </div>
                )}
            </div>
        </div>

        {/* Text Section */}
        <div className="space-y-4">
            <div className="flex items-center gap-2 text-purple-300 font-semibold border-b border-slate-700 pb-2">
            <Type className="w-5 h-5" />
            <h2>Clip Content</h2>
            </div>

            <div className="space-y-3">
            <div>
                <label className="text-xs font-medium text-slate-400 uppercase tracking-wider block mb-1">Headline</label>
                <input
                type="text"
                value={activeItem.headline}
