import React, { useState } from 'react';
import { ArrowLeft, Youtube, Download, Trash2, Copy, Plus, List, Play, Loader2 } from 'lucide-react';

interface YouTubeVideo {
    id: string;
    url: string;
    thumbnail: string;
}

interface ShortDownloaderProps {
  onBack: () => void;
}

const ShortDownloader: React.FC<ShortDownloaderProps> = ({ onBack }) => {
  const [urlInput, setUrlInput] = useState('');
  const [videos, setVideos] = useState<YouTubeVideo[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [copyFeedback, setCopyFeedback] = useState(false);

  const extractVideoId = (url: string): string | null => {
    const regExp = /^.*((youtu.be\/)|(v\/)|(\/u\/\w\/)|(embed\/)|(watch\?))\??v?=?([^#&?]*).*|.*shorts\/([^#&?]*).*/;
    const match = url.match(regExp);
    return (match && (match[7]?.length === 11)) ? match[7] : (match && (match[8]?.length === 11)) ? match[8] : null;
  };

  const handleProcessLinks = () => {
    setIsProcessing(true);
    const lines = urlInput.split('\n').map(l => l.trim()).filter(l => l.length > 0);
    const newVideos: YouTubeVideo[] = [];

    lines.forEach(line => {
        const id = extractVideoId(line);
        if (id && !videos.find(v => v.id === id)) {
            newVideos.push({
                id,
                url: line.startsWith('http') ? line : `https://youtube.com/shorts/${id}`,
                thumbnail: `https://img.youtube.com/vi/${id}/maxresdefault.jpg`
            });
        }
    });

    setVideos(prev => [...newVideos, ...prev]);
    setUrlInput('');
    setIsProcessing(false);
  };

  const handleCopyLinks = () => {
    const links = videos.map(v => v.url).join('\n');
    navigator.clipboard.writeText(links).then(() => {
        setCopyFeedback(true);
        setTimeout(() => setCopyFeedback(false), 2000);
    });
  };

  const removeVideo = (id: string) => {
    setVideos(prev => prev.filter(v => v.id !== id));
  };

  const clearAll = () => {
      if(window.confirm('Clear all processed videos?')) {
          setVideos([]);
      }
  };

  const handleDownload = (video: YouTubeVideo) => {
      const downloadUrl = `https://www.y2mate.com/youtube/${video.id}`;
      window.open(downloadUrl, '_blank');
  };

  const handleDownloadAll = () => {
      if (videos.length === 0) return;
      const confirmMsg = `This will open ${videos.length} new tabs for downloading. Browsers may block multiple popups. Continue?`;
      if (window.confirm(confirmMsg)) {
          videos.forEach((video, index) => {
              setTimeout(() => {
                  const downloadUrl = `https://www.y2mate.com/youtube/${video.id}`;
                  window.open(downloadUrl, '_blank');
              }, index * 600);
          });
      }
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 flex flex-col">
      <div className="bg-slate-900 border-b border-slate-800 p-4 sticky top-0 z-20 flex items-center justify-between">
        <div className="flex items-center gap-4">
            <button onClick={onBack} className="p-2 hover:bg-slate-800 rounded-full text-slate-400 hover:text-white"><ArrowLeft className="w-5 h-5" /></button>
            <h1 className="text-xl font-bold flex items-center gap-2"><Youtube className="w-6 h-6 text-red-600" />Shorts Downloader</h1>
        </div>
        {videos.length > 0 && (
            <div className="flex items-center gap-2">
                <button onClick={handleDownloadAll} className="bg-red-600 hover:bg-red-500 text-white text-xs px-3 py-2 rounded-lg font-semibold shadow-lg shadow-red-900/20 flex items-center gap-2"><Download className="w-4 h-4" />Download All</button>
                <button onClick={clearAll} className="text-slate-400 hover:text-red-400 text-xs px-3 py-2 rounded-lg font-medium border border-transparent hover:border-red-500/20 flex items-center gap-2"><Trash2 className="w-4 h-4" />Clear</button>
            </div>
        )}
      </div>

      <div className="flex-1 max-w-5xl w-full mx-auto p-6">
        <div className="bg-slate-900 rounded-2xl p-6 border border-slate-800 shadow-xl mb-8">
            <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-2">
                    <div className="w-8 h-8 rounded-lg bg-red-600/10 flex items-center justify-center"><List className="w-4 h-4 text-red-500" /></div>
                    <h2 className="text-lg font-semibold text-white">Batch Import</h2>
                </div>
                {videos.length > 0 && (
                    <button onClick={handleCopyLinks} className="text-[10px] text-slate-400 hover:text-white uppercase tracking-widest font-bold flex items-center gap-1.5 transition-colors">
                        <Copy className="w-3 h-3" /> {copyFeedback ? 'Copied!' : 'Copy All Links'}
                    </button>
                )}
            </div>
            <textarea 
                value={urlInput}
                onChange={(e) => setUrlInput(e.target.value)}
                placeholder="https://youtube.com/shorts/..."
                rows={5}
                className="w-full bg-slate-950 border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-red-600 outline-none resize-none font-mono text-sm mb-4"
            />
            <button onClick={handleProcessLinks} disabled={!urlInput.trim() || isProcessing} className="w-full bg-red-600 hover:bg-red-500 disabled:opacity-50 text-white px-6 py-4 rounded-xl font-bold flex items-center justify-center gap-2 shadow-lg shadow-red-900/20">
                {isProcessing ? <Loader2 className="w-5 h-5 animate-spin" /> : <Plus className="w-5 h-5" />}Add to Queue
            </button>
        </div>

        <div className="space-y-4">
            <h2 className="text-lg font-semibold text-slate-300 flex items-center gap-2">Download Queue <span className="bg-slate-800 text-slate-400 text-xs px-2 py-1 rounded-full">{videos.length}</span></h2>
            {videos.length === 0 ? (
                <div className="text-center py-20 text-slate-700 border-2 border-dashed border-slate-800 rounded-2xl">
                    <Youtube className="w-16 h-16 mx-auto mb-4 opacity-20" /><p className="text-lg font-medium">No videos in queue.</p>
                </div>
            ) : (
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                    {videos.map((video) => (
                        <div key={video.id} className="bg-slate-900 border border-slate-800 rounded-2xl overflow-hidden group hover:border-red-600/50 transition-all animate-slide-up">
                            <div className="aspect-[9/16] relative bg-black">
                                <img src={video.thumbnail} className="w-full h-full object-cover opacity-80 group-hover:opacity-100" onError={(e) => { e.currentTarget.src = `https://img.youtube.com/vi/${video.id}/hqdefault.jpg`; }} />
                                <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity"><a href={video.url} target="_blank" rel="noopener noreferrer" className="bg-white/20 backdrop-blur-md p-3 rounded-full hover:bg-white/30"><Play className="w-6 h-6 fill-white text-white" /></a></div>
                                <button onClick={() => removeVideo(video.id)} className="absolute top-2 right-2 p-2 bg-slate-950/80 hover:bg-red-600 text-white rounded-lg transition-colors"><Trash2 className="w-4 h-4" /></button>
                            </div>
                            <div className="p-4 bg-slate-900">
                                <div className="text-xs text-slate-500 mb-3 truncate font-mono">ID: {video.id}</div>
                                <button onClick={() => handleDownload(video)} className="w-full bg-slate-800 hover:bg-red-600 text-white py-3 rounded-xl font-semibold flex items-center justify-center gap-2 transition-all border border-slate-700 hover:border-red-500 shadow-md"><Download className="w-4 h-4" />Download Short</button>
                            </div>
                        </div>
                    ))}
                </div>
            )}
        </div>
      </div>
    </div>
  );
};

