import React, { useState } from 'react';
import { ArrowLeft, Youtube, Download, Trash2, Copy, Plus, List, Play, Loader2, CheckCircle, AlertCircle } from 'lucide-react';

interface YouTubeVideo {
    id: string;
    url: string;
    thumbnail: string;
    status: 'idle' | 'processing' | 'done' | 'error';
    error?: string;
}

interface ShortDownloaderProps {
  onBack: () => void;
}

// Daftar instansi Cobalt API publik sebagai cadangan jika satu gagal (CORS/Down)
const COBALT_INSTANCES = [
    'https://api.cobalt.tools/api/json',
    'https://cobalt.api.ryuko.space/api/json',
    'https://api.v7.cobalt.tools/api/json'
];

const ShortDownloader: React.FC<ShortDownloaderProps> = ({ onBack }) => {
  const [urlInput, setUrlInput] = useState('');
  const [videos, setVideos] = useState<YouTubeVideo[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isDownloadingAll, setIsDownloadingAll] = useState(false);
  const [copyFeedback, setCopyFeedback] = useState(false);

  const extractVideoId = (url: string): string | null => {
    const regExp = /^.*((youtu.be\/)|(v\/)|(\/u\/\w\/)|(embed\/)|(watch\?))\??v?=?([^#&?]*).*|.*shorts\/([^#&?]*).*/;
    const match = url.match(regExp);
    return (match && (match[7]?.length === 11)) ? match[7] : (match && (match[8]?.length === 11)) ? match[8] : null;
  };

  const handleProcessLinks = () => {
    setIsProcessing(true);
    const lines = urlInput.split('\n').map(l => l.trim()).filter(l => l.length > 0);
    const newVideos: YouTubeVideo[] = [];

    lines.forEach(line => {
        const id = extractVideoId(line);
        if (id && !videos.find(v => v.id === id)) {
            newVideos.push({
                id,
                url: line.startsWith('http') ? line : `https://youtube.com/shorts/${id}`,
                thumbnail: `https://img.youtube.com/vi/${id}/maxresdefault.jpg`,
                status: 'idle'
            });
        }
    });

    setVideos(prev => [...newVideos, ...prev]);
    setUrlInput('');
    setIsProcessing(false);
  };

  const handleCopyLinks = () => {
    const links = videos.map(v => v.url).join('\n');
    navigator.clipboard.writeText(links).then(() => {
        setCopyFeedback(true);
        setTimeout(() => setCopyFeedback(false), 2000);
    });
  };

  const removeVideo = (id: string) => {
    setVideos(prev => prev.filter(v => v.id !== id));
  };

  const clearAll = () => {
      if(window.confirm('Hapus semua antrean video?')) {
          setVideos([]);
      }
  };

  const downloadFile = async (video: YouTubeVideo): Promise<boolean> => {
    setVideos(prev => prev.map(v => v.id === video.id ? { ...v, status: 'processing', error: undefined } : v));

    // Mencoba beberapa instansi API jika terjadi kegagalan fetch/CORS
    for (const apiUrl of COBALT_INSTANCES) {
        try {
            const response = await fetch(apiUrl, {
                method: 'POST',
                headers: {
                    'Accept': 'application/json',
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    url: video.url,
                    videoQuality: '720',
                    vCodec: 'h264',
                    isAudioOnly: false,
                    removePlayer: true
                })
            });

            if (!response.ok) throw new Error(`HTTP Error ${response.status}`);

            const data = await response.json();

            if (data.status === 'stream' || data.status === 'redirect' || data.url) {
                // Gunakan cara teraman untuk mendownload: Hidden iframe atau direct window.location
                // Cara ini lebih tahan CORS dibanding fetch blob untuk video ukuran besar
                const link = document.createElement('a');
                link.href = data.url;
                link.target = '_blank'; // Membuka di tab baru sebentar lalu otomatis download
                link.setAttribute('download', `shorts-${video.id}.mp4`);
                document.body.appendChild(link);
                link.click();
                document.body.removeChild(link);

                setVideos(prev => prev.map(v => v.id === video.id ? { ...v, status: 'done' } : v));
                return true; // Sukses
            }
        } catch (err: any) {
            console.warn(`Gagal menggunakan instansi ${apiUrl}:`, err.message);
            // Lanjut ke instansi berikutnya dalam loop
        }
    }

    // Jika semua instansi gagal
    setVideos(prev => prev.map(v => v.id === video.id ? { ...v, status: 'error', error: 'API Error: Pastikan koneksi internet stabil atau coba lagi nanti.' } : v));
    return false;
  };

  const handleDownloadAll = async () => {
      if (videos.length === 0 || isDownloadingAll) return;

      const toDownload = videos.filter(v => v.status !== 'done');
      if (toDownload.length === 0) {
          alert("Semua video sudah selesai didownload.");
          return;
      }

      setIsDownloadingAll(true);

      // Proses download secara berurutan agar tidak membebani browser/API
      for (const video of toDownload) {
