import React, { useState } from 'react';
import { ArrowLeft, Youtube, Download, Trash2, Copy, Plus, List, Play, Loader2, CheckCircle, AlertCircle } from 'lucide-react';

interface YouTubeVideo {
    id: string;
    url: string;
    thumbnail: string;
    status: 'idle' | 'processing' | 'done' | 'error';
    error?: string;
}

interface ShortDownloaderProps {
  onBack: () => void;
}

// Daftar instansi Cobalt API publik yang lebih stabil dan mendukung CORS
const COBALT_INSTANCES = [
    'https://api.cobalt.tools/api/json',
    'https://cobalt-api.kwiateusz.pl/api/json',
    'https://api.v7.cobalt.tools/api/json',
    'https://cobalt.api.ryuko.space/api/json'
];

const ShortDownloader: React.FC<ShortDownloaderProps> = ({ onBack }) => {
  const [urlInput, setUrlInput] = useState('');
  const [videos, setVideos] = useState<YouTubeVideo[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isDownloadingAll, setIsDownloadingAll] = useState(false);
  const [copyFeedback, setCopyFeedback] = useState(false);

  const extractVideoId = (url: string): string | null => {
    const regExp = /^.*((youtu.be\/)|(v\/)|(\/u\/\w\/)|(embed\/)|(watch\?))\??v?=?([^#&?]*).*|.*shorts\/([^#&?]*).*/;
    const match = url.match(regExp);
    return (match && (match[7]?.length === 11)) ? match[7] : (match && (match[8]?.length === 11)) ? match[8] : null;
  };

  const handleProcessLinks = () => {
    setIsProcessing(true);
    const lines = urlInput.split('\n').map(l => l.trim()).filter(l => l.length > 0);
    const newVideos: YouTubeVideo[] = [];

    lines.forEach(line => {
        const id = extractVideoId(line);
        if (id && !videos.find(v => v.id === id)) {
            newVideos.push({
                id,
                url: line.startsWith('http') ? line : `https://youtube.com/shorts/${id}`,
                thumbnail: `https://img.youtube.com/vi/${id}/maxresdefault.jpg`,
                status: 'idle'
            });
        }
    });

    setVideos(prev => [...newVideos, ...prev]);
    setUrlInput('');
    setIsProcessing(false);
  };

  const handleCopyLinks = () => {
    const links = videos.map(v => v.url).join('\n');
    navigator.clipboard.writeText(links).then(() => {
        setCopyFeedback(true);
        setTimeout(() => setCopyFeedback(false), 2000);
    });
  };

  const removeVideo = (id: string) => {
    setVideos(prev => prev.filter(v => v.id !== id));
  };

  const clearAll = () => {
      if(window.confirm('Hapus semua antrean video?')) {
          setVideos([]);
      }
  };

  const downloadFile = async (video: YouTubeVideo): Promise<boolean> => {
    setVideos(prev => prev.map(v => v.id === video.id ? { ...v, status: 'processing', error: undefined } : v));

    // Mencoba beberapa instansi API jika terjadi kegagalan fetch/CORS
    // Kami juga mencoba menggunakan corsproxy.io jika fetch langsung gagal
    for (const apiUrl of COBALT_INSTANCES) {
        try {
            const fetchOptions: RequestInit = {
                method: 'POST',
                headers: {
                    'Accept': 'application/json',
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    url: video.url,
                    videoQuality: '720',
                    vCodec: 'h264',
                    isAudioOnly: false,
                    removePlayer: true
                })
            };

            let response;
            try {
                response = await fetch(apiUrl, fetchOptions);
            } catch (fetchErr) {
                // Jika "Failed to fetch", kemungkinan besar karena CORS. 
                // Kita coba pakai proxy untuk request JSON-nya.
                console.warn(`Direct fetch failed for ${apiUrl}, trying proxy...`);
                const proxyUrl = `https://corsproxy.io/?${encodeURIComponent(apiUrl)}`;
                response = await fetch(proxyUrl, fetchOptions);
            }

            if (!response.ok) continue;

            const data = await response.json();

            if (data.status === 'stream' || data.status === 'redirect' || data.url) {
                // Buat link unduhan rahasia
                const link = document.createElement('a');
                link.href = data.url;
                link.target = '_blank'; 
                // Atur atribut download (hanya berfungsi jika server tujuan mengizinkan)
                link.setAttribute('download', `shorts-${video.id}.mp4`);
                document.body.appendChild(link);
                link.click();

                // Beri sedikit jeda sebelum menghapus element
                setTimeout(() => {
                    if (document.body.contains(link)) {
                        document.body.removeChild(link);
                    }
                }, 100);

                setVideos(prev => prev.map(v => v.id === video.id ? { ...v, status: 'done' } : v));
                return true; 
            }
        } catch (err: any) {
            console.warn(`Instansi ${apiUrl} gagal:`, err.message);
            // Lanjut looping ke instansi berikutnya
        }
    }

    // Jika semua instansi dan metode gagal
    setVideos(prev => prev.map(v => v.id === video.id ? { ...v, status: 'error', error: 'Gagal mendapatkan link. Coba lagi dalam beberapa saat.' } : v));
    return false;
  };

  const handleDownloadAll = async () => {
      if (videos.length === 0 || isDownloadingAll) return;

      const toDownload = videos.filter(v => v.status !== 'done');
      if (toDownload.length === 0) {
          alert("Semua video dalam antrean sudah selesai.");
          return;
      }

      setIsDownloadingAll(true);

      for (const video of toDownload) {
          await downloadFile(video);
          // Jeda lebih lama (2 detik) untuk mencegah browser memblokir unduhan beruntun 
          // dan mengurangi risiko deteksi bot oleh server API.
          await new Promise(r => setTimeout(r, 2000));
      }

      setIsDownloadingAll(false);
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 flex flex-col">
      <div className="bg-slate-900 border-b border-slate-800 p-4 sticky top-0 z-20 flex items-center justify-between">
        <div className="flex items-center gap-4">
            <button onClick={onBack} className="p-2 hover:bg-slate-800 rounded-full text-slate-400 hover:text-white transition-colors">
              <ArrowLeft className="w-5 h-5" />
            </button>
            <h1 className="text-xl font-bold flex items-center gap-2">
              <Youtube className="w-6 h-6 text-red-600" />
              Shorts Downloader
            </h1>
        </div>
        {videos.length > 0 && (
            <div className="flex items-center gap-2">
                <button 
                  onClick={handleDownloadAll} 
                  disabled={isDownloadingAll}
                  className="bg-red-600 hover:bg-red-500 disabled:bg-slate-700 text-white text-xs px-4 py-2 rounded-lg font-semibold shadow-lg shadow-red-900/20 flex items-center gap-2 transition-all active:scale-95"
                >
                  {isDownloadingAll ? (
                      <><Loader2 className="w-4 h-4 animate-spin" /> Proses Antrean...</>
                  ) : (
                      <><Download className="w-4 h-4" /> Download Semua</>
                  )}
                </button>
                <button 
                  onClick={clearAll} 
                  className="text-slate-400 hover:text-red-400 text-xs px-3 py-2 rounded-lg font-medium border border-transparent hover:border-red-500/20 flex items-center gap-2 transition-all"
                >
                  <Trash2 className="w-4 h-4" />
                  Hapus Daftar
                </button>
            </div>
        )}
      </div>

      <div className="flex-1 max-w-5xl w-full mx-auto p-6">
        <div className="bg-slate-900 rounded-2xl p-6 border border-slate-800 shadow-xl mb-8">
            <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-2">
                    <div className="w-8 h-8 rounded-lg bg-red-600/10 flex items-center justify-center">
                      <List className="w-4 h-4 text-red-500" />
                    </div>
                    <h2 className="text-lg font-semibold text-white">Input Link YouTube Shorts</h2>
                </div>
                {videos.length > 0 && (
                    <button 
                      onClick={handleCopyLinks} 
                      className="text-[10px] text-slate-400 hover:text-white uppercase tracking-widest font-bold flex items-center gap-1.5 transition-colors"
                    >
                        <Copy className="w-3 h-3" /> {copyFeedback ? 'Disalin!' : 'Salin Semua Link'}
                    </button>
                )}
            </div>
            <textarea 
                value={urlInput}
                onChange={(e) => setUrlInput(e.target.value)}
                placeholder="Tempel link Shorts di sini (satu baris satu link)..."
                rows={5}
                className="w-full bg-slate-950 border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-red-600 outline-none resize-none font-mono text-sm mb-4 transition-all"
            />
            <button 
              onClick={handleProcessLinks} 
              disabled={!urlInput.trim() || isProcessing} 
              className="w-full bg-red-600 hover:bg-red-500 disabled:opacity-50 text-white px-6 py-4 rounded-xl font-bold flex items-center justify-center gap-2 shadow-lg shadow-red-900/20 transition-all active:scale-[0.98]"
            >
                {isProcessing ? <Loader2 className="w-5 h-5 animate-spin" /> : <Plus className="w-5 h-5" />}
                Tambahkan ke Daftar Download
            </button>
        </div>

        <div className="space-y-4">
            <div className="flex items-center justify-between">
                <h2 className="text-lg font-semibold text-slate-300 flex items-center gap-2">
                  Daftar Antrean <span className="bg-slate-800 text-slate-400 text-xs px-2 py-1 rounded-full">{videos.length}</span>
                </h2>
                {isDownloadingAll && (
                    <span className="text-xs text-blue-400 animate-pulse font-medium">Proses batch sedang berjalan...</span>
                )}
            </div>

            {videos.length === 0 ? (
                <div className="text-center py-20 text-slate-700 border-2 border-dashed border-slate-800 rounded-2xl">
                    <Youtube className="w-16 h-16 mx-auto mb-4 opacity-20" />
                    <p className="text-lg font-medium">Antrean Kosong</p>
                    <p className="text-sm opacity-60">Masukkan link Shorts di atas untuk memulai batch download.</p>
                </div>
            ) : (
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                    {videos.map((video) => (
                        <div key={video.id} className={`bg-slate-900 border rounded-2xl overflow-hidden group transition-all animate-slide-up ${video.status === 'done' ? 'border-green-500/50 shadow-[0_0_15px_rgba(34,197,94,0.1)]' : video.status === 'error' ? 'border-red-500/50' : 'border-slate-800 hover:border-red-600/50'}`}>
                            <div className="aspect-[9/16] relative bg-black">
                                <img 
                                  src={video.thumbnail} 
