    setVideos(prev => prev.filter(v => v.id !== id));
  };

  const clearAll = () => {
      if(window.confirm('Hapus semua daftar antrean?')) {
          setVideos([]);
      }
  };

  // Menggunakan prefix 'ss' untuk otomatis redirect ke downloader savefrom/ssyoutube
  const getDownloadLink = (url: string) => {
      // Mengubah https://youtube.com/... menjadi https://ssyoutube.com/...
      return url.replace('youtube.com', 'ssyoutube.com').replace('youtu.be', 'ssyoutube.com/watch?v=');
  };

  const triggerDownload = (video: YouTubeVideo) => {
      setVideos(prev => prev.map(v => v.id === video.id ? { ...v, status: 'opening' } : v));

      const win = window.open(getDownloadLink(video.url), '_blank');

      // Beri tanda selesai setelah jendela terbuka
      setTimeout(() => {
          setVideos(prev => prev.map(v => v.id === video.id ? { ...v, status: 'done' } : v));
