import React, { useState, useRef } from 'react';
import { ArrowLeft, Video, LayoutTemplate, ShieldCheck, Download, Upload, Loader2, Play, Trash2, Maximize, Move } from 'lucide-react';
import { FrameSettings, WatermarkPosition } from '../types';

interface FrameEditorProps {
    onBack: () => void;
}

const FrameEditor: React.FC<FrameEditorProps> = ({ onBack }) => {
    const [settings, setSettings] = useState<FrameSettings>({
        id: 'frame-1',
        videoUrl: null,
        frameImageUrl: null,
        watermarkUrl: null,
        watermarkOpacity: 0.8,
        watermarkPosition: WatermarkPosition.BOTTOM_RIGHT,
        watermarkSize: 15,
        generatedVideoUrl: null
    });

    const [isProcessing, setIsProcessing] = useState(false);
    const [progress, setProgress] = useState('');

    const videoInputRef = useRef<HTMLInputElement>(null);
    const frameInputRef = useRef<HTMLInputElement>(null);
    const watermarkInputRef = useRef<HTMLInputElement>(null);
    const videoRef = useRef<HTMLVideoElement>(null);

    const handleFileUpload = (type: 'video' | 'frame' | 'watermark', e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        const url = URL.createObjectURL(file);
        if (type === 'video') setSettings(prev => ({ ...prev, videoUrl: url }));
        if (type === 'frame') setSettings(prev => ({ ...prev, frameImageUrl: url }));
        if (type === 'watermark') setSettings(prev => ({ ...prev, watermarkUrl: url }));
    };

    const processVideo = async () => {
        if (!settings.videoUrl) {
            alert("Upload video terlebih dahulu.");
            return;
        }

        setIsProcessing(true);
        setProgress('Preparing canvas...');

        try {
            const canvas = document.createElement('canvas');
            const ctx = canvas.getContext('2d');
            if (!ctx) throw new Error("Could not get context");

            canvas.width = 720;
            canvas.height = 1280;

            const video = document.createElement('video');
            video.src = settings.videoUrl;
            video.crossOrigin = 'anonymous';
            video.muted = true;
            await new Promise((r) => video.onloadedmetadata = r);

            let frameImg = null;
            if (settings.frameImageUrl) {
                frameImg = new Image();
                frameImg.src = settings.frameImageUrl;
                await new Promise((r) => frameImg!.onload = r);
            }

            let watermarkImg = null;
            if (settings.watermarkUrl) {
                watermarkImg = new Image();
                watermarkImg.src = settings.watermarkUrl;
                await new Promise((r) => watermarkImg!.onload = r);
            }

            const stream = canvas.captureStream(30);
            const recorder = new MediaRecorder(stream, { mimeType: 'video/webm;codecs=vp9' });
            const chunks: Blob[] = [];

            recorder.ondataavailable = (e) => chunks.push(e.data);
            recorder.onstop = () => {
                const blob = new Blob(chunks, { type: 'video/webm' });
                const url = URL.createObjectURL(blob);
                setSettings(prev => ({ ...prev, generatedVideoUrl: url }));
                setIsProcessing(false);
                setProgress('');
            };

            recorder.start();
            video.play();

            const draw = () => {
                if (video.paused || video.ended) {
                    recorder.stop();
                    return;
                }

                ctx.fillStyle = 'black';
                ctx.fillRect(0, 0, canvas.width, canvas.height);

                // 1. Draw Video
                const vRatio = video.videoWidth / video.videoHeight;
                const cRatio = canvas.width / canvas.height;
                let dw, dh, sx, sy;
                if (vRatio > cRatio) {
                    dh = canvas.height; dw = dh * vRatio; sx = (canvas.width - dw) / 2; sy = 0;
                } else {
                    dw = canvas.width; dh = dw / vRatio; sx = 0; sy = (canvas.height - dh) / 2;
                }
                ctx.drawImage(video, sx, sy, dw, dh);

                // 2. Draw Frame
                if (frameImg) {
                    ctx.drawImage(frameImg, 0, 0, canvas.width, canvas.height);
                }

                // 3. Draw Watermark
                if (watermarkImg) {
                    ctx.save();
                    ctx.globalAlpha = settings.watermarkOpacity;
                    const wSize = (canvas.width * settings.watermarkSize) / 100;
                    const wAspect = watermarkImg.width / watermarkImg.height;
                    const wWidth = wSize;
                    const wHeight = wSize / wAspect;
                    const padding = 40;

                    let wx, wy;
                    switch (settings.watermarkPosition) {
                        case WatermarkPosition.TOP_LEFT: wx = padding; wy = padding; break;
                        case WatermarkPosition.TOP_RIGHT: wx = canvas.width - wWidth - padding; wy = padding; break;
                        case WatermarkPosition.BOTTOM_LEFT: wx = padding; wy = canvas.height - wHeight - padding; break;
                        case WatermarkPosition.BOTTOM_RIGHT: 
                        default: wx = canvas.width - wWidth - padding; wy = canvas.height - wHeight - padding; break;
                    }

                    ctx.drawImage(watermarkImg, wx, wy, wWidth, wHeight);
                    ctx.restore();
                }

                setProgress(`Processing: ${Math.floor(video.currentTime)}s`);
                requestAnimationFrame(draw);
            };

            draw();

        } catch (err) {
            console.error(err);
            setIsProcessing(false);
            alert("Failed to process video.");
        }
    };

    return (
        <div className="flex flex-col lg:flex-row h-screen w-full overflow-hidden bg-slate-950 text-white font-inter">
            {/* Sidebar Controls */}
            <div className="w-full lg:w-96 bg-slate-900 border-r border-slate-800 flex flex-col h-auto lg:h-full shadow-2xl z-20 overflow-y-auto">
                <div className="p-6 border-b border-slate-800 flex items-center gap-3">
                    <button onClick={onBack} className="p-2 -ml-2 hover:bg-slate-800 rounded-full text-slate-400 hover:text-white transition-colors">
                        <ArrowLeft className="w-5 h-5" />
                    </button>
                    <h1 className="text-xl font-bold bg-gradient-to-r from-purple-400 to-pink-500 bg-clip-text text-transparent">Frame & Watermark</h1>
                </div>

                <div className="p-6 space-y-8">
                    {/* Media Uploads */}
                    <div className="space-y-4">
                        <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2">
                            <Video className="w-3 h-3" /> Background Video
                        </label>
                        <input type="file" accept="video/*" ref={videoInputRef} className="hidden" onChange={(e) => handleFileUpload('video', e)} />
                        <button onClick={() => videoInputRef.current?.click()} className="w-full py-3 px-4 bg-slate-800 border border-slate-700 rounded-xl hover:border-purple-500 transition-all flex items-center justify-center gap-2 text-sm">
                            <Upload className="w-4 h-4" /> {settings.videoUrl ? 'Ganti Video' : 'Upload Video'}
                        </button>

                        <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2 pt-2">
                            <LayoutTemplate className="w-3 h-3" /> Custom Frame (PNG)
                        </label>
                        <input type="file" accept="image/png" ref={frameInputRef} className="hidden" onChange={(e) => handleFileUpload('frame', e)} />
                        <button onClick={() => frameInputRef.current?.click()} className="w-full py-3 px-4 bg-slate-800 border border-slate-700 rounded-xl hover:border-purple-500 transition-all flex items-center justify-center gap-2 text-sm">
                            <LayoutTemplate className="w-4 h-4" /> {settings.frameImageUrl ? 'Ganti Frame' : 'Upload Frame'}
                        </button>

                        <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2 pt-2">
                            <ShieldCheck className="w-3 h-3" /> Watermark Logo
                        </label>
                        <input type="file" accept="image/*" ref={watermarkInputRef} className="hidden" onChange={(e) => handleFileUpload('watermark', e)} />
                        <button onClick={() => watermarkInputRef.current?.click()} className="w-full py-3 px-4 bg-slate-800 border border-slate-700 rounded-xl hover:border-purple-500 transition-all flex items-center justify-center gap-2 text-sm">
                            <ShieldCheck className="w-4 h-4" /> {settings.watermarkUrl ? 'Ganti Logo' : 'Upload Watermark'}
                        </button>
                    </div>

                    {/* Branding Settings */}
                    {settings.watermarkUrl && (
                        <div className="space-y-5 animate-in fade-in slide-in-from-top-4 duration-300">
                            <div className="border-t border-slate-800 pt-6">
                                <h3 className="text-xs font-bold text-slate-400 mb-4 flex items-center gap-2"><Move className="w-3 h-3" /> Watermark Config</h3>

                                <div className="space-y-4">
                                    <div>
                                        <div className="flex justify-between text-[10px] text-slate-500 uppercase mb-2">
                                            <span>Posisi</span>
                                            <span className="text-purple-400">{settings.watermarkPosition.replace('-', ' ')}</span>
                                        </div>
                                        <div className="grid grid-cols-2 gap-2">
                                            {Object.values(WatermarkPosition).map(pos => (
                                                <button 
                                                    key={pos}
                                                    onClick={() => setSettings(prev => ({ ...prev, watermarkPosition: pos }))}
                                                    className={`py-2 text-[10px] font-bold rounded-lg border transition-all ${settings.watermarkPosition === pos ? 'bg-purple-600 border-purple-500 text-white' : 'bg-slate-800 border-slate-700 text-slate-400 hover:border-slate-600'}`}
                                                >
                                                    {pos.toUpperCase()}
                                                </button>
                                            ))}
                                        </div>
                                    </div>

                                    <div>
                                        <div className="flex justify-between text-[10px] text-slate-500 uppercase mb-2">
                                            <span>Ukuran</span>
                                            <span className="text-purple-400">{settings.watermarkSize}%</span>
                                        </div>
                                        <input 
                                            type="range" min="5" max="40" step="1"
                                            value={settings.watermarkSize}
                                            onChange={(e) => setSettings(prev => ({ ...prev, watermarkSize: Number(e.target.value) }))}
                                            className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-purple-500"
                                        />
                                    </div>

                                    <div>
                                        <div className="flex justify-between text-[10px] text-slate-500 uppercase mb-2">
                                            <span>Opasitas</span>
                                            <span className="text-purple-400">{Math.round(settings.watermarkOpacity * 100)}%</span>
                                        </div>
                                        <input 
                                            type="range" min="0.1" max="1" step="0.05"
                                            value={settings.watermarkOpacity}
                                            onChange={(e) => setSettings(prev => ({ ...prev, watermarkOpacity: Number(e.target.value) }))}
                                            className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-purple-500"
                                        />
                                    </div>
                                </div>
                            </div>
                        </div>
                    )}
                </div>

                <div className="mt-auto p-6 border-t border-slate-800 bg-slate-900/80 backdrop-blur-md sticky bottom-0">
                    <button 
                        onClick={processVideo}
                        disabled={isProcessing || !settings.videoUrl}
                        className={`w-full py-4 rounded-xl font-bold transition-all shadow-xl flex items-center justify-center gap-2 ${isProcessing ? 'bg-slate-700 cursor-not-allowed' : 'bg-purple-600 hover:bg-purple-500 active:scale-95 text-white'}`}
                    >
                        {isProcessing ? <><Loader2 className="w-5 h-5 animate-spin" /> {progress}</> : <><Play className="w-5 h-5 fill-current" /> Export Branding</>}
                    </button>
                </div>
            </div>

            {/* Preview Area */}
            <div className="flex-1 flex flex-col items-center justify-center p-8 relative">
                <div className="absolute inset-0 opacity-5 pointer-events-none" style={{ backgroundImage: 'radial-gradient(#475569 1px, transparent 1px)', backgroundSize: '24px 24px' }}></div>

                <div className="relative z-10 flex flex-col items-center gap-6">
                    <div className="flex items-center gap-2 text-slate-500 text-xs font-bold uppercase tracking-widest bg-slate-900/50 px-4 py-2 rounded-full border border-slate-800">
                        <Maximize className="w-3 h-3" /> Brand Preview
                    </div>

                    <div className="relative w-[320px] h-[570px] bg-black rounded-[32px] overflow-hidden shadow-[0_0_80px_rgba(168,85,247,0.15)] border-[8px] border-slate-800 ring-1 ring-slate-700">
                        {settings.videoUrl ? (
                            <video ref={videoRef} src={settings.videoUrl} autoPlay loop muted playsInline className="absolute inset-0 w-full h-full object-cover" />
                        ) : (
                            <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-700 p-8 text-center bg-slate-900">
                                <Video className="w-12 h-12 mb-4 opacity-20" />
                                <p className="text-xs font-medium">Upload video untuk melihat preview</p>
                            </div>
                        )}

                        {settings.frameImageUrl && (
                            <img src={settings.frameImageUrl} className="absolute inset-0 w-full h-full object-cover pointer-events-none" alt="Frame" />
                        )}

                        {settings.watermarkUrl && (
                            <div className={`absolute p-5 pointer-events-none flex transition-all duration-300 ${
                                settings.watermarkPosition === WatermarkPosition.TOP_LEFT ? 'top-0 left-0' :
                                settings.watermarkPosition === WatermarkPosition.TOP_RIGHT ? 'top-0 right-0' :
                                settings.watermarkPosition === WatermarkPosition.BOTTOM_LEFT ? 'bottom-0 left-0' : 'bottom-0 right-0'
                            }`}>
                                <img 
                                    src={settings.watermarkUrl} 
                                    style={{ 
                                        width: `${settings.watermarkSize * 3}px`, 
                                        opacity: settings.watermarkOpacity 
                                    }} 
                                    className="object-contain" 
                                    alt="Watermark" 
                                />
                            </div>
                        )}
                    </div>

                    {settings.generatedVideoUrl && (
                        <div className="flex flex-col items-center gap-3 animate-in fade-in slide-in-from-bottom-4 duration-500">
                            <button 
                                onClick={() => {
                                    const a = document.createElement('a');
                                    a.href = settings.generatedVideoUrl!;
                                    a.download = `branded-video-${Date.now()}.webm`;
                                    a.click();
                                }}
                                className="bg-green-600 hover:bg-green-500 text-white px-8 py-3 rounded-xl font-bold flex items-center gap-2 shadow-lg shadow-green-900/20 transition-all active:scale-95"
                            >
                                <Download className="w-5 h-5" /> Download Result
                            </button>
                            <button 
                                onClick={() => setSettings(prev => ({ ...prev, generatedVideoUrl: null }))}
                                className="text-slate-500 hover:text-red-400 text-xs flex items-center gap-1.5 transition-colors"
                            >
                                <Trash2 className="w-3 h-3" /> Clear Generated
                            </button>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

export default FrameEditor;

export enum ThemeColor {
  RED = 'red',
  BLUE = 'blue',
  PURPLE = 'purple'
}

export enum WatermarkPosition {
  TOP_LEFT = 'top-left',
  TOP_RIGHT = 'top-right',
  BOTTOM_LEFT = 'bottom-left',
  BOTTOM_RIGHT = 'bottom-right'
}

export interface NewsOverlayState {
  headline: string;
  subheadline: string;
  theme: ThemeColor;
  overlayImage: string | null;
}

export interface NewsItem extends NewsOverlayState {
  id: string;
  // Media
  videoUrl: string | null;
  videoFile: File | null;
  // Result
  generatedVideoUrl: string | null;
}

export interface FrameVideoItem {
  id: string;
  url: string;
  name: string;
  status: 'idle' | 'processing' | 'done' | 'error';
  generatedUrl: string | null;
  error?: string;
}

export interface FrameSettings {
  frameImageUrl: string | null;
  watermarkUrl: string | null;
  watermarkOpacity: number;
  watermarkPosition: WatermarkPosition;
  watermarkSize: number;
  videos: FrameVideoItem[];
}

export interface GlobalState {
  audioUrl: string | null;
  audioFile: File | null;
  isProcessing: boolean;
  processingItemId: string | null;
  progress: string;
}

export interface ScrapedArticle {
  id: string;
  url: string;
  title: string;
  firstParagraph: string;
  imageUrl: string;
}

import React, { useState, useRef } from 'react';
import { ArrowLeft, Video, LayoutTemplate, ShieldCheck, Download, Upload, Loader2, Play, Trash2, Maximize, Move, FileVideo, CheckCircle, AlertCircle, List } from 'lucide-react';
import { FrameSettings, WatermarkPosition, FrameVideoItem } from '../types';

interface FrameEditorProps {
    onBack: () => void;
}

const FrameEditor: React.FC<FrameEditorProps> = ({ onBack }) => {
    const [settings, setSettings] = useState<FrameSettings>({
        frameImageUrl: null,
        watermarkUrl: null,
        watermarkOpacity: 0.8,
        watermarkPosition: WatermarkPosition.BOTTOM_RIGHT,
        watermarkSize: 15,
        videos: []
    });

    const [activeVideoId, setActiveVideoId] = useState<string | null>(null);
    const [isProcessing, setIsProcessing] = useState(false);
    const [progress, setProgress] = useState('');

    const videoInputRef = useRef<HTMLInputElement>(null);
    const frameInputRef = useRef<HTMLInputElement>(null);
    const watermarkInputRef = useRef<HTMLInputElement>(null);
    const videoRef = useRef<HTMLVideoElement>(null);

    const activeVideo = settings.videos.find(v => v.id === activeVideoId) || settings.videos[0];

    const handleFileUpload = (type: 'video' | 'frame' | 'watermark', e: React.ChangeEvent<HTMLInputElement>) => {
        const files = e.target.files;
        if (!files || files.length === 0) return;

        if (type === 'video') {
            const newVideos: FrameVideoItem[] = Array.from(files).map(file => ({
                id: Math.random().toString(36).substr(2, 9),
                url: URL.createObjectURL(file),
                name: file.name,
                status: 'idle',
                generatedUrl: null
            }));
            setSettings(prev => ({ ...prev, videos: [...prev.videos, ...newVideos] }));
            if (!activeVideoId) setActiveVideoId(newVideos[0].id);
        } else {
            const file = files[0];
            const url = URL.createObjectURL(file);
            if (type === 'frame') setSettings(prev => ({ ...prev, frameImageUrl: url }));
            if (type === 'watermark') setSettings(prev => ({ ...prev, watermarkUrl: url }));
        }
        // Reset input so the same file can be uploaded again if needed
        e.target.value = '';
    };

    const removeVideo = (id: string) => {
        setSettings(prev => {
            const filtered = prev.videos.filter(v => v.id !== id);
            if (activeVideoId === id) {
                setActiveVideoId(filtered.length > 0 ? filtered[0].id : null);
            }
            return { ...prev, videos: filtered };
        });
    };

    const processSingleVideo = async (videoItem: FrameVideoItem): Promise<string> => {
        return new Promise(async (resolve, reject) => {
            try {
                const canvas = document.createElement('canvas');
                const ctx = canvas.getContext('2d');
                if (!ctx) throw new Error("Could not get context");

                canvas.width = 720;
                canvas.height = 1280;

                const video = document.createElement('video');
                video.src = videoItem.url;
                video.crossOrigin = 'anonymous';
                video.muted = true;
                await new Promise((r) => video.onloadedmetadata = r);

                let frameImg = null;
                if (settings.frameImageUrl) {
                    frameImg = new Image();
                    frameImg.src = settings.frameImageUrl;
                    await new Promise((r) => frameImg!.onload = r);
                }

                let watermarkImg = null;
                if (settings.watermarkUrl) {
                    watermarkImg = new Image();
                    watermarkImg.src = settings.watermarkUrl;
                    await new Promise((r) => watermarkImg!.onload = r);
                }

                const stream = canvas.captureStream(30);
                const recorder = new MediaRecorder(stream, { mimeType: 'video/webm;codecs=vp9' });
                const chunks: Blob[] = [];

                recorder.ondataavailable = (e) => chunks.push(e.data);
                recorder.onstop = () => {
                    const blob = new Blob(chunks, { type: 'video/webm' });
                    const url = URL.createObjectURL(blob);
                    resolve(url);
                };

                recorder.start();
                video.play();

                const draw = () => {
                    if (video.paused || video.ended) {
                        recorder.stop();
                        return;
                    }

                    ctx.fillStyle = 'black';
                    ctx.fillRect(0, 0, canvas.width, canvas.height);

                    const vRatio = video.videoWidth / video.videoHeight;
                    const cRatio = canvas.width / canvas.height;
                    let dw, dh, sx, sy;
                    if (vRatio > cRatio) {
                        dh = canvas.height; dw = dh * vRatio; sx = (canvas.width - dw) / 2; sy = 0;
                    } else {
                        dw = canvas.width; dh = dw / vRatio; sx = 0; sy = (canvas.height - dh) / 2;
                    }
                    ctx.drawImage(video, sx, sy, dw, dh);

                    if (frameImg) ctx.drawImage(frameImg, 0, 0, canvas.width, canvas.height);

                    if (watermarkImg) {
                        ctx.save();
                        ctx.globalAlpha = settings.watermarkOpacity;
                        const wSize = (canvas.width * settings.watermarkSize) / 100;
                        const wAspect = watermarkImg.width / watermarkImg.height;
                        const wWidth = wSize;
                        const wHeight = wSize / wAspect;
                        const padding = 40;

                        let wx, wy;
                        switch (settings.watermarkPosition) {
                            case WatermarkPosition.TOP_LEFT: wx = padding; wy = padding; break;
                            case WatermarkPosition.TOP_RIGHT: wx = canvas.width - wWidth - padding; wy = padding; break;
                            case WatermarkPosition.BOTTOM_LEFT: wx = padding; wy = canvas.height - wHeight - padding; break;
                            case WatermarkPosition.BOTTOM_RIGHT: 
                            default: wx = canvas.width - wWidth - padding; wy = canvas.height - wHeight - padding; break;
                        }
                        ctx.drawImage(watermarkImg, wx, wy, wWidth, wHeight);
                        ctx.restore();
                    }
                    requestAnimationFrame(draw);
                };
                draw();
            } catch (err) {
                reject(err);
            }
        });
    };

    const processAllVideos = async () => {
        if (settings.videos.length === 0) return;
        setIsProcessing(true);

        const videosToProcess = settings.videos.filter(v => v.status !== 'done');

        for (let i = 0; i < videosToProcess.length; i++) {
            const video = videosToProcess[i];
            setSettings(prev => ({
                ...prev,
                videos: prev.videos.map(v => v.id === video.id ? { ...v, status: 'processing' } : v)
            }));
            setProgress(`Processing ${i + 1}/${videosToProcess.length}: ${video.name}`);

            try {
                const resultUrl = await processSingleVideo(video);
                setSettings(prev => ({
                    ...prev,
                    videos: prev.videos.map(v => v.id === video.id ? { ...v, status: 'done', generatedUrl: resultUrl } : v)
                }));
            } catch (err) {
                setSettings(prev => ({
                    ...prev,
                    videos: prev.videos.map(v => v.id === video.id ? { ...v, status: 'error', error: 'Failed' } : v)
                }));
            }
        }

        setIsProcessing(false);
        setProgress('');
    };

    const downloadAll = () => {
        settings.videos.forEach((v, i) => {
            if (v.generatedUrl) {
                setTimeout(() => {
                    const a = document.createElement('a');
                    a.href = v.generatedUrl!;
                    a.download = `branded-${v.name.split('.')[0]}.webm`;
                    a.click();
                }, i * 500);
            }
        });
    };

    return (
        <div className="flex flex-col lg:flex-row h-screen w-full overflow-hidden bg-slate-950 text-white font-inter">
            {/* Sidebar Controls */}
            <div className="w-full lg:w-96 bg-slate-900 border-r border-slate-800 flex flex-col h-auto lg:h-full shadow-2xl z-20 overflow-hidden">
                <div className="p-6 border-b border-slate-800 flex items-center gap-3 shrink-0">
                    <button onClick={onBack} className="p-2 -ml-2 hover:bg-slate-800 rounded-full text-slate-400 hover:text-white transition-colors">
                        <ArrowLeft className="w-5 h-5" />
                    </button>
                    <h1 className="text-xl font-bold bg-gradient-to-r from-purple-400 to-pink-500 bg-clip-text text-transparent">Frame & Brand</h1>
                </div>

                <div className="flex-1 overflow-y-auto p-6 space-y-8">
                    {/* Media Queue */}
                    <div className="space-y-4">
                        <div className="flex items-center justify-between">
                            <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2">
                                <List className="w-3 h-3" /> Media Queue ({settings.videos.length})
                            </label>
                            <input type="file" accept="video/*" multiple ref={videoInputRef} className="hidden" onChange={(e) => handleFileUpload('video', e)} />
                            <button onClick={() => videoInputRef.current?.click()} className="text-[10px] text-purple-400 hover:text-purple-300 font-bold uppercase tracking-widest flex items-center gap-1 transition-colors">
                                <Plus className="w-3 h-3" /> Add Videos
                            </button>
                        </div>

                        {settings.videos.length === 0 ? (
                            <div className="border-2 border-dashed border-slate-800 rounded-xl p-8 text-center bg-slate-950/50">
                                <Video className="w-8 h-8 mx-auto mb-3 text-slate-700 opacity-20" />
                                <p className="text-xs text-slate-600">No videos in queue</p>
                            </div>
                        ) : (
                            <div className="space-y-2 max-h-64 overflow-y-auto pr-2 scrollbar-thin">
                                {settings.videos.map((v) => (
                                    <div 
                                        key={v.id}
                                        onClick={() => setActiveVideoId(v.id)}
                                        className={`p-3 rounded-xl border transition-all cursor-pointer flex items-center justify-between group ${
                                            v.id === activeVideoId ? 'bg-purple-600/10 border-purple-500/50 shadow-lg' : 'bg-slate-800 border-slate-700 hover:border-slate-600'
                                        }`}
                                    >
                                        <div className="flex items-center gap-3 overflow-hidden">
                                            {v.status === 'processing' ? <Loader2 className="w-4 h-4 text-purple-400 animate-spin shrink-0" /> : 
                                             v.status === 'done' ? <CheckCircle className="w-4 h-4 text-green-500 shrink-0" /> :
                                             v.status === 'error' ? <AlertCircle className="w-4 h-4 text-red-500 shrink-0" /> :
                                             <FileVideo className="w-4 h-4 text-slate-500 shrink-0" />}
                                            <span className="text-xs truncate text-slate-300 font-medium">{v.name}</span>
                                        </div>
                                        <button onClick={(e) => { e.stopPropagation(); removeVideo(v.id); }} className="opacity-0 group-hover:opacity-100 p-1.5 hover:bg-red-500/20 text-slate-500 hover:text-red-400 rounded-lg transition-all">
                                            <Trash2 className="w-3 h-3" />
                                        </button>
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>

                    {/* branding settings */}
                    <div className="space-y-6 pt-2">
                        <div>
                            <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2 mb-3">
                                <LayoutTemplate className="w-3 h-3" /> Frame Overlay (PNG)
                            </label>
                            <input type="file" accept="image/png" ref={frameInputRef} className="hidden" onChange={(e) => handleFileUpload('frame', e)} />
                            <button onClick={() => frameInputRef.current?.click()} className="w-full py-3 px-4 bg-slate-800 border border-slate-700 rounded-xl hover:border-purple-500 transition-all flex items-center justify-center gap-2 text-sm">
                                <Upload className="w-4 h-4" /> {settings.frameImageUrl ? 'Change Frame' : 'Upload Frame'}
                            </button>
                        </div>

                        <div>
                            <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2 mb-3">
