import React, { useState, useRef } from 'react';
import { ArrowLeft, Video, LayoutTemplate, ShieldCheck, Download, Upload, Loader2, Play, Trash2, Maximize, Move, FileVideo, CheckCircle, AlertCircle, List, Plus } from 'lucide-react';
import { FrameSettings, WatermarkPosition, FrameVideoItem } from '../types';

interface FrameEditorProps {
    onBack: () => void;
}

const FrameEditor: React.FC<FrameEditorProps> = ({ onBack }) => {
    const [settings, setSettings] = useState<FrameSettings>({
        frameImageUrl: null,
        watermarkUrl: null,
        watermarkOpacity: 0.8,
        watermarkPosition: WatermarkPosition.BOTTOM_RIGHT,
        watermarkSize: 15,
        videos: []
    });

    const [activeVideoId, setActiveVideoId] = useState<string | null>(null);
    const [isProcessing, setIsProcessing] = useState(false);
    const [progress, setProgress] = useState('');

    const videoInputRef = useRef<HTMLInputElement>(null);
    const frameInputRef = useRef<HTMLInputElement>(null);
    const watermarkInputRef = useRef<HTMLInputElement>(null);
    const videoRef = useRef<HTMLVideoElement>(null);

    const activeVideo = settings.videos.find(v => v.id === activeVideoId) || settings.videos[0];

    const handleFileUpload = (type: 'video' | 'frame' | 'watermark', e: React.ChangeEvent<HTMLInputElement>) => {
        const files = e.target.files;
        if (!files || files.length === 0) return;

        if (type === 'video') {
            const newVideos: FrameVideoItem[] = Array.from(files).map((file: File) => ({
                id: Math.random().toString(36).substr(2, 9),
                url: URL.createObjectURL(file),
                name: file.name,
                status: 'idle',
                generatedUrl: null
            }));
            setSettings(prev => ({ ...prev, videos: [...prev.videos, ...newVideos] }));
            if (!activeVideoId) setActiveVideoId(newVideos[0].id);
        } else {
            const file = files[0];
            const url = URL.createObjectURL(file);
            if (type === 'frame') setSettings(prev => ({ ...prev, frameImageUrl: url }));
            if (type === 'watermark') setSettings(prev => ({ ...prev, watermarkUrl: url }));
        }
        e.target.value = '';
    };

    const removeVideo = (id: string) => {
        setSettings(prev => {
            const filtered = prev.videos.filter(v => v.id !== id);
            if (activeVideoId === id) {
                setActiveVideoId(filtered.length > 0 ? filtered[0].id : null);
            }
            return { ...prev, videos: filtered };
        });
    };

    const processSingleVideo = async (videoItem: FrameVideoItem): Promise<string> => {
        return new Promise(async (resolve, reject) => {
            try {
                const canvas = document.createElement('canvas');
                const ctx = canvas.getContext('2d');
                if (!ctx) throw new Error("Could not get context");

                canvas.width = 720;
                canvas.height = 1280;

                const video = document.createElement('video');
                video.src = videoItem.url;
                video.crossOrigin = 'anonymous';
                video.muted = true; // Still mute to prevent audio feedback during processing
                await new Promise((r) => video.onloadedmetadata = r);

                // Setup Audio Context to capture video sound
                const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
                const source = audioCtx.createMediaElementSource(video);
                const dest = audioCtx.createMediaStreamDestination();
                source.connect(dest);
                // Note: We don't connect to audioCtx.destination so the user doesn't hear the fast-forward/processing audio

                let frameImg = null;
                if (settings.frameImageUrl) {
                    frameImg = new Image();
                    frameImg.src = settings.frameImageUrl;
                    await new Promise((r) => frameImg!.onload = r);
                }

                let watermarkImg = null;
                if (settings.watermarkUrl) {
                    watermarkImg = new Image();
                    watermarkImg.src = settings.watermarkUrl;
                    await new Promise((r) => watermarkImg!.onload = r);
                }

                const videoTrack = canvas.captureStream(30).getVideoTracks()[0];
                const audioTrack = dest.stream.getAudioTracks()[0];

                const tracks = [videoTrack];
                if (audioTrack) tracks.push(audioTrack);

                const combinedStream = new MediaStream(tracks);
                const recorder = new MediaRecorder(combinedStream, { mimeType: 'video/webm;codecs=vp9' });
                const chunks: Blob[] = [];

                recorder.ondataavailable = (e) => {
                    if (e.data.size > 0) chunks.push(e.data);
                };

                recorder.onstop = () => {
                    audioCtx.close();
                    const blob = new Blob(chunks, { type: 'video/webm' });
                    const url = URL.createObjectURL(blob);
                    resolve(url);
                };

                recorder.start();
                video.play();

                const draw = () => {
                    if (video.paused || video.ended) {
                        recorder.stop();
                        return;
                    }

                    ctx.fillStyle = 'black';
                    ctx.fillRect(0, 0, canvas.width, canvas.height);

                    const vRatio = video.videoWidth / video.videoHeight;
                    const cRatio = canvas.width / canvas.height;
                    let dw, dh, sx, sy;
                    if (vRatio > cRatio) {
                        dh = canvas.height; dw = dh * vRatio; sx = (canvas.width - dw) / 2; sy = 0;
                    } else {
                        dw = canvas.width; dh = dw / vRatio; sx = 0; sy = (canvas.height - dh) / 2;
                    }
