                                <Upload className="w-4 h-4" /> {settings.frameImageUrl ? 'Change Frame' : 'Upload Frame'}
                            </button>
                        </div>

                        <div>
                            <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2 mb-3">
                                <ShieldCheck className="w-3 h-3" /> Watermark Logo
                            </label>
                            <input type="file" accept="image/*" ref={watermarkInputRef} className="hidden" onChange={(e) => handleFileUpload('watermark', e)} />
                            <button onClick={() => watermarkInputRef.current?.click()} className="w-full py-3 px-4 bg-slate-800 border border-slate-700 rounded-xl hover:border-purple-500 transition-all flex items-center justify-center gap-2 text-sm">
                                <ShieldCheck className="w-4 h-4" /> {settings.watermarkUrl ? 'Change Logo' : 'Upload Logo'}
                            </button>
                        </div>

                        {settings.watermarkUrl && (
                            <div className="space-y-5 animate-in fade-in slide-in-from-top-4 duration-300 border-t border-slate-800 pt-6">
                                <h3 className="text-xs font-bold text-slate-400 flex items-center gap-2"><Move className="w-3 h-3" /> Watermark Config</h3>

                                <div className="space-y-4">
                                    <div>
                                        <div className="flex justify-between text-[10px] text-slate-500 uppercase mb-2">
                                            <span>Position</span>
                                            <span className="text-purple-400">{settings.watermarkPosition.replace('-', ' ')}</span>
