                    >
                        {isProcessing ? <><Loader2 className="w-5 h-5 animate-spin" /> {progress}</> : <><Play className="w-5 h-5 fill-current" /> Batch Process ({settings.videos.length})</>}
                    </button>
                    <p className="text-[9px] text-center text-slate-500 uppercase tracking-widest font-bold">Includes Original Audio</p>
                </div>
            </div>

            {/* Preview Area */}
            <div className="flex-1 flex flex-col items-center justify-center p-8 relative overflow-hidden">
                <div className="absolute inset-0 opacity-5 pointer-events-none" style={{ backgroundImage: 'radial-gradient(#475569 1px, transparent 1px)', backgroundSize: '24px 24px' }}></div>

