                    <div className="relative w-[320px] h-[570px] bg-black rounded-[40px] overflow-hidden shadow-[0_0_80px_rgba(168,85,247,0.15)] border-[8px] border-slate-800 ring-1 ring-slate-700">
                        {activeVideo ? (
                            <video key={activeVideo.id} ref={videoRef} src={activeVideo.url} autoPlay loop muted playsInline className="absolute inset-0 w-full h-full object-cover" />
                        ) : (
                            <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-700 p-8 text-center bg-slate-900">
                                <Video className="w-16 h-16 mb-4 opacity-10" />
