import { NewsItem, ThemeColor } from "../types";

const getThemeColors = (theme: ThemeColor) => {
  switch (theme) {
    case ThemeColor.BLUE:
      return { main: '#1d4ed8', dark: '#1e3a8a' }; 
    case ThemeColor.PURPLE:
      return { main: '#7e22ce', dark: '#581c87' }; 
    case ThemeColor.RED:
    default:
      return { main: '#b91c1c', dark: '#7f1d1d' }; 
  }
};

const wrapText = (ctx: CanvasRenderingContext2D, text: string, maxWidth: number) => {
  const words = text.split(' ');
  const lines = [];
  let currentLine = words[0];

  for (let i = 1; i < words.length; i++) {
    const word = words[i];
    const width = ctx.measureText(currentLine + " " + word).width;
    if (width < maxWidth) {
      currentLine += " " + word;
    } else {
      lines.push(currentLine);
      currentLine = word;
    }
  }
  lines.push(currentLine);
  return lines;
};

const loadImageWithFallback = async (url: string): Promise<HTMLImageElement | null> => {
    const load = (src: string) => new Promise<HTMLImageElement>((resolve, reject) => {
        const img = new Image();
        img.crossOrigin = "anonymous";
        img.onload = () => resolve(img);
        img.onerror = () => reject(new Error(`Failed to load ${src}`));
        img.src = src;
    });

    try {
        return await load(url);
    } catch (e) {
        console.warn("Direct image load failed, trying proxy...", e);
        try {
            return await load(`https://corsproxy.io/?${encodeURIComponent(url)}`);
        } catch (e2) {
             console.warn("Proxy image load failed", e2);
             return null;
        }
    }
};

export const exportCompositedVideo = async (
  item: NewsItem,
  audioUrl: string | null,
  onProgress: (msg: string) => void
): Promise<string> => {
  return new Promise(async (resolve, reject) => {
    try {
      if (!item.videoUrl) throw new Error("No video URL provided");

      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      if (!ctx) throw new Error("Could not get canvas context");

      canvas.width = 720;
      canvas.height = 1280;

      const video = document.createElement('video');
      video.crossOrigin = "anonymous";
      video.src = item.videoUrl;
      video.muted = true; 
      video.playsInline = true;

      await new Promise((r, rej) => {
        video.onloadedmetadata = r;
        video.onerror = () => rej(new Error("Failed to load video metadata"));
      });

      let overlayImg: HTMLImageElement | null = null;
      if (item.overlayImage) {
        overlayImg = await loadImageWithFallback(item.overlayImage);
      }

      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
      const dest = audioCtx.createMediaStreamDestination();

      const videoAudioSource = audioCtx.createMediaElementSource(video);
      videoAudioSource.connect(dest);

      let musicSourceNode: AudioBufferSourceNode | null = null;
      if (audioUrl) {
        try {
            const response = await fetch(audioUrl);
            const arrayBuffer = await response.arrayBuffer();
            const audioBuffer = await audioCtx.decodeAudioData(arrayBuffer);

            musicSourceNode = audioCtx.createBufferSource();
            musicSourceNode.buffer = audioBuffer;
            musicSourceNode.loop = true;
            musicSourceNode.connect(dest);
            musicSourceNode.start(0);
        } catch (e) {
            console.warn("Failed to load music, proceeding with original audio only.", e);
        }
      }

      const colors = getThemeColors(item.theme);
      const sidePadding = 32;
      const bottomSafeZone = 80; 
      const anchorX = sidePadding;

      let subLayout = null;
      if (item.subheadline) {
          ctx.font = '700 32px "Oswald", "Arial", sans-serif';
          const maxSubWidth = canvas.width - (sidePadding * 2);
          const lines = wrapText(ctx, item.subheadline, maxSubWidth);
          const lineHeight = 44;
          const paddingY = 24; 
          const boxHeight = (lines.length * lineHeight) + paddingY;

          let maxLineWidth = 0;
          lines.forEach(l => {
              const w = ctx.measureText(l).width;
              if (w > maxLineWidth) maxLineWidth = w;
          });

          subLayout = {
              lines,
              lineHeight,
              boxHeight,
              boxWidth: maxLineWidth + 40, 
          };
      }

      ctx.font = '900 60px "Oswald", "Arial Black", sans-serif';
      const maxHeadWidth = canvas.width - (sidePadding * 2) - 20; 
      const headLines = wrapText(ctx, item.headline || "HEADLINE", maxHeadWidth);
      const headLineHeight = 70;
      const headPaddingY = 30;
      const headBoxHeight = (headLines.length * headLineHeight) + headPaddingY;

      let maxHeadLineWidth = 0;
      headLines.forEach(l => {
          const w = ctx.measureText(l).width;
          if (w > maxHeadLineWidth) maxHeadLineWidth = w;
      });

      const headLayout = {
          lines: headLines,
          lineHeight: headLineHeight,
          boxHeight: headBoxHeight,
          boxWidth: maxHeadLineWidth + 50, 
      };

      let currentY = canvas.height - bottomSafeZone;

      let subY = 0;
      if (subLayout) {
          subY = currentY - subLayout.boxHeight;
          currentY = subY - 10; 
      }

      const headY = currentY - headLayout.boxHeight;
      currentY = headY - 10; 

      const badgeHeight = 32;
      const badgeY = currentY - badgeHeight;
      currentY = badgeY - 20; 

      const imgHeight = 630;
      const imgWidth = canvas.width; 
      const imgY = currentY - imgHeight;

      const videoStream = canvas.captureStream(30);
      const tracks = [...videoStream.getVideoTracks()];

      const audioTrack = dest.stream.getAudioTracks()[0];
      if (audioTrack) tracks.push(audioTrack);

      const combinedStream = new MediaStream(tracks);
      const recorder = new MediaRecorder(combinedStream, {
        mimeType: 'video/webm;codecs=vp9'
      });

      const chunks: Blob[] = [];
      recorder.ondataavailable = (e) => {
        if (e.data.size > 0) chunks.push(e.data);
      };

      recorder.onstop = () => {
        if (musicSourceNode) musicSourceNode.stop();
        audioCtx.close();
        const blob = new Blob(chunks, { type: 'video/webm' });
        const url = URL.createObjectURL(blob);
        resolve(url);
      };

      recorder.start();

      try {
        await video.play();
      } catch (e) {
          console.error("Video play failed", e);
          reject(e);
          return;
      }

      const drawFrame = () => {
        if (video.paused || video.ended) {
          recorder.stop();
          return;
        }

        ctx.fillStyle = '#000';
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        const videoRatio = video.videoWidth / video.videoHeight;
        const canvasRatio = canvas.width / canvas.height;
        let drawWidth, drawHeight, startX, startY;

        if (videoRatio > canvasRatio) {
            drawHeight = canvas.height;
            drawWidth = drawHeight * videoRatio;
            startX = (canvas.width - drawWidth) / 2;
            startY = 0;
        } else {
            drawWidth = canvas.width;
            drawHeight = drawWidth / videoRatio;
            startX = 0;
            startY = (canvas.height - drawHeight) / 2;
        }

        ctx.drawImage(video, startX, startY, drawWidth, drawHeight);

        if (overlayImg && overlayImg.complete && overlayImg.naturalWidth > 0) {
            ctx.save();
            ctx.shadowColor = "rgba(0,0,0,0.5)";
            ctx.shadowBlur = 20;
            ctx.strokeStyle = "white";
            ctx.lineWidth = 12; 

            const imgRatio = overlayImg.width / overlayImg.height;
            const targetRatio = imgWidth / imgHeight;
            let sx, sy, sWidth, sHeight;

            if (imgRatio > targetRatio) {
                sHeight = overlayImg.height;
                sWidth = sHeight * targetRatio;
                sy = 0;
                sx = (overlayImg.width - sWidth) / 2;
            } else {
                sWidth = overlayImg.width;
                sHeight = sWidth / targetRatio;
                sx = 0;
                sy = (overlayImg.height - sHeight) / 2;
            }

            try {
                ctx.drawImage(overlayImg, sx, sy, sWidth, sHeight, 0, imgY, imgWidth, imgHeight);
                ctx.strokeRect(0, imgY, imgWidth, imgHeight); 
            } catch (err) {
                console.warn("Error drawing image frame", err);
            }
            ctx.restore();
        }

        ctx.save();
        ctx.translate(anchorX, badgeY);
        ctx.transform(1, 0, -0.2, 1, 0, 0); 

        ctx.fillStyle = colors.main;
        ctx.fillRect(0, 0, 220, badgeHeight);

        ctx.transform(1, 0, 0.2, 1, 0, 0); 
        ctx.fillStyle = 'white';
        ctx.font = '900 20px "Oswald", "Arial Black", sans-serif'; 
        ctx.textBaseline = 'middle';
        ctx.fillText('BREAKING NEWS', 15, badgeHeight / 2 + 2);
        ctx.restore();

        ctx.save();
        ctx.translate(anchorX, headY);
        ctx.transform(1, 0, -0.035, 1, 0, 0); 

        ctx.shadowColor = "rgba(0,0,0,0.5)";
        ctx.shadowBlur = 15;

        ctx.fillStyle = 'rgba(255, 255, 255, 0.95)';
        ctx.fillRect(0, 0, headLayout.boxWidth, headLayout.boxHeight);

        ctx.shadowBlur = 0;
        ctx.fillStyle = 'black';
        ctx.fillRect(0, 0, 15, headLayout.boxHeight);

        ctx.fillStyle = 'black';
        ctx.font = '900 60px "Oswald", "Arial Black", sans-serif';
        ctx.transform(1, 0, 0.035, 1, 0, 0); 

        headLayout.lines.forEach((line, i) => {
            const lineY = 20 + (i * headLayout.lineHeight) + 40; 
            ctx.fillText(line, 25, lineY);
        });
        ctx.restore();

        if (subLayout && item.subheadline) {
            ctx.save();
            ctx.translate(anchorX, subY);
            ctx.transform(1, 0, -0.035, 1, 0, 0); 

            ctx.shadowColor = "rgba(0,0,0,0.5)";
            ctx.shadowBlur = 10;

            ctx.fillStyle = colors.dark;
            ctx.globalAlpha = 0.9;
            ctx.fillRect(0, 0, subLayout.boxWidth, subLayout.boxHeight);

            ctx.globalAlpha = 1;
            ctx.shadowBlur = 0;
            ctx.fillStyle = 'white';
            ctx.font = '700 32px "Oswald", "Arial", sans-serif';
            ctx.transform(1, 0, 0.035, 1, 0, 0); 

            subLayout.lines.forEach((line, i) => {
                 const lineY = 15 + (i * subLayout.lineHeight) + 24;
                 ctx.fillText(line, 20, lineY);
            });
            ctx.restore();
        }

        onProgress(`Processing: ${Math.floor(video.currentTime)}s / ${Math.floor(video.duration)}s`);
        requestAnimationFrame(drawFrame);
      };

      drawFrame();

    } catch (e: any) {
      reject(e);
    }
  });
};

import React, { useState, useRef } from 'react';
import { ArrowLeft, Video, LayoutTemplate, ShieldCheck, Download, Upload, Loader2, Play, Trash2, Maximize, Move, FileVideo, CheckCircle, AlertCircle, List, Plus } from 'lucide-react';
import { FrameSettings, WatermarkPosition, FrameVideoItem } from '../types';

interface FrameEditorProps {
    onBack: () => void;
}

const FrameEditor: React.FC<FrameEditorProps> = ({ onBack }) => {
    const [settings, setSettings] = useState<FrameSettings>({
        frameImageUrl: null,
        watermarkUrl: null,
        watermarkOpacity: 0.8,
        watermarkPosition: WatermarkPosition.BOTTOM_RIGHT,
        watermarkSize: 15,
        videos: []
    });

    const [activeVideoId, setActiveVideoId] = useState<string | null>(null);
    const [isProcessing, setIsProcessing] = useState(false);
    const [progress, setProgress] = useState('');

    const videoInputRef = useRef<HTMLInputElement>(null);
    const frameInputRef = useRef<HTMLInputElement>(null);
    const watermarkInputRef = useRef<HTMLInputElement>(null);
    const videoRef = useRef<HTMLVideoElement>(null);

    const activeVideo = settings.videos.find(v => v.id === activeVideoId) || settings.videos[0];

    const handleFileUpload = (type: 'video' | 'frame' | 'watermark', e: React.ChangeEvent<HTMLInputElement>) => {
        const files = e.target.files;
        if (!files || files.length === 0) return;

        if (type === 'video') {
            const newVideos: FrameVideoItem[] = Array.from(files).map((file: File) => ({
                id: Math.random().toString(36).substr(2, 9),
                url: URL.createObjectURL(file),
                name: file.name,
                status: 'idle',
                generatedUrl: null
            }));
            setSettings(prev => ({ ...prev, videos: [...prev.videos, ...newVideos] }));
            if (!activeVideoId && newVideos.length > 0) setActiveVideoId(newVideos[0].id);
        } else {
            const file = files[0];
            const url = URL.createObjectURL(file);
            if (type === 'frame') setSettings(prev => ({ ...prev, frameImageUrl: url }));
            if (type === 'watermark') setSettings(prev => ({ ...prev, watermarkUrl: url }));
        }
        e.target.value = '';
    };

    const removeVideo = (id: string) => {
        setSettings(prev => {
            const filtered = prev.videos.filter(v => v.id !== id);
            if (activeVideoId === id) {
                setActiveVideoId(filtered.length > 0 ? filtered[0].id : null);
            }
            return { ...prev, videos: filtered };
        });
    };

    const processSingleVideo = async (videoItem: FrameVideoItem): Promise<string> => {
        return new Promise(async (resolve, reject) => {
            try {
                const canvas = document.createElement('canvas');
                const ctx = canvas.getContext('2d');
                if (!ctx) throw new Error("Could not get canvas context");

                canvas.width = 720;
                canvas.height = 1280;

                const video = document.createElement('video');
                video.src = videoItem.url;
                video.crossOrigin = 'anonymous';
                video.muted = true; // Tetap muted untuk background processing agar tidak berisik di speaker
                video.volume = 1.0;

                await new Promise((r) => video.onloadedmetadata = r);

                // Setup Audio Context
                const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
                if (audioCtx.state === 'suspended') {
                    await audioCtx.resume();
                }

                const source = audioCtx.createMediaElementSource(video);
                const dest = audioCtx.createMediaStreamDestination();
                source.connect(dest);

                let frameImg = null;
                if (settings.frameImageUrl) {
                    frameImg = new Image();
                    frameImg.src = settings.frameImageUrl;
                    await new Promise((r) => frameImg!.onload = r);
                }

                let watermarkImg = null;
                if (settings.watermarkUrl) {
                    watermarkImg = new Image();
                    watermarkImg.src = settings.watermarkUrl;
                    await new Promise((r) => watermarkImg!.onload = r);
                }

                const videoStream = canvas.captureStream(30);
                const videoTrack = videoStream.getVideoTracks()[0];
                const audioTrack = dest.stream.getAudioTracks()[0];

                const combinedStream = new MediaStream();
                combinedStream.addTrack(videoTrack);
                if (audioTrack) {
                    combinedStream.addTrack(audioTrack);
                }

                // Gunakan codec yang mendukung audio (opus)
                const recorder = new MediaRecorder(combinedStream, { 
                    mimeType: 'video/webm;codecs=vp9,opus' 
                });

                const chunks: Blob[] = [];
                recorder.ondataavailable = (e) => {
                    if (e.data.size > 0) chunks.push(e.data);
                };

                recorder.onstop = () => {
                    audioCtx.close();
                    const blob = new Blob(chunks, { type: 'video/webm' });
                    const url = URL.createObjectURL(blob);
                    resolve(url);
                };

                recorder.start();
                video.play();

                const draw = () => {
                    if (video.paused || video.ended) {
                        if (recorder.state === 'recording') recorder.stop();
                        return;
                    }

                    ctx.fillStyle = 'black';
                    ctx.fillRect(0, 0, canvas.width, canvas.height);

                    const vRatio = video.videoWidth / video.videoHeight;
                    const cRatio = canvas.width / canvas.height;
                    let dw, dh, sx, sy;
                    if (vRatio > cRatio) {
                        dh = canvas.height; dw = dh * vRatio; sx = (canvas.width - dw) / 2; sy = 0;
                    } else {
                        dw = canvas.width; dh = dw / vRatio; sx = 0; sy = (canvas.height - dh) / 2;
                    }
                    ctx.drawImage(video, sx, sy, dw, dh);

                    if (frameImg) {
                        ctx.drawImage(frameImg, 0, 0, canvas.width, canvas.height);
                    }

                    if (watermarkImg) {
                        ctx.save();
                        ctx.globalAlpha = settings.watermarkOpacity;
                        const wSize = (canvas.width * settings.watermarkSize) / 100;
                        const wAspect = watermarkImg.width / watermarkImg.height;
                        const wWidth = wSize;
                        const wHeight = wSize / wAspect;
                        const padding = 40;

                        let wx, wy;
                        switch (settings.watermarkPosition) {
                            case WatermarkPosition.TOP_LEFT: wx = padding; wy = padding; break;
                            case WatermarkPosition.TOP_RIGHT: wx = canvas.width - wWidth - padding; wy = padding; break;
                            case WatermarkPosition.BOTTOM_LEFT: wx = padding; wy = canvas.height - wHeight - padding; break;
                            case WatermarkPosition.BOTTOM_RIGHT: 
                            default: wx = canvas.width - wWidth - padding; wy = canvas.height - wHeight - padding; break;
                        }
                        ctx.drawImage(watermarkImg, wx, wy, wWidth, wHeight);
                        ctx.restore();
                    }
                    requestAnimationFrame(draw);
                };
                draw();
            } catch (err) {
                reject(err);
            }
        });
    };

    const processAllVideos = async () => {
        if (settings.videos.length === 0) return;
        setIsProcessing(true);

        const videosToProcess = settings.videos.filter(v => v.status !== 'done');

        for (let i = 0; i < videosToProcess.length; i++) {
            const video = videosToProcess[i];
            setSettings(prev => ({
                ...prev,
                videos: prev.videos.map(v => v.id === video.id ? { ...v, status: 'processing' } : v)
            }));
            setProgress(`Processing ${i + 1}/${videosToProcess.length}: ${video.name}`);

            try {
                const resultUrl = await processSingleVideo(video);
                setSettings(prev => ({
                    ...prev,
                    videos: prev.videos.map(v => v.id === video.id ? { ...v, status: 'done', generatedUrl: resultUrl } : v)
                }));
            } catch (err) {
                console.error("Batch processing error:", err);
                setSettings(prev => ({
                    ...prev,
                    videos: prev.videos.map(v => v.id === video.id ? { ...v, status: 'error', error: 'Failed' } : v)
                }));
