                    </button>
                    <p className="text-[9px] text-center text-slate-500 uppercase tracking-widest font-bold">Audio Track Preserved</p>
                </div>
            </div>

            <div className="flex-1 flex flex-col items-center justify-center p-8 relative overflow-hidden">
