                                settings.watermarkPosition === WatermarkPosition.TOP_LEFT ? 'top-0 left-0' :
                                settings.watermarkPosition === WatermarkPosition.TOP_RIGHT ? 'top-0 right-0' :
                                settings.watermarkPosition === WatermarkPosition.BOTTOM_LEFT ? 'bottom-0 left-0' : 'bottom-0 right-0'
                            }`}>
                                <img 
                                    src={settings.watermarkUrl} 
                                    style={{ 
                                        width: `${settings.watermarkSize * 3}px`, 
                                        opacity: settings.watermarkOpacity 
                                    }} 
                                    className="object-contain" 
                                    alt="Watermark" 
                                />
                            </div>
                        )}
                    </div>

                    {activeVideo?.generatedUrl && (
                        <button 
                            onClick={() => {
                                const a = document.createElement('a');
                                a.href = activeVideo.generatedUrl!;
                                a.download = activeVideo.name;
                                a.click();
                            }}
                            className="bg-emerald-600 hover:bg-emerald-500 text-white px-8 py-3 rounded-xl font-bold flex items-center gap-2 shadow-lg shadow-emerald-900/20 transition-all active:scale-95 animate-in fade-in slide-in-from-bottom-4"
                        >
                            <Download className="w-5 h-5" /> Download Branded Clip
                        </button>
                    )}
                </div>
            </div>
        </div>
    );
};

