}

const AffiliateMaker: React.FC<AffiliateMakerProps> = ({ onBack }) => {
  const [item, setItem] = useState<AffiliateItem>({
    id: '1',
    productImage: null,
    productName: 'Sample Product Name',
    originalPrice: '250.000',
    discountPrice: '149.000',
    ctaText: 'Cek di Bio!',
    ratio: '1:1',
    theme: 'modern'
  });

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const url = URL.createObjectURL(file);
      setItem(prev => ({ ...prev, productImage: url }));
    }
  };

  const drawCanvas = async () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Set dimensions based on ratio
    let width = 1080;
    let height = 1080;
    if (item.ratio === '4:5') height = 1350;
    if (item.ratio === '9:16') height = 1920;

    canvas.width = width;
    canvas.height = height;

    // Background
    ctx.fillStyle = '#f8fafc';
    ctx.fillRect(0, 0, width, height);

    if (item.productImage) {
      const img = new Image();
      img.src = item.productImage;
      await new Promise((resolve) => { img.onload = resolve; });

      // Draw blurred background
      ctx.save();
      ctx.filter = 'blur(50px) brightness(0.9)';
      const bgScale = Math.max(width / img.width, height / img.height);
      const bgW = img.width * bgScale;
      const bgH = img.height * bgScale;
      ctx.drawImage(img, (width - bgW) / 2, (height - bgH) / 2, bgW, bgH);
      ctx.restore();

      // Draw Main Image
      const padding = width * 0.1;
      const displayW = width - (padding * 2);
      const displayH = (displayW / img.width) * img.height;
      const maxH = height * 0.6;

      let drawW = displayW;
      let drawH = displayH;

      if (drawH > maxH) {
        drawH = maxH;
        drawW = (drawH / img.height) * img.width;
      }

      const drawX = (width - drawW) / 2;
      const drawY = height * 0.15;

      ctx.save();
      ctx.shadowColor = 'rgba(0,0,0,0.3)';
      ctx.shadowBlur = 40;
      ctx.shadowOffsetY = 20;

      // Rounded rect for image
      const radius = 40;
      ctx.beginPath();
      ctx.moveTo(drawX + radius, drawY);
      ctx.lineTo(drawX + drawW - radius, drawY);
      ctx.quadraticCurveTo(drawX + drawW, drawY, drawX + drawW, drawY + radius);
      ctx.lineTo(drawX + drawW, drawY + drawH - radius);
      ctx.quadraticCurveTo(drawX + drawW, drawY + drawH, drawX + drawW - radius, drawY + drawH);
      ctx.lineTo(drawX + radius, drawY + drawH);
      ctx.quadraticCurveTo(drawX, drawY + drawH, drawX, drawY + drawH - radius);
      ctx.lineTo(drawX, drawY + radius);
      ctx.quadraticCurveTo(drawX, drawY, drawX + radius, drawY);
      ctx.closePath();
      ctx.clip();

      ctx.drawImage(img, drawX, drawY, drawW, drawH);
      ctx.restore();

      // Discount Badge
      if (item.originalPrice && item.discountPrice) {
          ctx.save();
          ctx.translate(drawX + 50, drawY + 50);
          ctx.rotate(-15 * Math.PI / 180);
          ctx.fillStyle = '#ef4444';
          ctx.beginPath();
          ctx.roundRect(-60, -30, 160, 60, 12);
          ctx.fill();
          ctx.fillStyle = 'white';
          ctx.font = 'bold 30px Inter';
          ctx.textAlign = 'center';
          ctx.fillText('BEST DEAL!', 20, 10);
          ctx.restore();
      }
    }

    // Product Info Area (Lower Part)
    const contentY = height * 0.78;

    // Product Name
    ctx.fillStyle = 'white';
    ctx.font = 'bold 50px Inter';
    ctx.textAlign = 'center';
    ctx.fillText(item.productName.toUpperCase(), width / 2, contentY);

    // Prices
    const priceY = contentY + 100;

    // Original Price (Strikethrough)
    ctx.font = '40px Inter';
    ctx.fillStyle = 'rgba(255,255,255,0.6)';
    const origW = ctx.measureText(`Rp ${item.originalPrice}`).width;
    ctx.fillText(`Rp ${item.originalPrice}`, (width / 2) - 100, priceY);
    ctx.fillRect((width / 2) - 100 - (origW / 2), priceY - 15, origW, 4);

    // Discount Price
    ctx.font = 'bold 80px Inter';
    ctx.fillStyle = '#10b981';
    ctx.fillText(`Rp ${item.discountPrice}`, (width / 2) + 120, priceY + 20);

    // CTA Button
    const btnW = 500;
    const btnH = 100;
    const btnX = (width - btnW) / 2;
    const btnY = priceY + 120;

    ctx.fillStyle = '#10b981';
    ctx.beginPath();
    ctx.roundRect(btnX, btnY, btnW, btnH, 50);
    ctx.fill();

    ctx.fillStyle = 'white';
    ctx.font = 'bold 40px Inter';
    ctx.textAlign = 'center';
    ctx.fillText(item.ctaText, width / 2, btnY + 65);
  };

  useEffect(() => {
    drawCanvas();
  }, [item]);

  const handleDownload = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const link = document.createElement('a');
    link.download = `affiliate-${item.productName.toLowerCase().replace(/\s+/g, '-')}.png`;
    link.href = canvas.toDataURL('image/png');
    link.click();
  };

  return (
    <div className="flex flex-col lg:flex-row h-screen w-full overflow-hidden bg-slate-950 text-white">
      {/* Sidebar */}
      <div className="w-full lg:w-96 bg-slate-900 border-r border-slate-800 flex flex-col h-auto lg:h-full shadow-2xl z-20 overflow-hidden">
        <div className="p-6 border-b border-slate-800 flex items-center gap-3 shrink-0">
          <button onClick={onBack} className="p-2 -ml-2 hover:bg-slate-800 rounded-full text-slate-400 hover:text-white transition-colors">
            <ArrowLeft className="w-5 h-5" />
          </button>
          <h1 className="text-xl font-bold bg-gradient-to-r from-emerald-400 to-teal-500 bg-clip-text text-transparent">Affiliate Maker</h1>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-8 scrollbar-thin">
          <div className="space-y-4">
            <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2">
              <Layout className="w-3 h-3" /> Canvas Ratio
            </label>
            <div className="grid grid-cols-3 gap-2">
              {(['1:1', '4:5', '9:16'] as AffiliateRatio[]).map(r => (
                <button
                  key={r}
                  onClick={() => setItem(prev => ({ ...prev, ratio: r }))}
                  className={`py-2 rounded-lg border text-xs font-bold transition-all ${item.ratio === r ? 'bg-emerald-600 border-emerald-500 text-white' : 'bg-slate-800 border-slate-700 text-slate-400 hover:border-slate-600'}`}
                >
                  {r}
                </button>
              ))}
            </div>
          </div>

          <div className="space-y-4">
            <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2">
              <Upload className="w-3 h-3" /> Product Image
            </label>
            <input type="file" accept="image/*" ref={fileInputRef} className="hidden" onChange={handleFileUpload} />
            <button 
                onClick={() => fileInputRef.current?.click()}
                className="w-full py-3 px-4 bg-slate-800 border border-slate-700 rounded-xl hover:border-emerald-500 transition-all flex items-center justify-center gap-2 text-sm"
            >
              <Upload className="w-4 h-4" /> {item.productImage ? 'Change Image' : 'Upload Image'}
            </button>
          </div>

          <div className="space-y-4 pt-4 border-t border-slate-800">
            <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2">
              <Tag className="w-3 h-3" /> Product Details
            </label>
            <div className="space-y-3">
              <input 
                type="text" 
                placeholder="Product Name"
                className="w-full bg-slate-950 border border-slate-700 rounded-lg px-4 py-2 text-sm focus:ring-1 focus:ring-emerald-500 outline-none"
                value={item.productName}
                onChange={(e) => setItem(prev => ({ ...prev, productName: e.target.value }))}
              />
              <div className="grid grid-cols-2 gap-3">
                <input 
                  type="text" 
                  placeholder="Price (Normal)"
                  className="w-full bg-slate-950 border border-slate-700 rounded-lg px-4 py-2 text-sm focus:ring-1 focus:ring-emerald-500 outline-none"
                  value={item.originalPrice}
                  onChange={(e) => setItem(prev => ({ ...prev, originalPrice: e.target.value }))}
                />
                <input 
                  type="text" 
                  placeholder="Price (Promo)"
                  className="w-full bg-slate-950 border border-slate-700 rounded-lg px-4 py-2 text-sm focus:ring-1 focus:ring-emerald-500 outline-none text-emerald-400 font-bold"
                  value={item.discountPrice}
                  onChange={(e) => setItem(prev => ({ ...prev, discountPrice: e.target.value }))}
                />
              </div>
              <input 
                type="text" 
                placeholder="Call to Action (e.g. Cek di Bio!)"
                className="w-full bg-slate-950 border border-slate-700 rounded-lg px-4 py-2 text-sm focus:ring-1 focus:ring-emerald-500 outline-none"
                value={item.ctaText}
                onChange={(e) => setItem(prev => ({ ...prev, ctaText: e.target.value }))}
              />
            </div>
          </div>
        </div>

        <div className="p-6 border-t border-slate-800 bg-slate-900/80 backdrop-blur-md">
            <button 
                onClick={handleDownload}
                className="w-full py-4 bg-emerald-600 hover:bg-emerald-500 text-white rounded-xl font-bold flex items-center justify-center gap-2 transition-all shadow-lg shadow-emerald-900/20 active:scale-95"
            >
                <Download className="w-5 h-5" /> Download Design
            </button>
        </div>
      </div>

      {/* Preview Area */}
      <div className="flex-1 flex flex-col items-center justify-center p-8 relative overflow-hidden">
        <div className="absolute inset-0 opacity-5 pointer-events-none" style={{ backgroundImage: 'radial-gradient(#475569 1px, transparent 1px)', backgroundSize: '24px 24px' }}></div>

        <div className="relative z-10 flex flex-col items-center gap-6">
            <div className="flex items-center gap-3 text-slate-500 text-xs font-bold uppercase tracking-widest bg-slate-900/50 px-4 py-2 rounded-full border border-slate-800">
                <Smartphone className="w-3 h-3" /> Realistic Preview
            </div>

            {/* Device Mockup */}
            <div 
                className={`relative bg-black rounded-[40px] overflow-hidden shadow-[0_0_80px_rgba(16,185,129,0.15)] border-[8px] border-slate-800 ring-1 ring-slate-700 transition-all duration-500`}
                style={{
                  width: item.ratio === '1:1' ? '400px' : item.ratio === '4:5' ? '400px' : '320px',
                  height: item.ratio === '1:1' ? '400px' : item.ratio === '4:5' ? '500px' : '570px'
                }}
            >
                <canvas 
                    ref={canvasRef} 
                    className="w-full h-full object-contain"
                />
            </div>

            <div className="flex items-center gap-6 mt-4">
                <div className="flex flex-col items-center gap-1">
                    <span className="text-[10px] text-slate-500 font-bold uppercase tracking-tighter">Theme</span>
                    <div className="flex gap-2">
                        <button className="w-6 h-6 rounded-full bg-emerald-500 border-2 border-white"></button>
                        <button className="w-6 h-6 rounded-full bg-blue-500"></button>
