import { GoogleGenAI } from "@google/genai";

interface AffiliateMakerProps {
  onBack: () => void;
}

const AffiliateMaker: React.FC<AffiliateMakerProps> = ({ onBack }) => {
  const [item, setItem] = useState<AffiliateItem>({
    id: '1',
    productImage: null,
    productName: 'Sample Product Name',
    originalPrice: '250.000',
    discountPrice: '149.000',
    ctaText: 'Cek di Bio!',
    ratio: '1:1',
    theme: 'modern'
  });

  const [isAiLoading, setIsAiLoading] = useState(false);
  const [aiPrompt, setAiPrompt] = useState('');

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const url = URL.createObjectURL(file);
      setItem(prev => ({ ...prev, productImage: url }));
    }
  };

  const fileToBase64 = (url: string): Promise<string> => {
    return new Promise((resolve, reject) => {
      fetch(url)
        .then(response => response.blob())
        .then(blob => {
          const reader = new FileReader();
          reader.onloadend = () => {
            const base64String = (reader.result as string).split(',')[1];
            resolve(base64String);
          };
          reader.onerror = reject;
          reader.readAsDataURL(blob);
        })
        .catch(reject);
    });
  };

  const handleAiEnhance = async (presetPrompt?: string) => {
    if (!item.productImage) {
      alert("Silakan unggah foto produk terlebih dahulu!");
      return;
    }

    setIsAiLoading(true);
    const finalPrompt = presetPrompt || aiPrompt || "Enhance this product photo with a high-quality professional studio background and aesthetic lighting.";

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const base64Data = await fileToBase64(item.productImage);

      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [
            {
              inlineData: {
                data: base64Data,
                mimeType: 'image/png',
              },
            },
            {
              text: `Please edit this product image. Instructions: ${finalPrompt}. Maintain the core appearance of the product but place it in a very creative, high-end environment. Make it look like a professional advertising shot.`,
            },
          ],
        },
        config: {
          imageConfig: {
            aspectRatio: item.ratio
          }
        }
      });

      let newImageUrl = '';
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          newImageUrl = `data:image/png;base64,${part.inlineData.data}`;
          break;
        }
      }

      if (newImageUrl) {
        setItem(prev => ({ ...prev, productImage: newImageUrl }));
      } else {
        throw new Error("AI tidak mengembalikan gambar.");
      }
    } catch (error) {
      console.error("AI Enhance Error:", error);
      alert("Gagal memproses gambar dengan AI. Pastikan API Key valid.");
    } finally {
      setIsAiLoading(false);
    }
  };

  const drawCanvas = async () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let width = 1080;
    let height = 1080;
    if (item.ratio === '4:5') height = 1350;
    if (item.ratio === '9:16') height = 1920;

    canvas.width = width;
    canvas.height = height;

    ctx.fillStyle = '#111';
    ctx.fillRect(0, 0, width, height);

    if (item.productImage) {
      const img = new Image();
      img.src = item.productImage;
      await new Promise((resolve) => { img.onload = resolve; });

      const imgRatio = img.width / img.height;
      const canvasRatio = width / height;
      let drawW, drawH, drawX, drawY;

      if (imgRatio > canvasRatio) {
        drawH = height;
        drawW = drawH * imgRatio;
        drawX = (width - drawW) / 2;
        drawY = 0;
      } else {
        drawW = width;
        drawH = drawW / imgRatio;
        drawX = 0;
        drawY = (height - drawH) / 2;
      }

      ctx.drawImage(img, drawX, drawY, drawW, drawH);
    }

    // Overlay Elements
    const contentY = height * 0.8;

    // Gradient shadow for text
    const grad = ctx.createLinearGradient(0, height * 0.6, 0, height);
    grad.addColorStop(0, 'transparent');
    grad.addColorStop(1, 'rgba(0,0,0,0.8)');
    ctx.fillStyle = grad;
    ctx.fillRect(0, height * 0.6, width, height * 0.4);

    // Product Name
    ctx.fillStyle = 'white';
    ctx.font = 'bold 44px Inter';
    ctx.textAlign = 'center';
    ctx.shadowColor = 'rgba(0,0,0,0.5)';
    ctx.shadowBlur = 10;
    ctx.fillText(item.productName.toUpperCase(), width / 2, contentY);

    // Price Box
    const priceY = contentY + 80;
    ctx.font = 'bold 70px Inter';
    ctx.fillStyle = '#10b981';
    ctx.fillText(`Rp ${item.discountPrice}`, width / 2, priceY);

    // CTA Button
    const btnW = 450;
    const btnH = 90;
    const btnX = (width - btnW) / 2;
    const btnY = priceY + 60;

    ctx.shadowBlur = 0;
    ctx.fillStyle = '#10b981';
    ctx.beginPath();
    ctx.roundRect(btnX, btnY, btnW, btnH, 45);
    ctx.fill();

    ctx.fillStyle = 'white';
    ctx.font = 'bold 36px Inter';
    ctx.fillText(item.ctaText, width / 2, btnY + 58);
  };

  useEffect(() => {
    drawCanvas();
  }, [item]);

  const handleDownload = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const link = document.createElement('a');
    link.download = `affiliate-${item.productName.toLowerCase().replace(/\s+/g, '-')}.png`;
    link.href = canvas.toDataURL('image/png');
    link.click();
  };

  return (
    <div className="flex flex-col lg:flex-row h-screen w-full overflow-hidden bg-slate-950 text-white">
      <div className="w-full lg:w-96 bg-slate-900 border-r border-slate-800 flex flex-col h-auto lg:h-full shadow-2xl z-20 overflow-hidden">
        <div className="p-6 border-b border-slate-800 flex items-center gap-3 shrink-0">
          <button onClick={onBack} className="p-2 -ml-2 hover:bg-slate-800 rounded-full text-slate-400 hover:text-white transition-colors">
            <ArrowLeft className="w-5 h-5" />
          </button>
          <h1 className="text-xl font-bold bg-gradient-to-r from-emerald-400 to-teal-500 bg-clip-text text-transparent">Affiliate AI</h1>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-6 scrollbar-thin">
          <div className="space-y-3">
            <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2">
              <Upload className="w-3 h-3" /> Product Photo
            </label>
            <input type="file" accept="image/*" ref={fileInputRef} className="hidden" onChange={handleFileUpload} />
            <button 
                onClick={() => fileInputRef.current?.click()}
                className="w-full py-3 px-4 bg-slate-800 border border-slate-700 rounded-xl hover:border-emerald-500 transition-all flex items-center justify-center gap-2 text-sm"
            >
              <ImageIcon className="w-4 h-4" /> {item.productImage ? 'Ganti Foto' : 'Unggah Foto'}
            </button>
          </div>

          <div className="p-4 bg-slate-950/50 rounded-2xl border border-emerald-500/20 space-y-4">
             <label className="text-[10px] font-bold text-emerald-500 uppercase tracking-widest flex items-center gap-2">
              <Sparkles className="w-3 h-3" /> AI Enhancement
            </label>

            <div className="grid grid-cols-2 gap-2">
