interface AffiliateMakerProps {
  onBack: () => void;
}

const AffiliateMaker: React.FC<AffiliateMakerProps> = ({ onBack }) => {
  const [item, setItem] = useState<Partial<AffiliateItem>>({
    id: '1',
    productImage: null,
    ratio: '9:16'
  });

  const [isAiLoading, setIsAiLoading] = useState(false);
  const [aiPrompt, setAiPrompt] = useState('');

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const url = URL.createObjectURL(file);
      setItem(prev => ({ ...prev, productImage: url }));
    }
  };

  const fileToBase64 = (url: string): Promise<string> => {
    return new Promise((resolve, reject) => {
      fetch(url)
        .then(response => response.blob())
        .then(blob => {
          const reader = new FileReader();
          reader.onloadend = () => {
            const base64String = (reader.result as string).split(',')[1];
            resolve(base64String);
          };
          reader.onerror = reject;
          reader.readAsDataURL(blob);
        })
        .catch(reject);
    });
  };

  const handleAiEnhance = async (presetPrompt?: string) => {
    if (!item.productImage) {
      alert("Silakan unggah foto produk terlebih dahulu!");
      return;
    }

    setIsAiLoading(true);
    const finalPrompt = presetPrompt || aiPrompt || "Professional high-end product photography in a creative studio setting with aesthetic lighting.";

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const base64Data = await fileToBase64(item.productImage);

      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [
            {
              inlineData: {
                data: base64Data,
                mimeType: 'image/png',
              },
