              text: `Please edit this product image. Instructions: ${finalPrompt}. Maintain the core appearance and scale of the product but place it in a very creative, high-end environment. The output MUST be in 9:16 vertical aspect ratio. Make it look like a stunning professional advertising shot for social media stories.`,
            },
          ],
        },
        config: {
          imageConfig: {
            aspectRatio: '9:16'
          }
        }
      });

      let newImageUrl = '';
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          newImageUrl = `data:image/png;base64,${part.inlineData.data}`;
          break;
        }
      }

      if (newImageUrl) {
        setItem(prev => ({ ...prev, productImage: newImageUrl }));
      } else {
        throw new Error("AI tidak mengembalikan gambar.");
      }
    } catch (error: any) {
      console.error("AI Enhance Error:", error);
      alert("Gagal memproses gambar dengan AI. Pastikan API Key valid dan coba lagi.");
    } finally {
      setIsAiLoading(false);
    }
  };

  const drawCanvas = async () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Fixed 9:16 Dimensions for high quality
    const width = 1080;
    const height = 1920;

    canvas.width = width;
    canvas.height = height;

    ctx.fillStyle = '#0a0a0a';
    ctx.fillRect(0, 0, width, height);

    if (item.productImage) {
      const img = new Image();
      img.src = item.productImage;
      await new Promise((resolve) => { img.onload = resolve; });

      const imgRatio = img.width / img.height;
      const canvasRatio = width / height;
      let drawW, drawH, drawX, drawY;

      if (imgRatio > canvasRatio) {
        // Image is wider than 9:16, cover it
        drawH = height;
        drawW = drawH * imgRatio;
        drawX = (width - drawW) / 2;
        drawY = 0;
      } else {
        // Image is taller than 9:16, cover it
        drawW = width;
        drawH = drawW / imgRatio;
        drawX = 0;
        drawY = (height - drawH) / 2;
      }

      ctx.drawImage(img, drawX, drawY, drawW, drawH);
    } else {
        // Placeholder text if no image
        ctx.fillStyle = '#334155';
        ctx.font = 'bold 40px Inter';
        ctx.textAlign = 'center';
        ctx.fillText('UPLOAD PRODUCT PHOTO', width / 2, height / 2);
    }
  };

