                    disabled={isAiLoading}
                    onClick={() => handleAiEnhance("Professional female model holding this product in a luxury lifestyle indoor setting, high-end boutique background, soft cinematic lighting.")}
                    className="flex flex-col items-center gap-2 p-3 bg-slate-800 hover:bg-emerald-900/40 rounded-xl border border-slate-700 transition-all text-[10px] font-bold text-slate-300 group"
                >
                    <User className="w-5 h-5 text-pink-400 group-hover:scale-110 transition-transform" /> Female Model
                </button>
                <button 
                    disabled={isAiLoading}
                    onClick={() => handleAiEnhance("Professional male model using or holding this product in a modern industrial loft setting, sharp focus, aesthetic professional lighting.")}
                    className="flex flex-col items-center gap-2 p-3 bg-slate-800 hover:bg-emerald-900/40 rounded-xl border border-slate-700 transition-all text-[10px] font-bold text-slate-300 group"
