import React, { useState, useRef, useEffect } from 'react';
import { ArrowLeft, Upload, Download, Smartphone, RefreshCw, Sparkles, User, UserCheck, Image as ImageIcon, Loader2, Wand2, Check } from 'lucide-react';
import { AffiliateItem } from '../types';
import { GoogleGenAI } from "@google/genai";

interface AffiliateMakerProps {
  onBack: () => void;
}

const AffiliateMaker: React.FC<AffiliateMakerProps> = ({ onBack }) => {
  const [sourceImage, setSourceImage] = useState<string | null>(null);
  const [generatedImages, setGeneratedImages] = useState<string[]>([]);
  const [selectedIndex, setSelectedIndex] = useState<number>(0);
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [aiPrompt, setAiPrompt] = useState('');

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const url = URL.createObjectURL(file);
      setSourceImage(url);
      setGeneratedImages([]); // Reset results on new upload
    }
  };

  const fileToBase64 = (url: string): Promise<string> => {
    return new Promise((resolve, reject) => {
      fetch(url)
        .then(response => response.blob())
        .then(blob => {
          const reader = new FileReader();
          reader.onloadend = () => {
            const base64String = (reader.result as string).split(',')[1];
            resolve(base64String);
          };
          reader.onerror = reject;
          reader.readAsDataURL(blob);
        })
        .catch(reject);
    });
  };

  const generateSingleVariation = async (ai: any, base64Data: string, prompt: string, seedSuffix: string) => {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            inlineData: {
              data: base64Data,
              mimeType: 'image/png',
            },
          },
          {
            text: `Professional high-end 9:16 vertical product advertisement. Scene: ${prompt}. Variation type: ${seedSuffix}. Keep the product clear and prominent. High resolution, professional lighting.`,
          },
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: '9:16'
        }
      }
    });

    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return null;
  };

  const handleAiEnhance = async (presetPrompt?: string) => {
    if (!sourceImage) {
      alert("Silakan unggah foto produk terlebih dahulu!");
      return;
    }

    setIsAiLoading(true);
    const basePrompt = presetPrompt || aiPrompt || "Professional high-end product photography in a creative studio setting.";

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const base64Data = await fileToBase64(sourceImage);

      // Define 3 variations of prompts to ensure diversity in results
      const variations = [
        `${basePrompt} - version A, cinematic lighting`,
        `${basePrompt} - version B, clean minimalist luxury style`,
        `${basePrompt} - version C, artistic and vibrant atmosphere`
      ];

      // Execute generations in parallel
      const resultPromises = variations.map((p, idx) => generateSingleVariation(ai, base64Data, p, `var_${idx}`));
      const results = await Promise.all(resultPromises);

      const filteredResults = results.filter((img): img is string => img !== null);

      if (filteredResults.length > 0) {
        setGeneratedImages(filteredResults);
        setSelectedIndex(0);
      } else {
        throw new Error("AI tidak mengembalikan gambar.");
      }
    } catch (error: any) {
      console.error("AI Enhance Error:", error);
      alert("Gagal memproses gambar dengan AI. Pastikan API Key valid.");
    } finally {
      setIsAiLoading(false);
    }
  };

  const drawCanvas = async () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const width = 1080;
    const height = 1920;
    canvas.width = width;
    canvas.height = height;

    ctx.fillStyle = '#0a0a0a';
    ctx.fillRect(0, 0, width, height);

    const displayImage = generatedImages.length > 0 ? generatedImages[selectedIndex] : sourceImage;

    if (displayImage) {
      const img = new Image();
      img.src = displayImage;
      await new Promise((resolve) => { img.onload = resolve; });

      const imgRatio = img.width / img.height;
