  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const url = URL.createObjectURL(file);
      setSourceImage(url);
      setGeneratedImages([]); // Reset results on new upload
    }
  };

  const fileToBase64 = (url: string): Promise<string> => {
    return new Promise((resolve, reject) => {
      fetch(url)
        .then(response => response.blob())
        .then(blob => {
          const reader = new FileReader();
          reader.onloadend = () => {
            const base64String = (reader.result as string).split(',')[1];
            resolve(base64String);
          };
          reader.onerror = reject;
          reader.readAsDataURL(blob);
        })
        .catch(reject);
    });
  };

  const generateSingleVariation = async (ai: any, base64Data: string, sceneDescription: string) => {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            inlineData: {
              data: base64Data,
              mimeType: 'image/png',
            },
          },
          {
            text: `High-fidelity product advertisement in 9:16 vertical aspect ratio. 
            CRITICAL INSTRUCTION: DO NOT change the appearance, brand, shape, or details of the product provided in the image. 
            Keep the product EXACTLY as shown in the original image.

            TASK: Re-render the image by placing this exact product into a new scene: ${sceneDescription}. 
            Make it look like a professional professional studio photoshoot. Ensure the lighting on the product matches the new environment.`,
          },
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: '9:16'
        }
      }
    });

    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return null;
