    const basePrompt = presetPrompt || aiPrompt || "Professional high-end product photography in a creative studio setting.";

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const base64Data = await fileToBase64(sourceImage);

      // Define 3 variations with strict preservation rules
      const variations = [
        `High-end lifestyle scene with a professional model interactively showing the product. Professional soft studio lighting.`,
        `Modern minimalist home interior background with a person holding or using the product. Natural window lighting.`,
        `Luxury artistic studio set with abstract geometric shapes, high contrast lighting, and premium textures surrounding the product.`
      ];

