            <button disabled={isAiLoading || isVideoLoading || !sourceImage} onClick={() => handleAiEnhance()} className="w-full py-3 bg-emerald-600 hover:bg-emerald-500 rounded-xl text-sm font-bold flex items-center justify-center gap-2 shadow-lg shadow-emerald-900/20 transition-all active:scale-95">
                {isAiLoading ? <Loader2 className="w-4 h-4 animate-spin" /> : <Sparkles className="w-4 h-4" />}
                Generate 3 Options
            </button>
          </div>

          {generatedImages.length > 0 && (
            <div className="p-5 bg-blue-900/10 rounded-2xl border border-blue-500/20 space-y-4 animate-in fade-in zoom-in duration-300">
               <label className="text-[10px] font-bold text-blue-400 uppercase tracking-widest flex items-center gap-2">
                <Video className="w-3 h-3" /> Video Ads (Veo 3.1)
              </label>
              <button 
                disabled={isVideoLoading || isAiLoading} 
                onClick={handleGenerateVideo}
                className="w-full py-4 bg-blue-600 hover:bg-blue-500 rounded-xl text-xs font-black flex items-center justify-center gap-2 shadow-lg shadow-blue-900/40 transition-all active:scale-95"
              >
