                            <button onClick={() => frameInputRef.current?.click()} className="w-full py-3 px-4 bg-slate-800 border border-slate-700 rounded-xl hover:border-purple-500 transition-all flex items-center justify-center gap-2 text-sm">
                                <Upload className="w-4 h-4" /> {settings.frameImageUrl ? 'Change Frame' : 'Upload Frame'}
                            </button>
                        </div>

                        <div>
                            <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2 mb-3">
                                <ShieldCheck className="w-3 h-3" /> Watermark Logo
                            </label>
                            <input type="file" accept="image/*" ref={watermarkInputRef} className="hidden" onChange={(e) => handleFileUpload('watermark', e)} />
                            <button onClick={() => watermarkInputRef.current?.click()} className="w-full py-3 px-4 bg-slate-800 border border-slate-700 rounded-xl hover:border-purple-500 transition-all flex items-center justify-center gap-2 text-sm">
                                <ShieldCheck className="w-4 h-4" /> {settings.watermarkUrl ? 'Change Watermark' : 'Upload Watermark'}
                            </button>
                        </div>

                        {settings.watermarkUrl && (
                            <div className="space-y-5 animate-in fade-in slide-in-from-top-4 duration-300 border-t border-slate-800 pt-6">
                                <h3 className="text-xs font-bold text-slate-400 flex items-center gap-2"><Move className="w-3 h-3" /> Brand Config</h3>
                                <div className="space-y-4">
                                    <div>
                                        <div className="flex justify-between text-[10px] text-slate-500 uppercase mb-2">
                                            <span>Position</span>
                                            <span className="text-purple-400">{settings.watermarkPosition.replace('-', ' ')}</span>
                                        </div>
                                        <div className="grid grid-cols-2 gap-2">
                                            {Object.values(WatermarkPosition).map(pos => (
                                                <button 
                                                    key={pos}
                                                    onClick={() => setSettings(prev => ({ ...prev, watermarkPosition: pos }))}
                                                    className={`py-2 text-[10px] font-bold rounded-lg border transition-all ${settings.watermarkPosition === pos ? 'bg-purple-600 border-purple-500 text-white shadow-lg' : 'bg-slate-800 border-slate-700 text-slate-400 hover:border-slate-600'}`}
                                                >
                                                    {pos.toUpperCase().replace('_', ' ')}
                                                </button>
                                            ))}
                                        </div>
                                    </div>
                                    <div>
                                        <div className="flex justify-between text-[10px] text-slate-500 uppercase mb-2">
                                            <span>Scale</span>
                                            <span className="text-purple-400">{settings.watermarkSize}%</span>
                                        </div>
                                        <input 
                                            type="range" min="5" max="50" step="1"
                                            value={settings.watermarkSize}
                                            onChange={(e) => setSettings(prev => ({ ...prev, watermarkSize: Number(e.target.value) }))}
                                            className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-purple-500"
                                        />
                                    </div>
                                    <div>
                                        <div className="flex justify-between text-[10px] text-slate-500 uppercase mb-2">
                                            <span>Transparency</span>
                                            <span className="text-purple-400">{Math.round(settings.watermarkOpacity * 100)}%</span>
                                        </div>
                                        <input 
                                            type="range" min="0" max="1" step="0.05"
                                            value={settings.watermarkOpacity}
                                            onChange={(e) => setSettings(prev => ({ ...prev, watermarkOpacity: Number(e.target.value) }))}
                                            className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-purple-500"
                                        />
