            <div className="flex-1 flex flex-col items-center justify-center p-8 relative overflow-hidden">
                <div className="absolute inset-0 opacity-5 pointer-events-none" style={{ backgroundImage: 'radial-gradient(#475569 1px, transparent 1px)', backgroundSize: '24px 24px' }}></div>

                <div className="relative z-10 flex flex-col items-center gap-6">
                    <div className="flex items-center gap-3 text-slate-500 text-xs font-bold uppercase tracking-widest bg-slate-900/50 px-4 py-2 rounded-full border border-slate-800">
                        <Maximize className="w-3 h-3" /> {activeVideo ? `Preview: ${activeVideo.name}` : 'Branding Preview'}
                    </div>

                    <div className="relative w-[320px] h-[570px] bg-black rounded-[40px] overflow-hidden shadow-[0_0_80px_rgba(168,85,247,0.15)] border-[8px] border-slate-800 ring-1 ring-slate-700 group/preview">
