                                    <button 
                                        onClick={togglePlay}
                                        className="p-2 hover:bg-slate-800 rounded-full text-white transition-colors"
                                    >
                                        {isPreviewPaused ? <Play className="w-4 h-4 fill-current" /> : <Pause className="w-4 h-4 fill-current" />}
                                    </button>

                                    <div className="flex items-center gap-2 flex-1">
                                        <button 
                                            onClick={() => setIsPreviewMuted(!isPreviewMuted)}
                                            className="p-2 hover:bg-slate-800 rounded-full text-white transition-colors"
                                        >
                                            {isPreviewMuted || previewVolume === 0 ? <VolumeX className="w-4 h-4" /> : <Volume2 className="w-4 h-4" />}
                                        </button>
                                        <input 
                                            type="range" min="0" max="1" step="0.01"
                                            value={previewVolume}
                                            onChange={(e) => {
                                                setPreviewVolume(Number(e.target.value));
                                                if (Number(e.target.value) > 0) setIsPreviewMuted(false);
                                            }}
                                            className="flex-1 h-1 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-purple-500"
                                        />
                                    </div>
                                </div>
                            </div>
                        )}

                        {settings.frameImageUrl && (
                            <img src={settings.frameImageUrl} className="absolute inset-0 w-full h-full object-cover pointer-events-none z-10" alt="Frame" />
                        )}

                        {settings.watermarkUrl && (
                            <div className={`absolute p-5 pointer-events-none flex transition-all duration-300 z-20 ${
                                settings.watermarkPosition === WatermarkPosition.TOP_LEFT ? 'top-0 left-0' :
                                settings.watermarkPosition === WatermarkPosition.TOP_RIGHT ? 'top-0 right-0' :
                                settings.watermarkPosition === WatermarkPosition.BOTTOM_LEFT ? 'bottom-0 left-0' : 'bottom-0 right-0'
                            }`}>
                                <img 
                                    src={settings.watermarkUrl} 
                                    style={{ 
                                        width: `${settings.watermarkSize * 3}px`, 
                                        opacity: settings.watermarkOpacity 
                                    }} 
                                    className="object-contain" 
                                    alt="Watermark" 
                                />
                            </div>
                        )}
                    </div>

                    {activeVideo?.generatedUrl && (
                        <button 
                            onClick={() => {
                                const a = document.createElement('a');
                                a.href = activeVideo.generatedUrl!;
                                a.download = activeVideo.name;
                                a.click();
                            }}
                            className="bg-emerald-600 hover:bg-emerald-500 text-white px-8 py-3 rounded-xl font-bold flex items-center gap-2 shadow-lg shadow-emerald-900/20 transition-all active:scale-95 animate-in fade-in slide-in-from-bottom-4"
                        >
                            <Download className="w-5 h-5" /> Download Branded Clip
                        </button>
                    )}
                </div>
            </div>
        </div>
    );
};

export default FrameEditor;

import React, { useState, useRef, useEffect } from 'react';
import { ArrowLeft, Video, LayoutTemplate, ShieldCheck, Download, Upload, Loader2, Play, Trash2, Maximize, Move, FileVideo, CheckCircle, AlertCircle, List, Plus, Music, Pause, Volume2, VolumeX, Scissors, Type, Sparkles } from 'lucide-react';
import { FrameSettings, WatermarkPosition, FrameVideoItem, Caption } from '../types';
import { GoogleGenAI, Type as SchemaType } from "@google/genai";

interface FrameEditorProps {
    onBack: () => void;
}

interface VisualizerProps {
    videoRef: React.RefObject<HTMLVideoElement | null>;
    isActive: boolean;
    isMuted: boolean;
    volume: number;
}

const WaveformVisualizer: React.FC<VisualizerProps> = ({ videoRef, isActive, isMuted, volume }) => {
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const analyserRef = useRef<AnalyserNode | null>(null);
    const audioContextRef = useRef<AudioContext | null>(null);
    const sourceRef = useRef<MediaElementAudioSourceNode | null>(null);
    const gainNodeRef = useRef<GainNode | null>(null);
    const animationRef = useRef<number | null>(null);

    useEffect(() => {
        if (!isActive || !videoRef.current) return;

        const video = videoRef.current;

        if (!audioContextRef.current) {
            audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
        }

        const ctx = audioContextRef.current;

        if (!analyserRef.current) {
            analyserRef.current = ctx.createAnalyser();
            analyserRef.current.fftSize = 128;
        }

        if (!gainNodeRef.current) {
            gainNodeRef.current = ctx.createGain();
            gainNodeRef.current.connect(ctx.destination);
        }

        const analyser = analyserRef.current;
        const gainNode = gainNodeRef.current;

        try {
            if (!sourceRef.current) {
                sourceRef.current = ctx.createMediaElementSource(video);
                sourceRef.current.connect(analyser);
                analyser.connect(gainNode);
            }
        } catch (e) {
            console.warn("Audio source already connected or blocked", e);
        }

        const bufferLength = analyser.frequencyBinCount;
        const dataArray = new Uint8Array(bufferLength);

        const draw = () => {
            if (!canvasRef.current) return;
            const canvas = canvasRef.current;
            const canvasCtx = canvas.getContext('2d');
            if (!canvasCtx) return;

            animationRef.current = requestAnimationFrame(draw);
            analyser.getByteFrequencyData(dataArray);

            canvasCtx.clearRect(0, 0, canvas.width, canvas.height);

            const barWidth = (canvas.width / bufferLength) * 2;
            let barHeight;
            let x = 0;

            for (let i = 0; i < bufferLength; i++) {
                barHeight = (dataArray[i] / 255) * canvas.height;

                const gradient = canvasCtx.createLinearGradient(0, canvas.height, 0, 0);
                gradient.addColorStop(0, 'rgba(168, 85, 247, 0.4)'); 
                gradient.addColorStop(1, 'rgba(236, 72, 153, 0.8)'); 

                canvasCtx.fillStyle = gradient;
                canvasCtx.fillRect(x, canvas.height - barHeight, barWidth - 1, barHeight);

                x += barWidth;
            }
        };

        draw();

        return () => {
            if (animationRef.current) cancelAnimationFrame(animationRef.current);
        };
    }, [isActive, videoRef.current?.src]);

    useEffect(() => {
        if (gainNodeRef.current && audioContextRef.current) {
            if (audioContextRef.current.state === 'suspended') {
                audioContextRef.current.resume();
            }
            gainNodeRef.current.gain.setTargetAtTime(isMuted ? 0 : volume, audioContextRef.current.currentTime, 0.02);
        }
    }, [isMuted, volume]);

    return (
        <canvas 
            ref={canvasRef} 
            className="absolute bottom-24 left-0 w-full h-12 pointer-events-none z-30 opacity-60" 
            width={320} 
            height={60} 
        />
    );
};

const FrameEditor: React.FC<FrameEditorProps> = ({ onBack }) => {
    const [settings, setSettings] = useState<FrameSettings>({
        frameImageUrl: null,
        watermarkUrl: null,
        watermarkOpacity: 0.8,
        watermarkPosition: WatermarkPosition.BOTTOM_RIGHT,
        watermarkSize: 15,
        videos: []
    });

    const [activeVideoId, setActiveVideoId] = useState<string | null>(null);
    const [isPreviewPaused, setIsPreviewPaused] = useState(false);
    const [isPreviewMuted, setIsPreviewMuted] = useState(true);
    const [previewVolume, setPreviewVolume] = useState(0.8);
    const [isProcessing, setIsProcessing] = useState(false);
    const [isGeneratingCaptions, setIsGeneratingCaptions] = useState(false);
    const [progress, setProgress] = useState('');

    const videoInputRef = useRef<HTMLInputElement>(null);
    const frameInputRef = useRef<HTMLInputElement>(null);
    const watermarkInputRef = useRef<HTMLInputElement>(null);
    const videoRef = useRef<HTMLVideoElement>(null);

    const activeVideo = settings.videos.find(v => v.id === activeVideoId) || settings.videos[0];

    useEffect(() => {
        const video = videoRef.current;
        if (!video || !activeVideo) return;

        const checkTrim = () => {
            if (video.currentTime >= activeVideo.trimRange.end) {
                video.currentTime = activeVideo.trimRange.start;
            }
        };

        video.addEventListener('timeupdate', checkTrim);
        return () => video.removeEventListener('timeupdate', checkTrim);
    }, [activeVideo?.trimRange, activeVideoId]);

    const togglePlay = () => {
        if (!videoRef.current) return;
        if (isPreviewPaused) {
            videoRef.current.play();
        } else {
            videoRef.current.pause();
        }
        setIsPreviewPaused(!isPreviewPaused);
    };

    const handleFileUpload = (type: 'video' | 'frame' | 'watermark', e: React.ChangeEvent<HTMLInputElement>) => {
        const files = e.target.files;
        if (!files || files.length === 0) return;

        if (type === 'video') {
            Array.from(files).forEach((file: File) => {
                const url = URL.createObjectURL(file);
                const tempVideo = document.createElement('video');
                tempVideo.src = url;
                tempVideo.onloadedmetadata = () => {
                    const newVideo: FrameVideoItem = {
                        id: Math.random().toString(36).substr(2, 9),
                        url: url,
                        file: file,
                        name: file.name,
                        status: 'idle',
                        generatedUrl: null,
                        trimRange: { start: 0, end: tempVideo.duration },
                        duration: tempVideo.duration,
                        captions: []
                    };
                    setSettings(prev => ({ ...prev, videos: [...prev.videos, newVideo] }));
                    if (!activeVideoId) setActiveVideoId(newVideo.id);
                };
            });
        } else {
            const file = files[0];
            const url = URL.createObjectURL(file);
            if (type === 'frame') setSettings(prev => ({ ...prev, frameImageUrl: url }));
            if (type === 'watermark') setSettings(prev => ({ ...prev, watermarkUrl: url }));
        }
        e.target.value = '';
    };

    const removeVideo = (id: string) => {
        setSettings(prev => {
            const filtered = prev.videos.filter(v => v.id !== id);
            if (activeVideoId === id) {
                setActiveVideoId(filtered.length > 0 ? filtered[0].id : null);
            }
            return { ...prev, videos: filtered };
        });
    };

    const updateTrim = (id: string, start: number, end: number) => {
        setSettings(prev => ({
            ...prev,
            videos: prev.videos.map(v => v.id === id ? { ...v, trimRange: { start, end } } : v)
        }));
    };

    const generateCaptions = async () => {
        if (!activeVideo) return;
        setIsGeneratingCaptions(true);
        setProgress('AI is listening to your video...');

        try {
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
            const file = activeVideo.file;
            const reader = new FileReader();

            const base64Data = await new Promise<string>((resolve) => {
                reader.onload = () => resolve((reader.result as string).split(',')[1]);
                reader.readAsDataURL(file);
            });

            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: [
                    {
                        parts: [
                            { inlineData: { data: base64Data, mimeType: file.type } },
                            { text: "Tolong transkrip video ini menjadi subtitle dalam format JSON. Hasilnya harus berupa array objek dengan properti 'text', 'start' (detik), dan 'end' (detik). Gunakan Bahasa Indonesia." }
                        ]
                    }
                ],
                config: {
                    responseMimeType: 'application/json',
                    responseSchema: {
                        type: SchemaType.ARRAY,
                        items: {
                            type: SchemaType.OBJECT,
                            properties: {
                                text: { type: SchemaType.STRING },
                                start: { type: SchemaType.NUMBER },
                                end: { type: SchemaType.NUMBER }
                            },
                            required: ['text', 'start', 'end']
                        }
                    }
                }
            });

            const caps = JSON.parse(response.text || '[]') as Caption[];
            setSettings(prev => ({
                ...prev,
                videos: prev.videos.map(v => v.id === activeVideo.id ? { ...v, captions: caps } : v)
            }));
            setProgress('Captions generated!');
        } catch (err) {
            console.error("Caption generation failed", err);
            alert("Gagal membuat caption otomatis. Pastikan API Key valid.");
        } finally {
            setIsGeneratingCaptions(false);
            setTimeout(() => setProgress(''), 3000);
        }
    };

    const processSingleVideo = async (videoItem: FrameVideoItem): Promise<string> => {
        return new Promise(async (resolve, reject) => {
            try {
                const canvas = document.createElement('canvas');
                const ctx = canvas.getContext('2d');
                if (!ctx) throw new Error("Could not get canvas context");

                canvas.width = 720;
                canvas.height = 1280;

                const video = document.createElement('video');
                video.src = videoItem.url;
                video.crossOrigin = 'anonymous';
                video.muted = false; 
                video.volume = 1.0;

                await new Promise((r) => video.onloadedmetadata = r);

                const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
                if (audioCtx.state === 'suspended') {
                    await audioCtx.resume();
                }

                const source = audioCtx.createMediaElementSource(video);
                const dest = audioCtx.createMediaStreamDestination();
                source.connect(dest);

                let frameImg = null;
                if (settings.frameImageUrl) {
                    frameImg = new Image();
                    frameImg.src = settings.frameImageUrl;
                    await new Promise((r) => frameImg!.onload = r);
                }

                let watermarkImg = null;
                if (settings.watermarkUrl) {
                    watermarkImg = new Image();
                    watermarkImg.src = settings.watermarkUrl;
                    await new Promise((r) => watermarkImg!.onload = r);
                }

                const videoStream = canvas.captureStream(30);
                const videoTrack = videoStream.getVideoTracks()[0];
                const audioTracks = dest.stream.getAudioTracks();

                const combinedStream = new MediaStream();
                combinedStream.addTrack(videoTrack);
                if (audioTracks.length > 0) {
                    combinedStream.addTrack(audioTracks[0]);
                }

                const recorder = new MediaRecorder(combinedStream, { 
                    mimeType: 'video/webm;codecs=vp9,opus' 
                });

                const chunks: Blob[] = [];
                recorder.ondataavailable = (e) => {
                    if (e.data.size > 0) chunks.push(e.data);
                };

                recorder.onstop = () => {
                    audioCtx.close();
                    const blob = new Blob(chunks, { type: 'video/webm' });
                    const url = URL.createObjectURL(blob);
                    resolve(url);
                };

                recorder.start();
                video.currentTime = videoItem.trimRange.start;
                video.play();

                const draw = () => {
                    if (video.paused || video.ended || video.currentTime >= videoItem.trimRange.end) {
                        if (recorder.state === 'recording') recorder.stop();
                        return;
                    }

                    ctx.fillStyle = 'black';
                    ctx.fillRect(0, 0, canvas.width, canvas.height);

                    const vRatio = video.videoWidth / video.videoHeight;
                    const cRatio = canvas.width / canvas.height;
                    let dw, dh, sx, sy;
                    if (vRatio > cRatio) {
                        dh = canvas.height; dw = dh * vRatio; sx = (canvas.width - dw) / 2; sy = 0;
                    } else {
                        dw = canvas.width; dh = dw / vRatio; sx = 0; sy = (canvas.height - dh) / 2;
                    }
                    ctx.drawImage(video, sx, sy, dw, dh);

                    // Frame
                    if (frameImg) {
                        ctx.drawImage(frameImg, 0, 0, canvas.width, canvas.height);
                    }

                    // Captions
                    if (videoItem.captions.length > 0) {
                        const currentCap = videoItem.captions.find(c => video.currentTime >= c.start && video.currentTime <= c.end);
                        if (currentCap) {
                            ctx.save();
                            ctx.font = 'bold 36px "Inter", sans-serif';
                            ctx.textAlign = 'center';
                            ctx.textBaseline = 'middle';

                            const lines = currentCap.text.split('\n');
                            const yBase = canvas.height - 180;

                            ctx.fillStyle = 'rgba(0,0,0,0.6)';
                            const textWidth = ctx.measureText(currentCap.text).width + 40;
                            ctx.fillRect(canvas.width/2 - textWidth/2, yBase - 30, textWidth, 60);

                            ctx.fillStyle = 'white';
                            ctx.strokeStyle = 'black';
                            ctx.lineWidth = 4;
                            ctx.strokeText(currentCap.text, canvas.width/2, yBase);
                            ctx.fillText(currentCap.text, canvas.width/2, yBase);
                            ctx.restore();
                        }
                    }

                    // Watermark
                    if (watermarkImg) {
                        ctx.save();
                        ctx.globalAlpha = settings.watermarkOpacity;
                        const wSize = (canvas.width * settings.watermarkSize) / 100;
                        const wAspect = watermarkImg.width / watermarkImg.height;
                        const wWidth = wSize;
                        const wHeight = wSize / wAspect;
                        const padding = 40;
                        let wx, wy;
                        switch (settings.watermarkPosition) {
                            case WatermarkPosition.TOP_LEFT: wx = padding; wy = padding; break;
                            case WatermarkPosition.TOP_RIGHT: wx = canvas.width - wWidth - padding; wy = padding; break;
                            case WatermarkPosition.BOTTOM_LEFT: wx = padding; wy = canvas.height - wHeight - padding; break;
                            case WatermarkPosition.BOTTOM_RIGHT: 
                            default: wx = canvas.width - wWidth - padding; wy = canvas.height - wHeight - padding; break;
                        }
                        ctx.drawImage(watermarkImg, wx, wy, wWidth, wHeight);
                        ctx.restore();
                    }
                    requestAnimationFrame(draw);
                };
                draw();
            } catch (err) {
                reject(err);
            }
        });
    };

    const processAllVideos = async () => {
        if (settings.videos.length === 0) return;
        setIsProcessing(true);
        const videosToProcess = settings.videos.filter(v => v.status !== 'done');
        for (let i = 0; i < videosToProcess.length; i++) {
            const video = videosToProcess[i];
            setSettings(prev => ({
                ...prev,
                videos: prev.videos.map(v => v.id === video.id ? { ...v, status: 'processing' } : v)
            }));
            setProgress(`Processing ${i + 1}/${videosToProcess.length}: ${video.name}`);
            try {
                const resultUrl = await processSingleVideo(video);
                setSettings(prev => ({
                    ...prev,
                    videos: prev.videos.map(v => v.id === video.id ? { ...v, status: 'done', generatedUrl: resultUrl } : v)
                }));
            } catch (err) {
                console.error("Batch processing error:", err);
                setSettings(prev => ({
                    ...prev,
                    videos: prev.videos.map(v => v.id === video.id ? { ...v, status: 'error', error: 'Failed' } : v)
                }));
            }
        }
        setIsProcessing(false);
        setProgress('');
    };

    const downloadAll = () => {
        const doneVideos = settings.videos.filter(v => v.status === 'done' && v.generatedUrl);
        if (doneVideos.length === 0) return;
        doneVideos.forEach((v, i) => {
            setTimeout(() => {
                const a = document.createElement('a');
                a.href = v.generatedUrl!;
                a.download = v.name;
                a.click();
            }, i * 1200); 
        });
    };

    return (
        <div className="flex flex-col lg:flex-row h-screen w-full overflow-hidden bg-slate-950 text-white font-inter">
            <div className="w-full lg:w-96 bg-slate-900 border-r border-slate-800 flex flex-col h-auto lg:h-full shadow-2xl z-20 overflow-hidden">
                <div className="p-6 border-b border-slate-800 flex items-center gap-3 shrink-0">
                    <button onClick={onBack} className="p-2 -ml-2 hover:bg-slate-800 rounded-full text-slate-400 hover:text-white transition-colors">
                        <ArrowLeft className="w-5 h-5" />
                    </button>
                    <h1 className="text-xl font-bold bg-gradient-to-r from-purple-400 to-pink-500 bg-clip-text text-transparent">Frame & Brand</h1>
                </div>

                <div className="flex-1 overflow-y-auto p-6 space-y-8 scrollbar-thin">
                    <div className="space-y-4">
                        <div className="flex items-center justify-between">
                            <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2">
                                <List className="w-3 h-3" /> Media Queue ({settings.videos.length})
                            </label>
                            <input type="file" accept="video/*" multiple ref={videoInputRef} className="hidden" onChange={(e) => handleFileUpload('video', e)} />
                            <button onClick={() => videoInputRef.current?.click()} className="text-[10px] text-purple-400 hover:text-purple-300 font-bold uppercase tracking-widest flex items-center gap-1 transition-colors">
                                <Plus className="w-3 h-3" /> Add Clips
                            </button>
                        </div>

                        {settings.videos.length === 0 ? (
                            <div className="border-2 border-dashed border-slate-800 rounded-xl p-8 text-center bg-slate-950/50">
                                <Video className="w-8 h-8 mx-auto mb-3 text-slate-700 opacity-20" />
                                <p className="text-xs text-slate-600">No videos uploaded</p>
                            </div>
                        ) : (
                            <div className="space-y-2 max-h-48 overflow-y-auto pr-2 scrollbar-thin">
                                {settings.videos.map((v) => (
                                    <div 
                                        key={v.id}
                                        onClick={() => {
                                            setActiveVideoId(v.id);
                                            setIsPreviewPaused(false);
                                        }}
                                        className={`p-3 rounded-xl border transition-all cursor-pointer flex items-center justify-between group ${
                                            v.id === activeVideoId ? 'bg-purple-600/10 border-purple-500/50 shadow-lg' : 'bg-slate-800 border-slate-700 hover:border-slate-600'
                                        }`}
                                    >
                                        <div className="flex items-center gap-3 overflow-hidden">
                                            {v.status === 'processing' ? <Loader2 className="w-4 h-4 text-purple-400 animate-spin shrink-0" /> : 
                                             v.status === 'done' ? <CheckCircle className="w-4 h-4 text-green-500 shrink-0" /> :
                                             v.status === 'error' ? <AlertCircle className="w-4 h-4 text-red-500 shrink-0" /> :
                                             <FileVideo className="w-4 h-4 text-slate-500 shrink-0" />}
                                            <span className="text-[10px] truncate text-slate-300 font-medium">{v.name}</span>
                                        </div>
                                        <button 
                                          onClick={(e) => { e.stopPropagation(); removeVideo(v.id); }} 
                                          className="opacity-0 group-hover:opacity-100 p-1.5 hover:bg-red-500/20 text-slate-500 hover:text-red-400 rounded-lg transition-all"
                                        >
                                            <Trash2 className="w-3 h-3" />
                                        </button>
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>

                    {activeVideo && (
                        <div className="space-y-6 pt-2 border-t border-slate-800 pt-6 animate-in fade-in duration-500">
                             <div className="space-y-4">
                                <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2">
                                    <Scissors className="w-3 h-3" /> Video Trimmer
                                </label>
                                <div className="space-y-3 p-3 bg-slate-800/50 rounded-xl border border-slate-700">
                                    <div>
                                        <div className="flex justify-between text-[9px] text-slate-400 uppercase mb-1">
                                            <span>Start Time</span>
                                            <span>{activeVideo.trimRange.start.toFixed(1)}s</span>
                                        </div>
                                        <input 
                                            type="range" min="0" max={activeVideo.duration} step="0.1"
                                            value={activeVideo.trimRange.start}
                                            onChange={(e) => updateTrim(activeVideo.id, Math.min(Number(e.target.value), activeVideo.trimRange.end - 0.5), activeVideo.trimRange.end)}
                                            className="w-full h-1 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-purple-500"
                                        />
                                    </div>
                                    <div>
                                        <div className="flex justify-between text-[9px] text-slate-400 uppercase mb-1">
                                            <span>End Time</span>
                                            <span>{activeVideo.trimRange.end.toFixed(1)}s</span>
                                        </div>
                                        <input 
                                            type="range" min="0" max={activeVideo.duration} step="0.1"
                                            value={activeVideo.trimRange.end}
                                            onChange={(e) => updateTrim(activeVideo.id, activeVideo.trimRange.start, Math.max(Number(e.target.value), activeVideo.trimRange.start + 0.5))}
                                            className="w-full h-1 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-purple-500"
                                        />
                                    </div>
                                </div>
                            </div>

                            <div className="space-y-4">
                                <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2">
                                    <Type className="w-3 h-3" /> Auto Captions
                                </label>
                                <button 
                                    onClick={generateCaptions}
                                    disabled={isGeneratingCaptions}
                                    className={`w-full py-3 px-4 bg-slate-800 border border-slate-700 rounded-xl hover:border-purple-500 transition-all flex items-center justify-center gap-2 text-xs font-bold ${isGeneratingCaptions ? 'opacity-50' : ''}`}
                                >
                                    {isGeneratingCaptions ? <Loader2 className="w-4 h-4 animate-spin" /> : <Sparkles className="w-4 h-4 text-amber-400" />}
                                    {activeVideo.captions.length > 0 ? 'Regenerate Captions' : 'Auto Generate Captions'}
                                </button>
                                {activeVideo.captions.length > 0 && (
                                    <div className="p-2 bg-purple-500/10 border border-purple-500/20 rounded-lg text-[10px] text-purple-300 italic text-center">
                                        {activeVideo.captions.length} subtitle chunks detected.
                                    </div>
                                )}
                            </div>
                        </div>
                    )}

                    <div className="space-y-6 pt-2 border-t border-slate-800 pt-6">
                        <div>
                            <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2 mb-3">
                                <LayoutTemplate className="w-3 h-3" /> Frame Overlay (PNG)
                            </label>
                            <input type="file" accept="image/png" ref={frameInputRef} className="hidden" onChange={(e) => handleFileUpload('frame', e)} />
                            <button onClick={() => frameInputRef.current?.click()} className="w-full py-3 px-4 bg-slate-800 border border-slate-700 rounded-xl hover:border-purple-500 transition-all flex items-center justify-center gap-2 text-sm">
                                <Upload className="w-4 h-4" /> {settings.frameImageUrl ? 'Change Frame' : 'Upload Frame'}
                            </button>
                        </div>

                        <div>
                            <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2 mb-3">
                                <ShieldCheck className="w-3 h-3" /> Watermark Logo
                            </label>
                            <input type="file" accept="image/*" ref={watermarkInputRef} className="hidden" onChange={(e) => handleFileUpload('watermark', e)} />
                            <button onClick={() => watermarkInputRef.current?.click()} className="w-full py-3 px-4 bg-slate-800 border border-slate-700 rounded-xl hover:border-purple-500 transition-all flex items-center justify-center gap-2 text-sm">
                                <ShieldCheck className="w-4 h-4" /> {settings.watermarkUrl ? 'Change Watermark' : 'Upload Watermark'}
                            </button>
                        </div>

                        {settings.watermarkUrl && (
                            <div className="space-y-5 animate-in fade-in slide-in-from-top-4 duration-300 border-t border-slate-800 pt-6">
                                <h3 className="text-xs font-bold text-slate-400 flex items-center gap-2"><Move className="w-3 h-3" /> Brand Config</h3>
                                <div className="space-y-4">
                                    <div>
                                        <div className="flex justify-between text-[10px] text-slate-500 uppercase mb-2">
                                            <span>Position</span>
                                            <span className="text-purple-400">{settings.watermarkPosition.replace('-', ' ')}</span>
                                        </div>
                                        <div className="grid grid-cols-2 gap-2">
                                            {Object.values(WatermarkPosition).map(pos => (
                                                <button 
                                                    key={pos}
                                                    onClick={() => setSettings(prev => ({ ...prev, watermarkPosition: pos }))}
                                                    className={`py-2 text-[10px] font-bold rounded-lg border transition-all ${settings.watermarkPosition === pos ? 'bg-purple-600 border-purple-500 text-white shadow-lg' : 'bg-slate-800 border-slate-700 text-slate-400 hover:border-slate-600'}`}
                                                >
                                                    {pos.toUpperCase().replace('_', ' ')}
                                                </button>
                                            ))}
                                        </div>
                                    </div>
                                    <div>
                                        <div className="flex justify-between text-[10px] text-slate-500 uppercase mb-2">
                                            <span>Scale</span>
                                            <span className="text-purple-400">{settings.watermarkSize}%</span>
                                        </div>
                                        <input 
                                            type="range" min="5" max="50" step="1"
                                            value={settings.watermarkSize}
                                            onChange={(e) => setSettings(prev => ({ ...prev, watermarkSize: Number(e.target.value) }))}
                                            className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-purple-500"
                                        />
                                    </div>
                                    <div>
                                        <div className="flex justify-between text-[10px] text-slate-500 uppercase mb-2">
                                            <span>Transparency</span>
                                            <span className="text-purple-400">{Math.round(settings.watermarkOpacity * 100)}%</span>
                                        </div>
                                        <input 
                                            type="range" min="0" max="1" step="0.05"
                                            value={settings.watermarkOpacity}
                                            onChange={(e) => setSettings(prev => ({ ...prev, watermarkOpacity: Number(e.target.value) }))}
                                            className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-purple-500"
                                        />
                                    </div>
                                </div>
                            </div>
                        )}
                    </div>
                </div>

                <div className="shrink-0 p-6 border-t border-slate-800 bg-slate-900/80 backdrop-blur-md space-y-3">
                    {settings.videos.some(v => v.status === 'done') && !isProcessing && (
                        <button 
                            onClick={downloadAll} 
                            className="w-full py-3 rounded-xl font-bold bg-emerald-600 hover:bg-emerald-500 text-white flex items-center justify-center gap-2 transition-all shadow-lg shadow-emerald-900/20 active:scale-95"
                        >
                            <Download className="w-4 h-4" /> Download All Result
                        </button>
                    )}
                    <button 
                        onClick={processAllVideos}
                        disabled={isProcessing || settings.videos.length === 0}
                        className={`w-full py-4 rounded-xl font-bold transition-all shadow-xl flex items-center justify-center gap-2 ${isProcessing ? 'bg-slate-700 cursor-not-allowed text-slate-400' : 'bg-purple-600 hover:bg-purple-500 active:scale-95 text-white'}`}
                    >
                        {isProcessing ? <><Loader2 className="w-5 h-5 animate-spin" /> {progress}</> : <><Play className="w-5 h-5 fill-current" /> Batch Process ({settings.videos.length})</>}
                    </button>
                    {progress && <p className="text-[10px] text-center text-purple-300 animate-pulse">{progress}</p>}
                </div>
            </div>

            <div className="flex-1 flex flex-col items-center justify-center p-8 relative overflow-hidden">
                <div className="absolute inset-0 opacity-5 pointer-events-none" style={{ backgroundImage: 'radial-gradient(#475569 1px, transparent 1px)', backgroundSize: '24px 24px' }}></div>

                <div className="relative z-10 flex flex-col items-center gap-6">
                    <div className="flex items-center gap-3 text-slate-500 text-xs font-bold uppercase tracking-widest bg-slate-900/50 px-4 py-2 rounded-full border border-slate-800">
                        <Maximize className="w-3 h-3" /> {activeVideo ? `Preview: ${activeVideo.name}` : 'Branding Preview'}
                    </div>

                    <div className="relative w-[320px] h-[570px] bg-black rounded-[40px] overflow-hidden shadow-[0_0_80px_rgba(168,85,247,0.15)] border-[8px] border-slate-800 ring-1 ring-slate-700 group/preview">
                        {activeVideo ? (
                            <video 
                                key={activeVideo.id} 
                                ref={videoRef} 
                                src={activeVideo.url} 
                                autoPlay 
                                loop 
                                muted 
                                playsInline 
                                className="absolute inset-0 w-full h-full object-cover" 
                            />
                        ) : (
                            <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-700 p-8 text-center bg-slate-900">
                                <Video className="w-16 h-16 mb-4 opacity-10" />
                                <p className="text-sm font-medium">Add clips to start</p>
                            </div>
                        )}

                        <WaveformVisualizer 
                            videoRef={videoRef} 
                            isActive={!!activeVideo} 
                            isMuted={isPreviewMuted}
                            volume={previewVolume}
                        />

                        {activeVideo && activeVideo.captions.length > 0 && (
                            <div className="absolute bottom-32 inset-x-4 z-40 text-center pointer-events-none transition-all duration-300">
                                {activeVideo.captions.map((c, i) => {
                                    const isActive = videoRef.current ? (videoRef.current.currentTime >= c.start && videoRef.current.currentTime <= c.end) : false;
                                    if (!isActive) return null;
                                    return (
                                        <div key={i} className="animate-in fade-in slide-in-from-bottom-2 duration-300">
                                            <span className="inline-block bg-black/60 backdrop-blur-sm text-white font-bold text-sm px-3 py-1.5 rounded-lg border border-white/10 shadow-xl shadow-black/40">
                                                {c.text}
                                            </span>
                                        </div>
                                    );
                                })}
                            </div>
                        )}

                        {activeVideo && (
                            <div className="absolute inset-x-0 bottom-4 px-4 z-40 opacity-0 group-hover/preview:opacity-100 transition-opacity duration-300">
                                <div className="bg-slate-950/80 backdrop-blur-md border border-slate-800 rounded-2xl p-3 flex items-center gap-3 shadow-2xl">
                                    <button 
                                        onClick={togglePlay}
                                        className="p-2 hover:bg-slate-800 rounded-full text-white transition-colors"
                                    >
                                        {isPreviewPaused ? <Play className="w-4 h-4 fill-current" /> : <Pause className="w-4 h-4 fill-current" />}
                                    </button>

                                    <div className="flex items-center gap-2 flex-1">
                                        <button 
                                            onClick={() => setIsPreviewMuted(!isPreviewMuted)}
                                            className="p-2 hover:bg-slate-800 rounded-full text-white transition-colors"
                                        >
                                            {isPreviewMuted || previewVolume === 0 ? <VolumeX className="w-4 h-4" /> : <Volume2 className="w-4 h-4" />}
                                        </button>
                                        <input 
                                            type="range" min="0" max="1" step="0.01"
                                            value={previewVolume}
                                            onChange={(e) => {
                                                setPreviewVolume(Number(e.target.value));
                                                if (Number(e.target.value) > 0) setIsPreviewMuted(false);
                                            }}
                                            className="flex-1 h-1 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-purple-500"
                                        />
                                    </div>
                                </div>
                            </div>
                        )}

                        {settings.frameImageUrl && (
                            <img src={settings.frameImageUrl} className="absolute inset-0 w-full h-full object-cover pointer-events-none z-10" alt="Frame" />
                        )}

                        {settings.watermarkUrl && (
                            <div className={`absolute p-5 pointer-events-none flex transition-all duration-300 z-20 ${
                                settings.watermarkPosition === WatermarkPosition.TOP_LEFT ? 'top-0 left-0' :
                                settings.watermarkPosition === WatermarkPosition.TOP_RIGHT ? 'top-0 right-0' :
                                settings.watermarkPosition === WatermarkPosition.BOTTOM_LEFT ? 'bottom-0 left-0' : 'bottom-0 right-0'
                            }`}>
                                <img 
                                    src={settings.watermarkUrl} 
                                    style={{ 
                                        width: `${settings.watermarkSize * 3}px`, 
                                        opacity: settings.watermarkOpacity 
                                    }} 
                                    className="object-contain" 
                                    alt="Watermark" 
                                />
                            </div>
                        )}
                    </div>

                    {activeVideo?.generatedUrl && (
                        <button 
                            onClick={() => {
                                const a = document.createElement('a');
                                a.href = activeVideo.generatedUrl!;
                                a.download = activeVideo.name;
                                a.click();
                            }}
                            className="bg-emerald-600 hover:bg-emerald-500 text-white px-8 py-3 rounded-xl font-bold flex items-center gap-2 shadow-lg shadow-emerald-900/20 transition-all active:scale-95 animate-in fade-in slide-in-from-bottom-4"
                        >
                            <Download className="w-5 h-5" /> Download Branded Clip
                        </button>
                    )}
                </div>
            </div>
        </div>
    );
};

export default FrameEditor;

export enum ThemeColor {
  RED = 'red',
  BLUE = 'blue',
  PURPLE = 'purple'
}

export enum WatermarkPosition {
  TOP_LEFT = 'top-left',
  TOP_RIGHT = 'top-right',
  BOTTOM_LEFT = 'bottom-left',
  BOTTOM_RIGHT = 'bottom-right'
}

export interface NewsOverlayState {
  headline: string;
  subheadline: string;
  theme: ThemeColor;
  overlayImage: string | null;
  headlineSize: number;
  subheadlineSize: number;
  imageHeight: number;
}

export interface NewsItem extends NewsOverlayState {
  id: string;
  // Media
  videoUrl: string | null;
  videoFile: File | null;
  // Result
  generatedVideoUrl: string | null;
}

export interface Caption {
  text: string;
  start: number;
  end: number;
}

export interface FrameVideoItem {
  id: string;
  url: string;
  name: string;
  file: File;
  status: 'idle' | 'processing' | 'done' | 'error';
  generatedUrl: string | null;
  error?: string;
  trimRange: { start: number; end: number };
  duration: number;
  captions: Caption[];
}

export interface FrameSettings {
  frameImageUrl: string | null;
  watermarkUrl: string | null;
  watermarkOpacity: number;
  watermarkPosition: WatermarkPosition;
  watermarkSize: number;
  videos: FrameVideoItem[];
}

export interface OverlayItem {
  id: string;
  bgVideo: { url: string; file: File } | null;
  overlayVideo: { url: string; file: File } | null;
  status: 'idle' | 'processing' | 'done' | 'error';
  generatedUrl: string | null;
  config: {
    x: number;
    y: number;
    width: number;
    height: number;
    opacity: number;
    rotation: number;
  };
}

export interface GlobalState {
  audioUrl: string | null;
  audioFile: File | null;
  isProcessing: boolean;
  processingItemId: string | null;
  progress: string;
}

export interface ScrapedArticle {
  id: string;
  url: string;
  title: string;
  firstParagraph: string;
  imageUrl: string;
}

export type ViewState = 'home' | 'editor' | 'scraper' | 'shorts' | 'frames' | 'overlay';

import React, { useState, useRef, useEffect } from 'react';
import { ArrowLeft, Upload, Layers, Video, Play, Pause, Download, Loader2, Move, Maximize, Smartphone, Trash2, RefreshCw, Plus, List, CheckCircle, AlertCircle, MoveHorizontal, MoveVertical, RotateCw, Sun } from 'lucide-react';
import { OverlayItem } from '../types';

interface VideoOverlayMakerProps {
    onBack: () => void;
}

const VideoOverlayMaker: React.FC<VideoOverlayMakerProps> = ({ onBack }) => {
    const [items, setItems] = useState<OverlayItem[]>([{
        id: Math.random().toString(36).substr(2, 9),
        bgVideo: null,
        overlayVideo: null,
        status: 'idle',
        generatedUrl: null,
        config: { x: 50, y: 50, width: 40, height: 40, opacity: 1, rotation: 0 }
    }]);
    const [activeId, setActiveId] = useState<string>(items[0].id);
    const [isProcessing, setIsProcessing] = useState(false);
    const [isPlaying, setIsPlaying] = useState(false);
    const [progress, setProgress] = useState('');

    const activeItem = items.find(i => i.id === activeId) || items[0];

    const bgInputRef = useRef<HTMLInputElement>(null);
    const overlayInputRef = useRef<HTMLInputElement>(null);
    const canvasRef = useRef<HTMLCanvasElement>(null);

    const bgVideoEl = useRef<HTMLVideoElement>(null);
    const overlayVideoEl = useRef<HTMLVideoElement>(null);

    const updateActiveItem = (updates: Partial<OverlayItem> | { config: Partial<OverlayItem['config']> }) => {
        setItems(prev => prev.map(item => {
            if (item.id !== activeId) return item;
            if ('config' in updates) {
                return { ...item, config: { ...item.config, ...updates.config } };
            }
            return { ...item, ...updates };
        }));
    };

    const handleVideoUpload = (type: 'bg' | 'overlay', e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            const url = URL.createObjectURL(file);
            if (type === 'bg') updateActiveItem({ bgVideo: { url, file }, generatedUrl: null });
            else {
                // When uploading overlay, try to set a default height that maintains aspect ratio
                const tempVideo = document.createElement('video');
                tempVideo.src = url;
                tempVideo.onloadedmetadata = () => {
                    const ratio = tempVideo.videoWidth / tempVideo.videoHeight;
                    // For a 9:16 canvas (720x1280), if width is 40% (288px), 
                    // height should be (288 / ratio) which is (0.4 * 720 / ratio) / 1280 of canvas height
                    const hPercent = (0.4 * 720 / ratio) / 1280 * 100;
                    updateActiveItem({ 
                        overlayVideo: { url, file }, 
                        generatedUrl: null,
                        config: { ...activeItem.config, height: Math.round(hPercent) }
                    });
                };
            }
            setIsPlaying(false);
        }
        e.target.value = '';
    };

    const addItem = () => {
        const newItem: OverlayItem = {
            id: Math.random().toString(36).substr(2, 9),
            bgVideo: null,
            overlayVideo: activeItem.overlayVideo, // Preserve overlay by default
            status: 'idle',
            generatedUrl: null,
            config: { ...activeItem.config }
        };
        setItems(prev => [...prev, newItem]);
        setActiveId(newItem.id);
    };

    const removeItem = (id: string) => {
        if (items.length <= 1) return;
        const newItems = items.filter(i => i.id !== id);
        setItems(newItems);
        if (activeId === id) setActiveId(newItems[0].id);
    };

    const resetTransform = () => {
        updateActiveItem({ config: { x: 50, y: 50, width: 40, height: 40, opacity: 1, rotation: 0 } });
    };

    const togglePlay = () => {
        if (!bgVideoEl.current || !overlayVideoEl.current) return;

        if (isPlaying) {
            bgVideoEl.current.pause();
            overlayVideoEl.current.pause();
        } else {
            if (overlayVideoEl.current.ended) {
                bgVideoEl.current.currentTime = 0;
                overlayVideoEl.current.currentTime = 0;
            }
            bgVideoEl.current.play();
            overlayVideoEl.current.play();
        }
        setIsPlaying(!isPlaying);
    };

    const drawFrame = (ctx: CanvasRenderingContext2D, width: number, height: number, item: OverlayItem) => {
        ctx.fillStyle = '#000';
        ctx.fillRect(0, 0, width, height);

        // Draw Background Video
        if (bgVideoEl.current && bgVideoEl.current.readyState >= 2) {
            const v = bgVideoEl.current;
            const vRatio = v.videoWidth / v.videoHeight;
            const cRatio = width / height;
            let dw, dh, dx, dy;

            if (vRatio > cRatio) {
                dh = height; dw = dh * vRatio; dx = (width - dw) / 2; dy = 0;
            } else {
                dw = width; dh = dw / vRatio; dx = 0; dy = (height - dh) / 2;
            }
            ctx.drawImage(v, dx, dy, dw, dh);
        }

        // Draw Overlay Video
        if (overlayVideoEl.current && overlayVideoEl.current.readyState >= 2) {
            const v = overlayVideoEl.current;

            const oWidth = (width * item.config.width) / 100;
            const oHeight = (height * item.config.height) / 100;

            const ox = (width * item.config.x) / 100;
            const oy = (height * item.config.y) / 100;

            ctx.save();
            ctx.translate(ox, oy);
            ctx.rotate((item.config.rotation * Math.PI) / 180);
            ctx.globalAlpha = item.config.opacity;
            ctx.shadowColor = 'rgba(0,0,0,0.5)';
            ctx.shadowBlur = 20;
            // Draw centered
            ctx.drawImage(v, -oWidth / 2, -oHeight / 2, oWidth, oHeight);
            ctx.restore();
        }
    };

    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas) return;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        let animationFrame: number;
        const render = () => {
            drawFrame(ctx, canvas.width, canvas.height, activeItem);
            animationFrame = requestAnimationFrame(render);
        };
        render();
        return () => cancelAnimationFrame(animationFrame);
    }, [activeId, items, isPlaying]);

    const processSingleExport = async (item: OverlayItem): Promise<string> => {
        if (!item.bgVideo || !item.overlayVideo) throw new Error("Missing media");

        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        if (!ctx) throw new Error("Canvas context error");
        canvas.width = 720;
        canvas.height = 1280;

        const bgV = document.createElement('video');
        bgV.src = item.bgVideo.url;
        bgV.muted = false;
        bgV.playsInline = true;

        const ovV = document.createElement('video');
        ovV.src = item.overlayVideo.url;
        ovV.muted = false;
        ovV.playsInline = true;

        await Promise.all([
            new Promise(r => bgV.onloadedmetadata = r),
            new Promise(r => ovV.onloadedmetadata = r)
        ]);

        const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
        const dest = audioCtx.createMediaStreamDestination();

        const bgSource = audioCtx.createMediaElementSource(bgV);
        const ovSource = audioCtx.createMediaElementSource(ovV);

        bgSource.connect(dest);
        ovSource.connect(dest);

        const videoStream = canvas.captureStream(30);
        const combinedStream = new MediaStream([
            videoStream.getVideoTracks()[0],
            dest.stream.getAudioTracks()[0]
        ]);

        const recorder = new MediaRecorder(combinedStream, { mimeType: 'video/webm;codecs=vp9,opus' });
        const chunks: Blob[] = [];

        return new Promise((resolve, reject) => {
            recorder.ondataavailable = e => chunks.push(e.data);
            recorder.onstop = () => {
                const blob = new Blob(chunks, { type: 'video/webm' });
                resolve(URL.createObjectURL(blob));
                audioCtx.close();
            };

            recorder.start();
            bgV.play();
            ovV.play();

            const renderLoop = () => {
                if (ovV.ended || ovV.paused) {
                    recorder.stop();
                    bgV.pause();
                    return;
                }

                ctx.fillStyle = '#000';
                ctx.fillRect(0, 0, canvas.width, canvas.height);

                const vRatio = bgV.videoWidth / bgV.videoHeight;
                const cRatio = canvas.width / canvas.height;
                let dw, dh, dx, dy;
                if (vRatio > cRatio) {
                    dh = canvas.height; dw = dh * vRatio; dx = (canvas.width - dw) / 2; dy = 0;
                } else {
                    dw = canvas.width; dh = dw / vRatio; dx = 0; dy = (canvas.height - dh) / 2;
                }
                ctx.drawImage(bgV, dx, dy, dw, dh);

                const oWidth = (canvas.width * item.config.width) / 100;
                const oHeight = (canvas.height * item.config.height) / 100;
                const ox = (canvas.width * item.config.x) / 100;
                const oy = (canvas.height * item.config.y) / 100;

                ctx.save();
                ctx.translate(ox, oy);
                ctx.rotate((item.config.rotation * Math.PI) / 180);
                ctx.globalAlpha = item.config.opacity;
                ctx.drawImage(ovV, -oWidth / 2, -oHeight / 2, oWidth, oHeight);
                ctx.restore();

                setProgress(`Processing: ${Math.floor(ovV.currentTime)}s / ${Math.floor(ovV.duration)}s`);
                requestAnimationFrame(renderLoop);
            };
            renderLoop();
        });
    };

    const triggerDownload = (url: string, originalName: string) => {
        const a = document.createElement('a');
        a.href = url;
        const lastDotIndex = originalName.lastIndexOf('.');
        const baseName = lastDotIndex !== -1 ? originalName.substring(0, lastDotIndex) : originalName;
        const safeName = baseName.replace(/[/\\?%*:|"<>]/g, '-').trim() || 'video';
        a.download = `${safeName}.webm`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
    };

    const handleBatchExport = async () => {
        const validItems = items.filter(i => i.bgVideo && i.overlayVideo && i.status !== 'done');
        if (validItems.length === 0) return;

        setIsProcessing(true);
        setIsPlaying(false);

        for (let i = 0; i < validItems.length; i++) {
            const item = validItems[i];
            setItems(prev => prev.map(v => v.id === item.id ? { ...v, status: 'processing' } : v));
            setProgress(`Exporting item ${i + 1}/${validItems.length}...`);

            try {
                const url = await processSingleExport(item);
                setItems(prev => prev.map(v => v.id === item.id ? { ...v, status: 'done', generatedUrl: url } : v));

                if (item.overlayVideo) {
                    triggerDownload(url, item.overlayVideo.file.name);
                }
            } catch (err) {
                console.error(err);
                setItems(prev => prev.map(v => v.id === item.id ? { ...v, status: 'error' } : v));
            }
        }

        setIsProcessing(false);
        setProgress('');
    };

    return (
        <div className="flex flex-col lg:flex-row h-screen w-full overflow-hidden bg-slate-950 text-white font-inter">
            {/* Sidebar */}
            <div className="w-full lg:w-96 bg-slate-900 border-r border-slate-800 flex flex-col h-auto lg:h-full z-20 shadow-2xl overflow-hidden">
                <div className="p-6 border-b border-slate-800 flex items-center gap-3 shrink-0">
                    <button onClick={onBack} className="p-2 -ml-2 hover:bg-slate-800 rounded-full text-slate-400 hover:text-white transition-colors">
                        <ArrowLeft className="w-5 h-5" />
                    </button>
                    <h1 className="text-xl font-bold bg-gradient-to-r from-amber-400 to-orange-500 bg-clip-text text-transparent">Overlay Maker</h1>
                </div>

                <div className="flex-1 overflow-y-auto p-6 space-y-8 scrollbar-thin">
                    <div className="space-y-4">
                        <div className="flex items-center justify-between">
                            <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2">
                                <List className="w-3 h-3" /> Queue ({items.length})
                            </label>
                            <button onClick={addItem} className="text-[10px] text-amber-500 hover:text-amber-400 font-bold uppercase tracking-widest flex items-center gap-1">
                                <Plus className="w-3 h-3" /> Add Item
                            </button>
                        </div>

                        <div className="space-y-2 max-h-32 overflow-y-auto pr-2 scrollbar-thin">
                            {items.map((item, idx) => (
                                <div 
                                    key={item.id}
                                    onClick={() => { setActiveId(item.id); setIsPlaying(false); }}
                                    className={`p-3 rounded-xl border flex items-center justify-between cursor-pointer group transition-all ${activeId === item.id ? 'bg-amber-500/10 border-amber-500/50' : 'bg-slate-800 border-slate-700 hover:border-slate-600'}`}
                                >
                                    <div className="flex items-center gap-3 overflow-hidden">
                                        {item.status === 'processing' ? <Loader2 className="w-3 h-3 animate-spin text-amber-500" /> :
                                         item.status === 'done' ? <CheckCircle className="w-3 h-3 text-green-500" /> :
                                         item.status === 'error' ? <AlertCircle className="w-3 h-3 text-red-500" /> :
                                         <span className="text-[10px] font-bold text-slate-600">#{idx + 1}</span>}
                                        <span className="text-[10px] font-medium truncate text-slate-400">{item.bgVideo?.file.name || 'Empty slot'}</span>
                                    </div>
                                    <button onClick={(e) => { e.stopPropagation(); removeItem(item.id); }} className="opacity-0 group-hover:opacity-100 p-1 hover:bg-red-500/20 text-slate-500 hover:text-red-400 rounded transition-all">
                                        <Trash2 className="w-3 h-3" />
                                    </button>
                                </div>
                            ))}
                        </div>
                    </div>

                    <div className="space-y-4 border-t border-slate-800 pt-6">
                        <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2">
                            <Video className="w-3 h-3" /> Active Media
                        </label>

                        <div className="space-y-3">
                            <input type="file" accept="video/*" ref={bgInputRef} className="hidden" onChange={(e) => handleVideoUpload('bg', e)} />
                            <button onClick={() => bgInputRef.current?.click()} className={`w-full py-3 px-4 bg-slate-800 border rounded-xl flex items-center gap-3 transition-all ${activeItem.bgVideo ? 'border-amber-500/50' : 'border-slate-700 hover:border-slate-600'}`}>
                                <Upload className={`w-4 h-4 ${activeItem.bgVideo ? 'text-amber-500' : 'text-slate-500'}`} />
                                <span className="text-xs font-bold truncate flex-1 text-left">{activeItem.bgVideo?.file.name || 'Background Video'}</span>
                            </button>

                            <input type="file" accept="video/*" ref={overlayInputRef} className="hidden" onChange={(e) => handleVideoUpload('overlay', e)} />
                            <button onClick={() => overlayInputRef.current?.click()} className={`w-full py-3 px-4 bg-slate-800 border rounded-xl flex items-center gap-3 transition-all ${activeItem.overlayVideo ? 'border-blue-500/50' : 'border-slate-700 hover:border-slate-600'}`}>
                                <Layers className={`w-4 h-4 ${activeItem.overlayVideo ? 'text-blue-500' : 'text-slate-500'}`} />
                                <span className="text-xs font-bold truncate flex-1 text-left">{activeItem.overlayVideo?.file.name || 'Overlay Video'}</span>
                            </button>
                        </div>
                    </div>

                    {activeItem.overlayVideo && (
                        <div className="space-y-6 pt-2 border-t border-slate-800 pt-6 animate-in slide-in-from-bottom-4">
                            <div className="flex items-center justify-between">
                                <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2">
                                    <Move className="w-3 h-3" /> Transformations
                                </label>
                                <button onClick={resetTransform} className="text-[10px] text-amber-500 hover:text-amber-400 font-bold uppercase tracking-widest flex items-center gap-1">
                                    <RefreshCw className="w-3 h-3" /> Reset
                                </button>
                            </div>

                            <div className="space-y-5">
                                <div className="grid grid-cols-2 gap-4">
                                    <div>
                                        <div className="flex justify-between text-[10px] text-slate-500 uppercase mb-2">
                                            <span className="flex items-center gap-1"><MoveHorizontal className="w-3 h-3" /> Width</span>
                                            <span className="text-amber-500">{activeItem.config.width}%</span>
                                        </div>
                                        <input type="range" min="5" max="150" value={activeItem.config.width} onChange={(e) => updateActiveItem({ config: { width: Number(e.target.value) } })} className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-amber-500" />
                                    </div>
                                    <div>
                                        <div className="flex justify-between text-[10px] text-slate-500 uppercase mb-2">
                                            <span className="flex items-center gap-1"><MoveVertical className="w-3 h-3" /> Height</span>
                                            <span className="text-amber-500">{activeItem.config.height}%</span>
                                        </div>
                                        <input type="range" min="5" max="150" value={activeItem.config.height} onChange={(e) => updateActiveItem({ config: { height: Number(e.target.value) } })} className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-amber-500" />
                                    </div>
                                </div>

                                <div>
                                    <div className="flex justify-between text-[10px] text-slate-500 uppercase mb-2">
                                        <span>Position X</span>
