export type ViewState = 'home' | 'editor' | 'scraper' | 'shorts' | 'frames' | 'overlay' | 'image-studio';

import React, { useState, useRef, useEffect } from 'react';
import { ArrowLeft, Upload, Type, ImageIcon, Download, Loader2, Sparkles, Trash2, Smartphone, Maximize, Palette, Move, RefreshCw, Layers, Plus, FileSpreadsheet, List, CheckCircle, Type as FontIcon } from 'lucide-react';
import { GoogleGenAI } from "@google/genai";
import { ImageItem } from '../types';
import * as XLSX from 'xlsx';

interface ImageStudioProps {
    onBack: () => void;
}

const FONTS = [
    { name: 'Inter', family: '"Inter", sans-serif' },
    { name: 'Oswald', family: '"Oswald", sans-serif' },
    { name: 'Bebas Neue', family: '"Bebas Neue", sans-serif' },
    { name: 'Montserrat', family: '"Montserrat", sans-serif' }
];

const DEFAULT_ITEM: Omit<ImageItem, 'id'> = {
    baseImage: null,
    headline: 'DESIGN TITLE',
    subheadline: 'Subtitle text goes here',
    headlineSize: 80,
    subheadlineSize: 36,
    yPosition: 80,
    fontFamily: '"Bebas Neue", sans-serif',
    textColor: '#ffffff',
    textBgColor: 'rgba(0,0,0,0.7)',
    useBgBox: true,
    status: 'idle'
};

const ImageStudio: React.FC<ImageStudioProps> = ({ onBack }) => {
    const [items, setItems] = useState<ImageItem[]>([
        { ...DEFAULT_ITEM, id: Math.random().toString(36).substr(2, 9) }
    ]);
    const [activeId, setActiveId] = useState<string>(items[0].id);
    const [isGenerating, setIsGenerating] = useState(false);
    const [aspectRatio, setAspectRatio] = useState<'1:1' | '9:16' | '16:9'>('9:16');
    const [prompt, setPrompt] = useState('');

    const canvasRef = useRef<HTMLCanvasElement>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);
    const excelInputRef = useRef<HTMLInputElement>(null);

    const activeItem = items.find(i => i.id === activeId) || items[0];

    const updateActiveItem = (updates: Partial<ImageItem>) => {
        setItems(prev => prev.map(item => item.id === activeId ? { ...item, ...updates } : item));
    };

    const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            const url = URL.createObjectURL(file);
            updateActiveItem({ baseImage: url });
        }
        e.target.value = '';
    };

    const handleExcelImport = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        try {
            const data = await file.arrayBuffer();
            const workbook = XLSX.read(data);
            const sheet = workbook.Sheets[workbook.SheetNames[0]];
            const jsonData = XLSX.utils.sheet_to_json<any[]>(sheet, { header: 1 });

            const newItems: ImageItem[] = [];
            jsonData.forEach((row, idx) => {
                if (idx === 0 && row.length === 0) return; // Skip potential header
                const h = String(row[0] || '').trim();
                const s = String(row[1] || '').trim();
                const img = String(row[2] || '').trim();

                if (h || s || img) {
                    newItems.push({
                        ...DEFAULT_ITEM,
                        id: Math.random().toString(36).substr(2, 9),
                        headline: h || DEFAULT_ITEM.headline,
                        subheadline: s || '',
                        baseImage: img && img.startsWith('http') ? img : null
                    });
                }
            });

            if (newItems.length > 0) {
                setItems(prev => [...prev, ...newItems]);
                setActiveId(newItems[0].id);
            }
        } catch (err) {
            alert("Gagal membaca file Excel.");
        }
        e.target.value = '';
    };

    const generateAIImage = async () => {
        if (!prompt.trim()) return;
        setIsGenerating(true);
        try {
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
            let contents: any;
            if (activeItem.baseImage) {
                const response = await fetch(activeItem.baseImage);
                const blob = await response.blob();
                const base64 = await new Promise<string>((r) => {
                    const reader = new FileReader();
                    reader.onloadend = () => r((reader.result as string).split(',')[1]);
                    reader.readAsDataURL(blob);
                });
                contents = { parts: [{ inlineData: { data: base64, mimeType: blob.type } }, { text: prompt }] };
            } else {
                contents = { parts: [{ text: prompt }] };
            }

            const result = await ai.models.generateContent({
                model: 'gemini-2.5-flash-image',
                contents,
                config: { imageConfig: { aspectRatio } }
            });

            for (const part of result.candidates[0].content.parts) {
                if (part.inlineData) {
                    updateActiveItem({ baseImage: `data:image/png;base64,${part.inlineData.data}` });
                    break;
                }
            }
        } catch (error) {
            alert("Gagal menghasilkan gambar AI.");
        } finally {
            setIsGenerating(false);
        }
    };

    const drawToCanvas = (ctx: CanvasRenderingContext2D, width: number, height: number, item: ImageItem) => {
        ctx.fillStyle = '#000';
        ctx.fillRect(0, 0, width, height);

        const render = async () => {
            if (item.baseImage) {
                try {
                    const img = new Image();
                    img.crossOrigin = "anonymous";
                    img.src = item.baseImage;
                    await new Promise((r) => img.onload = r);
                    const iRatio = img.width / img.height;
                    const cRatio = width / height;
                    let dw, dh, dx, dy;
                    if (iRatio > cRatio) { dh = height; dw = dh * iRatio; dx = (width - dw) / 2; dy = 0; }
                    else { dw = width; dh = dw / iRatio; dx = 0; dy = (height - dh) / 2; }
                    ctx.drawImage(img, dx, dy, dw, dh);
                } catch (e) { console.warn("Image load failed"); }
            }

            const centerX = width / 2;
            const targetY = (height * item.yPosition) / 100;

            if (item.headline) {
                ctx.font = `900 ${item.headlineSize}px ${item.fontFamily}`;
                const hWidth = ctx.measureText(item.headline.toUpperCase()).width;
                const padding = item.headlineSize * 0.4;
                if (item.useBgBox) {
                    ctx.fillStyle = item.textBgColor;
                    ctx.fillRect(centerX - hWidth / 2 - padding, targetY - item.headlineSize, hWidth + padding * 2, item.headlineSize + padding * 0.5);
                }
                ctx.fillStyle = item.textColor;
                ctx.textAlign = 'center';
                ctx.fillText(item.headline.toUpperCase(), centerX, targetY);
            }

            if (item.subheadline) {
                ctx.font = `600 ${item.subheadlineSize}px ${item.fontFamily}`;
                const sY = targetY + item.headlineSize * 0.7;
                const sWidth = ctx.measureText(item.subheadline).width;
                const padding = item.subheadlineSize * 0.5;
                if (item.useBgBox) {
                    ctx.fillStyle = item.textBgColor;
                    ctx.fillRect(centerX - sWidth / 2 - padding, sY - item.subheadlineSize * 0.8, sWidth + padding * 2, item.subheadlineSize * 1.4);
                }
                ctx.fillStyle = item.textColor;
                ctx.textAlign = 'center';
                ctx.fillText(item.subheadline, centerX, sY + item.subheadlineSize / 2);
            }
        };
        render();
    };

    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas) return;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        if (aspectRatio === '9:16') { canvas.width = 720; canvas.height = 1280; }
        else if (aspectRatio === '16:9') { canvas.width = 1280; canvas.height = 720; }
        else { canvas.width = 1000; canvas.height = 1000; }

        drawToCanvas(ctx, canvas.width, canvas.height, activeItem);
    }, [items, activeId, aspectRatio]);

    const downloadAll = async () => {
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        if (aspectRatio === '9:16') { canvas.width = 720; canvas.height = 1280; }
        else if (aspectRatio === '16:9') { canvas.width = 1280; canvas.height = 720; }
        else { canvas.width = 1000; canvas.height = 1000; }

        for (let i = 0; i < items.length; i++) {
            const item = items[i];
            await new Promise((r) => {
                drawToCanvas(ctx, canvas.width, canvas.height, item);
                setTimeout(r, 200); // Give time for image loading in canvas
            });
            const link = document.createElement('a');
            link.download = `graphic-${i + 1}-${Date.now()}.png`;
            link.href = canvas.toDataURL('image/png');
            link.click();
            await new Promise(r => setTimeout(r, 1000)); // Delay to prevent browser blocking
        }
    };

    return (
        <div className="flex flex-col lg:flex-row h-screen w-full overflow-hidden bg-slate-950 text-white font-inter">
            {/* Sidebar */}
            <div className="w-full lg:w-96 bg-slate-900 border-r border-slate-800 flex flex-col h-auto lg:h-full z-20 shadow-2xl overflow-hidden">
                <div className="p-6 border-b border-slate-800 flex items-center gap-3 shrink-0">
                    <button onClick={onBack} className="p-2 -ml-2 hover:bg-slate-800 rounded-full text-slate-400 hover:text-white transition-colors">
                        <ArrowLeft className="w-5 h-5" />
                    </button>
                    <h1 className="text-xl font-bold bg-gradient-to-r from-indigo-400 to-blue-500 bg-clip-text text-transparent">Graphic Studio</h1>
                </div>

                <div className="flex-1 overflow-y-auto p-6 space-y-8 scrollbar-thin">
                    {/* Storyboard / Queue */}
                    <div className="space-y-4">
                        <div className="flex items-center justify-between">
                            <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2">
                                <List className="w-3 h-3" /> Queue ({items.length})
                            </label>
                            <div className="flex gap-2">
                                <input type="file" accept=".xlsx, .xls" ref={excelInputRef} className="hidden" onChange={handleExcelImport} />
                                <button onClick={() => excelInputRef.current?.click()} className="text-[10px] text-emerald-500 hover:text-emerald-400 font-bold uppercase tracking-widest flex items-center gap-1 transition-colors">
                                    <FileSpreadsheet className="w-3 h-3" /> Import
                                </button>
                                <button onClick={() => {
                                    const newItem = { ...DEFAULT_ITEM, id: Math.random().toString(36).substr(2, 9) };
                                    setItems(p => [...p, newItem]);
                                    setActiveId(newItem.id);
                                }} className="text-[10px] text-indigo-500 hover:text-indigo-400 font-bold uppercase tracking-widest flex items-center gap-1 transition-colors">
                                    <Plus className="w-3 h-3" /> Add
                                </button>
                            </div>
                        </div>
                        <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-thin">
                            {items.map((item, idx) => (
                                <div 
                                    key={item.id}
                                    onClick={() => setActiveId(item.id)}
                                    className={`relative flex-shrink-0 w-16 h-20 rounded-lg border-2 cursor-pointer transition-all overflow-hidden ${activeId === item.id ? 'border-indigo-500 shadow-lg' : 'border-slate-800 grayscale hover:grayscale-0'}`}
                                >
                                    {item.baseImage ? <img src={item.baseImage} className="w-full h-full object-cover" /> : <div className="w-full h-full bg-slate-800 flex items-center justify-center text-[10px] font-bold text-slate-600">#{idx+1}</div>}
                                    {items.length > 1 && (
                                        <button onClick={(e) => { e.stopPropagation(); setItems(p => p.filter(i => i.id !== item.id)); if(activeId === item.id) setActiveId(items[0].id); }} className="absolute top-0 right-0 p-1 bg-red-600/80 hover:bg-red-600 text-white rounded-bl-lg">
                                            <Trash2 className="w-2 h-2" />
                                        </button>
                                    )}
                                </div>
                            ))}
                        </div>
                    </div>

                    <div className="space-y-4">
                        <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2">
                            <Sparkles className="w-3 h-3" /> AI Image Generator
                        </label>
                        <textarea 
                            value={prompt}
                            onChange={(e) => setPrompt(e.target.value)}
                            placeholder="Describe what you want to create or edit..."
                            className="w-full bg-slate-950 border border-slate-700 rounded-xl px-4 py-3 text-sm text-white focus:ring-1 focus:ring-indigo-500 outline-none h-20 resize-none"
                        />
                        <div className="grid grid-cols-3 gap-2">
                            {['1:1', '9:16', '16:9'].map(ratio => (
                                <button 
                                    key={ratio}
                                    onClick={() => setAspectRatio(ratio as any)}
                                    className={`py-2 text-[10px] font-bold rounded-lg border transition-all ${aspectRatio === ratio ? 'bg-indigo-600 border-indigo-500 text-white' : 'bg-slate-800 border-slate-700 text-slate-400 hover:border-slate-600'}`}
                                >
                                    {ratio}
                                </button>
                            ))}
                        </div>
                        <button 
                            onClick={generateAIImage}
                            disabled={isGenerating || !prompt.trim()}
                            className="w-full py-3 bg-indigo-600 hover:bg-indigo-500 disabled:bg-slate-800 disabled:text-slate-500 rounded-xl font-bold flex items-center justify-center gap-2 transition-all shadow-xl active:scale-95"
                        >
                            {isGenerating ? <Loader2 className="w-4 h-4 animate-spin" /> : <Sparkles className="w-4 h-4" />}
                            AI Magic
                        </button>
                    </div>

                    <div className="space-y-4 pt-4 border-t border-slate-800">
                        <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2">
                            <ImageIcon className="w-3 h-3" /> Base Media
                        </label>
                        <input type="file" accept="image/*" ref={fileInputRef} className="hidden" onChange={handleImageUpload} />
                        <button onClick={() => fileInputRef.current?.click()} className="w-full py-3 px-4 bg-slate-800 border border-slate-700 rounded-xl hover:border-indigo-500 transition-all flex items-center justify-center gap-2 text-sm">
                            <Upload className="w-4 h-4" /> {activeItem.baseImage ? 'Replace Image' : 'Upload Image'}
                        </button>
                        <input 
                            type="text" 
                            placeholder="Paste image URL..."
                            className="w-full bg-slate-950 border border-slate-700 rounded-lg p-2 text-[10px] text-slate-400"
                            value={activeItem.baseImage?.startsWith('blob') ? '' : activeItem.baseImage || ''}
                            onChange={(e) => updateActiveItem({ baseImage: e.target.value })}
                        />
                    </div>

                    <div className="space-y-6 pt-4 border-t border-slate-800">
                        <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2">
                            <Type className="w-3 h-3" /> Content & Typography
                        </label>
                        <div className="space-y-4">
                            <div className="space-y-1">
                                <span className="text-[10px] text-slate-500 uppercase font-bold">Headline</span>
