                                            onClick={() => updateActiveItem({ fontFamily: font.family })}
                                            className={`py-2 text-[9px] rounded border transition-all ${activeItem.fontFamily === font.family ? 'bg-indigo-600 border-indigo-500 text-white shadow-lg' : 'bg-slate-800 border-slate-700 text-slate-400'}`}
