                                <Layers className={`w-3.5 h-3.5 ${activeItem.overlayVideo ? 'text-blue-500' : 'text-slate-500'}`} />
                                <span className="text-[11px] font-bold truncate flex-1 text-left">{activeItem.overlayVideo?.file.name || 'Overlay Video'}</span>
                            </button>
