import React, { useState } from 'react';
import { ArrowLeft, Facebook, Download, Trash2, Plus, List, Loader2, CheckCircle, AlertCircle, RefreshCw, ImageIcon, Search, ExternalLink } from 'lucide-react';

interface FBPhoto {
    id: string;
    url: string;
    imageUrl: string | null;
    status: 'idle' | 'processing' | 'done' | 'error';
    error?: string;
}

interface FacebookDownloaderProps {
  onBack: () => void;
}

const FacebookDownloader: React.FC<FacebookDownloaderProps> = ({ onBack }) => {
  const [urlInput, setUrlInput] = useState('');
  const [photos, setPhotos] = useState<FBPhoto[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [progress, setProgress] = useState('');

  const cleanUrl = (url: string) => {
      try {
          const u = new URL(url.trim());
          u.searchParams.delete('fbclid');
          u.searchParams.delete('extid');
          u.searchParams.delete('ref');
          return u.toString();
      } catch (e) {
          return url.trim();
      }
  };

  const fetchHtml = async (url: string): Promise<string> => {
    // List of proxies to try in sequence
    const proxies = [
        `https://api.allorigins.win/raw?url=${encodeURIComponent(url)}`,
        `https://corsproxy.io/?${encodeURIComponent(url)}`,
        `https://api.codetabs.com/v1/proxy?quest=${encodeURIComponent(url)}`
    ];

    for (const proxyUrl of proxies) {
        try {
            const response = await fetch(proxyUrl);
            if (response.ok) {
                const text = await response.text();
                // Basic check to see if we got actual HTML content
                if (text && (text.includes('facebook.com') || text.includes('fbcdn'))) return text;
            }
        } catch (e) {
            console.warn(`Proxy failed: ${proxyUrl}`, e);
        }
    }

    throw new Error('Gagal mengambil konten. Pastikan link publik dan coba lagi.');
  };

  const extractImage = (html: string): string | null => {
      const decodeFBUrl = (url: string) => {
          return url
            .replace(/\\/g, '')
            .replace(/&amp;/g, '&')
            .replace(/u0025/g, '%');
      };

      // 1. Try OG Meta Tags (Best for high-res if present)
      const ogMatch = html.match(/property="og:image"\s+content="([^"]+)"/i) || 
                      html.match(/content="([^"]+)"\s+property="og:image"/i);
      if (ogMatch && ogMatch[1]) return decodeFBUrl(ogMatch[1]);

      // 2. Try modern FB JSON patterns (GraphQL responses embedded in scripts)
      // Look for preferred high-res versions first
      const highResPatterns = [
          /"highest_res_image":\s*{\s*"uri":\s*"([^"]+)"/i,
          /"image":\s*{\s*"uri":\s*"([^"]+)"/i,
          /"browser_native_sd_url":\s*"([^"]+)"/i,
          /"thumbnail_url":\s*"([^"]+)"/i
      ];

      for (const pattern of highResPatterns) {
          const match = html.match(pattern);
          if (match && match[1] && match[1].includes('fbcdn')) {
              return decodeFBUrl(match[1]);
          }
      }

      // 3. Brute force search for fbcdn URLs in the HTML
      // Often useful for posts without clear meta tags
      const fbcdnRegex = /"(https:[^"]+?fbcdn[^"]+?)"/g;
      let match;
      const candidates: string[] = [];
      while ((match = fbcdnRegex.exec(html)) !== null) {
